INSERT INTO `ai_knowledge_base` VALUES
(1,'faq_general','Definisi Hipnoterapi','Apa itu hipnoterapi di Albashiro?','Hipnoterapi di Albashiro adalah metode terapi yang menggabungkan teknik relaksasi mendalam (trance) dengan nilai-nilai spiritual Islam. Berbeda dengan hipnosis panggung, di sini Anda memegang kendali penuh. Kami membantu Anda mengakses pikiran bawah sadar untuk mengubah pola pikir negatif, trauma, atau kebiasaan buruk, sambil tetap berlandaskan pada tauhid dan ketergantungan kepada Allah SWT.','definisi,apa itu,pengertian,intro',10,1,'2025-12-25 17:55:42','2025-12-25 17:55:42'),
(2,'faq_general','Keamanan','Apakah hipnoterapi aman? Ada efek sampingnya?','Sangat aman. Hipnoterapi adalah kondisi alami manusia, mirip seperti saat Anda melamun atau terlalu asyik membaca buku. Tidak ada efek samping berbahaya seperti \'tidak bisa bangun\' atau \'hilang ingatan\'. Di Albashiro, kami memastikan semua sugesti bersifat positif, memberdayakan, dan sesuai syariat. Efek samping yang paling umum hanyalah rasa kantuk yang nyaman dan perasaan rileks yang mendalam setelah sesi.','aman,bahaya,efek samping,safety',10,1,'2025-12-25 17:55:42','2025-12-25 17:55:42'),
(3,'faq_general','Durasi Sesi','Berapa lama satu sesi terapi berlangsung?','Satu sesi standar di Albashiro berlangsung antara 90 hingga 120 menit. Durasi ini mencakup: (1) Konsultasi awal/Anamnesis (30 menit) untuk membedah masalah, (2) Proses terapi/Induksi & Sugesti (45-60 menit), dan (3) Debriefing/Terminasi (15 menit). Untuk anak-anak, durasi mungkin lebih pendek (60-90 menit) tergantung tingkat fokus mereka. Kami tidak memburu-buru proses demi hasil maksimal.','durasi,waktu,lama sesi,jam',8,1,'2025-12-25 17:55:42','2025-12-25 17:55:42'),
(4,'faq_general','Perbandingan Psikolog','Apa bedanya sama ke Psikolog atau Psikiater?','Psikolog biasanya menggunakan konseling sadar (talk therapy) untuk membedah masalah kognitif. Psikiater adalah dokter medis yang bisa meresepkan obat untuk ketidakseimbangan kimiawi otak. Hipnoterapi Albashiro bekerja langsung ke \'akar\' di pikiran bawah sadar (subconscious) tempat emosi dan memori disimpan. Kami sering menjadi pelengkap; jika Anda sudah ke psikolog tapi merasa \'mentok\' karena trauma yang terlalu dalam, hipnoterapi bisa menjangkau area yang sulit disentuh logika sadar.','beda,psikolog,psikiater,dokter',8,1,'2025-12-25 17:55:42','2025-12-25 17:55:42'),
(5,'conditions','Generalized Anxiety (GAD)','Saya sering cemas tanpa sebab jelas, bisa bantu?','Bisa, itu tanda Generalized Anxiety Disorder (GAD). Di Albashiro, kami menggunakan teknik \'Regression to Cause\' untuk mencari akar pemicu kecemasan pertama kali (mungkin di masa kecil). Kami kemudian melakukan \'Emotional Release\' untuk membuang beban emosi tersebut dan menggantinya dengan anchoring ketenangan. 85% klien melaporkan penurunan kecemasan signifikan setelah 4 sesi.','cemas,anxiety,gad,khawatir',9,1,'2025-12-25 17:55:42','2025-12-25 17:55:42'),
(6,'conditions','Panic Attack','Gimana ngatasin serangan panik yang tiba-tiba?','Panic attack terjadi karena \'sistem alarm\' otak terlalu sensitif. Terapi kami mengajarkan teknik \'Switch Pattern\' dan \'Anchor\' di mana Anda bisa memicu rasa tenang instan saat serangan mau datang. Kami juga melatih pernapasan diafragma yang dikombinasikan dengan Dzikir (seperti \'Hasbunallah\') untuk menstabilkan detak jantung. Tujuan akhirnya adalah memberitahu bawah sadar bahwa Anda aman.','panik,sesak,jantung berdebar,panic attack',9,1,'2025-12-25 17:55:43','2025-12-25 17:55:43'),
(7,'conditions','Phobia: Cynophobia','Anak saya takut banget sama kucing, sampai histeris.','Cynophobia (takut kucing) sangat bisa disembuhkan. Kami menggunakan metode desensitisasi sistematis dalam kondisi trance. Anak akan diajak membayangkan kucing dari jarak jauh dalam suasana aman, perlahan mendekat, hingga berinteraksi, sambil mempertahankan rasa rileks. Kami sering menggabungkan ini dengan cerita metafora tentang kucing kesayangan Nabi untuk mengubah persepsi menakutkan menjadi kasih sayang. Biasanya butuh 2-3 sesi saja.','takut kucing,cynophobia,fobia hewan,anak',8,1,'2025-12-25 17:55:43','2025-12-25 17:55:43'),
(8,'conditions','Phobia: Acrophobia','Saya gak berani naik pesawat atau tempat tinggi.','Acrophobia seringkali berhubungan dengan rasa \'hilang kendali\'. Dalam terapi, kami melakukan simulasi mental naik pesawat/tempat tinggi sambil memberikan sugesti relaksasi otot. Kami menanamkan \'Safety Anchor\', sebuah pemicu fisik (misal menyentuh jempol dan telunjuk) yang otomatis membuat tubuh rileks saat ketinggian mulai terasa. Success rate untuk fobia spesifik seperti ini mencapai 90%.','takut tinggi,pesawat,acrophobia,terbang',8,1,'2025-12-25 17:55:43','2025-12-25 17:55:43'),
(9,'conditions','Depresi Ringan','Rasanya hampa dan sedih terus, apakah ini depresi?','Perasaan hampa berkepanjangan bisa jadi tanda depresi ringan hingga sedang. Hipnoterapi membantu dengan memutus siklus pikiran negatif (ruminasi). Kami mengajak Anda berdialog dengan \'bagian diri\' yang merasa sedih (Parts Therapy) untuk memahami pesan di baliknya, bukan melawannya. Dikombinasikan dengan terapi syukur dan dzikir, kami membantu menyalakan kembali harapan. *Catatan: Untuk depresi berat dengan risiko bunuh diri, kami mewajibkan pendampingan psikiater.*','sedih,depresi,hampa,bad mood',9,1,'2025-12-25 17:55:43','2025-12-25 17:55:43'),
(10,'conditions','Trauma Masa Kecil','Saya punya trauma dipukul orang tua waktu kecil.','Inner Child Healing adalah spesialisasi kami. Kami akan memandu Anda (dalam kondisi dewasa saat ini) untuk menemui \'diri kecil\' Anda di dalam pikiran yang masih menyimpan rasa sakit itu. Anda akan memberikan perlindungan, kasih sayang, dan pemahaman yang dulu tidak didapatkan. Proses ini sangat emosional tapi sangat melegakan. Luka masa lalu tidak dihapus memorinya, tapi muatan emosi sakitnya dinetralkan sepenuhnya.','trauma,pukul,kekerasan,inner child',10,1,'2025-12-25 17:55:43','2025-12-25 17:55:43'),
(11,'conditions','Insomnia','Susah banget tidur, otak mikir terus tiap malam.','Insomnia sering disebabkan oleh gelombang otak Beta yang terlalu aktif saat harusnya masuk ke Alpha/Theta. Kami melatih \'Self-Hypnosis\' khusus tidur. Anda akan diajarkan teknik mematikan \'saklar\' pikiran satu per satu dari ujung kaki ke kepala. Kami juga memberikan audio terapi khusus (sleep hypnotherapy) yang didalamnya terdapat lantunan ayat suci lembut untuk didengarkan saat mau tidur.','susah tidur,insomnia,begadang,lelah',9,1,'2025-12-25 17:55:44','2025-12-25 17:55:44'),
(12,'conditions','Kecanduan Game Online','Anak saya kecanduan game sampai bolos sekolah.','Kecanduan game adalah pelarian dari ketidaknyamanan di dunia nyata atau kebutuhan akan dopamin instan. Terapi kami tidak langsung melarang, tapi mencari \'kebutuhan apa\' yang dipenuhi game itu (pengakuan? tantangan?). Kami menggunakan teknik \'Aversion Therapy\' (membuat game terasa membosankan) sekaligus membangun motivasi baru untuk aktivitas nyata. Perlu kerjasama orang tua untuk membatasi gadget di rumah.','game,kecanduan,gadget,ml,ff',9,1,'2025-12-25 17:55:44','2025-12-25 17:55:44'),
(13,'islamic','Hukum Hipnoterapi','Apa hukum hipnoterapi dalam Islam? Halal?','Hipnoterapi di Albashiro Insya Allah 100% Halal. Fatwa ulama memperbolehkan hipnoterapi selama: (1) Tidak menggunakan bantuan jin/khodam, (2) Tidak mengandung mantra syirik, (3) Bertujuan untuk pengobatan (ishlah). Kami murni menggunakan potensi akal dan jiwa yang dianugerahkan Allah (neuroscience & psikologi). Klien tetap sadar dan justru diarahkan untuk semakin dekat pada Allah.','halal,haram,hukum islam,syirik',10,1,'2025-12-25 17:55:44','2025-12-25 17:55:44'),
(14,'islamic','Dzikir Istighfar','Gimana Istighfar dipakai buat terapi?','Istighfar bukan sekadar lisan, tapi \'pembersih jiwa\'. Dalam sesi \'Cleansing\', klien dibimbing masuk kondisi deep trance, lalu diminta memvisualisasikan dosa, kesalahan, atau beban masa lalu sebagai noda hitam. Dengan setiap tarikan napas dan ucapan \'Astaghfirullah\', klien memvisualisasikan noda itu luntur disiram cahaya Rahmat Allah. Ini memberikan efek kelegaan psikologis yang luar biasa (catharsis) dan ketenangan batin.','istighfar,taubat,cleansing,dosa',8,1,'2025-12-25 17:55:44','2025-12-25 17:55:44'),
(15,'islamic','Ruqyah vs Hipnoterapi','Bedanya sama Ruqyah Syar\'iyyah apa?','Ruqyah Syar\'iyyah fokus pada gangguan yang bersifat spiritual/ghaib atau penyakit ain dengan bacan Al-Quran. Hipnoterapi fokus pada gangguan psikologis/pola pikir/memori. Di Albashiro, kami mengintegrasikan keduanya. Jika masalahnya murni psikologis (misal: fobia), kami pakai hipnoterapi. Jika ada indikasi gangguan jin, kami sarankan Ruqyah. Namun, seringkali \'gangguan\' terasa berat karena pikiran lemah, jadi hipnoterapi memperkuat jiwa agar tidak mudah diganggu.','ruqyah,jin,sihir,beda',8,1,'2025-12-25 17:55:45','2025-12-25 17:55:45'),
(16,'islamic','Ayat Kursi','Kenapa baca Ayat Kursi pas terapi?','Ayat Kursi adalah ayat perlindungan terkuat. Kami menggunakannya di awal sesi (Induksi) dan akhir sesi (Terminasi) sebagai \'Spiritual Anchor\'. Ini memberikan sugesti kuat kepada klien bahwa mereka dalam lindungan Allah yang Maha Kuat, sehingga rasa takut atau cemas saat terapi hilang. Secara psikologis, ini meningkatkan rasa aman (security) yang krusial untuk keberhasilan terapi.','ayat kursi,lindungan,doa,bacaan',7,1,'2025-12-25 17:55:45','2025-12-25 17:55:45'),
(17,'pricing','Biaya Sesi Individual','Berapa biaya per sesi untuk satu orang?','Investasi untuk satu sesi hipnoterapi individual (dewasa) adalah Rp [HARGA]. Ini mencakup sesi 2 jam penuh, konsultasi mendalam, terapi inti, dan rekaman audio self-hypnosis custom untuk dibawa pulang. Kami menyarankan minimal komitmen 3 sesi untuk hasil permanen, karena pikiran butuh repetisi untuk berubah.','harga,biaya,tarif,murah',9,1,'2025-12-25 17:55:45','2025-12-25 17:55:45'),
(18,'pricing','Paket Hemat','Ada paket hemat kalau ambil banyak sesi?','Ada. Kami menyediakan \'Transformation Package\' isi 5 sesi dengan diskon 20%. Paket ini cocok untuk masalah kompleks seperti depresi menahun, trauma berat, atau penurunan berat badan. Selain lebih hemat, mengambil paket menunjukkan komitmen Anda untuk sembuh, yang secara psikologis meningkatkan success rate terapi hingga 30%. Pembayaran bisa dicicil 2x.','paket,diskon,promo,murah',9,1,'2025-12-25 17:55:45','2025-12-25 17:55:45'),
(19,'pricing','Layanan Online','Bisa terapi online? Biayanya sama?','Bisa banget! Hipnoterapi via Zoom/Video Call sama efektifnya dengan tatap muka, asalkan Anda punya koneksi internet stabil dan headset. Malah banyak klien lebih rileks karena berada di kamar sendiri. Biayanya sama, karena durasi dan keahlian terapis yang digunakan tetap sama. Kelebihannya, Anda hemat waktu dan ongkos perjalanan.','online,zoom,jarak jauh,biaya',8,1,'2025-12-25 17:55:45','2025-12-25 17:55:45'),
(20,'pricing','Corporate/Group','Bisa buat kantor atau grup karyawan?','Bisa. Kami memiliki program \'Corporate Wellness\' untuk mengatasi stres kerja, burnout, atau meningkatkan sales performance. Formatnya bisa workshop sehari atau sesi grup relaksasi. Biaya mulai dari Rp [HARGA] per pax untuk grup minimal 10 orang. Ini investasi bagus untuk produktivitas perusahaan karena karyawan yang bahagia adalah karyawan yang produktif.','kantor,grup,corporate,karyawan',7,1,'2025-12-25 17:55:46','2025-12-25 17:55:46'),
(21,'policies','Cara Booking','Gimana cara daftar antriannya?','Booking wajib dilakukan minimal H-1. Silakan isi form pendaftaran di website atau WA admin kami. Anda perlu membayar Down Payment (DP) sebesar 50% untuk mengunci jadwal. Ini penting karena satu sesi memakan waktu 2 jam, jadi kami harus memastikan slot tersebut benar-benar terisi. Jadwal weekend biasanya penuh 2 minggu sebelumnya, jadi saran kami booking jauh hari.','daftar,booking,cara,reservasi',8,1,'2025-12-25 17:55:46','2025-12-25 17:55:46'),
(22,'policies','Kebijakan Batal','Kalau batal mendadak hangus gak uangnya?','Jika pembatalan dilakukan lebih dari 24 jam sebelum jadwal, DP bisa direfund 100% atau reschedule gratis. Jika pembatalan dilakukan di bawah 24 jam (mendadak), mohon maaf DP hangus sebagai kompensasi waktu terapis yang terbuang. Namun, untuk kondisi darurat (sakit keras, musibah), kami berikan toleransi reschedule 1x tanpa biaya tambahan. Fair kan?','batal,cancel,refund,uang kembali',8,1,'2025-12-25 17:55:46','2025-12-25 17:55:46'),
(23,'policies','Privasi Data','Rahasia saya aman gak? Takut bocor.','Privasi Anda adalah harga mati bagi kami. Albashiro memegang teguh Kode Etik Hipnoterapi. Semua data rekam medis, cerita aib, atau pengakuan selama sesi dijamin 100% RAHASIA dan tidak akan dibagikan ke siapapun (termasuk pasangan/orang tua) tanpa izin tertulis dari Anda, kecuali ada indikasi yang membahayakan nyawa. Kami menggunakan sistem database terenkripsi untuk keamanan data digital.','rahasia,privasi,aman,bocor',10,1,'2025-12-25 17:55:46','2025-12-25 17:55:46'),
(24,'process','Tahap Anamnesis','Apa yang dilakukan pas awal datang?','Tahap pertama adalah Anamnesis atau wawancara mendalam. Di sini kita ngobrol santai tapi terarah. Terapis akan menggali akar masalah, pola pikir, dan tujuan Anda. Ini bukan sekadar curhat, tapi kami memetakan \'peta mental\' Anda. Kejujuran Anda di tahap ini sangat menentukan keberhasilan terapi. Jangan khawatir, kami tidak menghakimi (non-judgmental).','awal,konsultasi,wawancara,anamnesis',7,1,'2025-12-25 17:55:46','2025-12-25 17:55:46'),
(25,'process','Induksi','Susah gak sih dihipnotis?','Gak susah kok. Induksi adalah proses membimbing Anda dari gelombang otak Beta (sadar penuh) ke Alpha/Theta (rileks). Caranya macam-macam, bisa dengan fokus napas, relaksasi otot, atau visualisasi turun tangga. Kuncinya cuma satu: \'Niat dan Pasrah\'. Kalau Anda berniat sembuh dan mengikuti arahan terapis tanpa menganalisa, Anda akan masuk kondisi trance dengan sangat mudah dan nikmat.','masuk,trance,induksi,susah',8,1,'2025-12-25 17:55:47','2025-12-25 17:55:47'),
(26,'process','Teknik NLP','Katanya pakai NLP juga, itu apa?','NLP (Neuro-Linguistic Programming) adalah teknologi pikiran untuk memprogram ulang respon otak. Contoh: Jika Anda takut public speaking, kami pakai teknik \'Swish Pattern\'. Kami ambil gambar mental Anda yang takut, lalu \'timpa\' dengan gambar mental Anda yang percaya diri secara cepat dan berulang. Otak akan \'bingung\' dan akhirnya memilih gambar yang percaya diri sebagai default baru. Ini sangat efektif dan cepat.','nlp,teknik,metode,program',7,1,'2025-12-25 17:55:47','2025-12-25 17:55:47'),
(27,'process','Self-Hypnosis','Saya diajarin cara terapi sendiri gak?','Pasti! Tujuan Albashiro adalah memandirikan klien. Di setiap sesi, kami mengajarkan teknik Self-Hypnosis sederhana. Misalnya teknik \'3 Jari\' (Anchor) untuk memanggil rasa tenang kapan saja. Anda juga akan diajarkan cara membuat sugesti (afirmasi) yang benar supaya bisa memprogram diri sendiri di rumah sebelum tidur. Anda jadi terapis buat diri sendiri.','sendiri,mandiri,belajar,rumah',8,1,'2025-12-25 17:55:47','2025-12-25 17:55:47'),
(28,'age_specific','Anak (5-12 Tahun)','Anak saya susah diatur, bisa diterapi?','Untuk anak usia 5-12 tahun, pendekatan kami beda. Kami tidak suruh mereka \'tidur\', tapi bermain lewat cerita (storytelling) dan imajinasi. Dunia anak adalah dunia Alpha (imajinatif), jadi mereka sebenarnya subjek hipnosis terbaik. Kami selipkan pesan moral dan perubahan perilaku lewat dongeng di mana si anak jadi pahlawannya. Orang tua wajib ikut sesi konseling awal untuk menyamakan pola asuh di rumah.','anak,kecil,nakal,susah diatur',9,1,'2025-12-25 17:55:47','2025-12-25 17:55:47'),
(29,'age_specific','Remaja (13-18 Tahun)','Remaja pemberontak dan tertutup, gimana pendekatannya?','Remaja butuh didengar, bukan diceramahi. Terapis kami memposisikan diri sebagai \'sahabat mentor\'. Kami masuk ke dunia mereka (bahasa gaul, minat mereka) untuk membangun kepercayaan (rapport). Isu remaja biasanya seputar identitas, bullying, atau akademik. Hipnoterapi membantu meningkatkan \'Self-Worth\' mereka sehingga tidak mudah terpengaruh lingkungan buruk. Privasi mereka sangat kami jaga agar mereka mau terbuka.','remaja,abg,pemberontak,sekolah',9,1,'2025-12-25 17:55:47','2025-12-25 17:55:47'),
(30,'age_specific','Lansia (60+)','Orang tua saya sering cemas mikirin mati.','Ini umum terjadi pada lansia (Thanatophobia). Kami menggunakan pendekatan Spiritual Hypnotherapy yang lembut. Fokusnya adalah \'Penerimaan\' (Acceptance) dan \'Persiapan Jiwa\'. Kami membimbing mereka untuk berdamai dengan masa lalu (memaafkan semua orang) dan melihat kematian sebagai fase indah \'Pulang\' kepada Sang Kekasih (Allah). Dzikir napas sangat membantu menenangkan jantung dan pikiran mereka.','tua,lansia,mati,cemas',8,1,'2025-12-25 17:55:48','2025-12-25 17:55:48'),
(31,'research','Efektivitas','Ada bukti ilmiahnya gak sih hipnoterapi ini?','Banyak. Jurnal *American Health Magazine* merilis studi perbandingan: Psikoanalisis 38% sembuh (600 sesi), Behavior Therapy 72% sembuh (22 sesi), sedangkan **Hipnoterapi 93% sembuh hanya dalam 6 sesi**. Studi neuroimaging (MRI) juga menunjukkan saat trance, area otak yang memproses rasa sakit dan emosi menjadi lebih tenang, memungkinkan \'re-wiring\' saraf otak (neuroplasticity) terjadi lebih cepat.','ilmiah,bukti,riset,jurnal',8,1,'2025-12-25 17:55:48','2025-12-25 17:55:48'),
(32,'myths','Mitos: Hilang Kesadaran','Takut nanti gak sadar terus rahasia terbongkar.','Ini mitos terbesar. Hipnotis TIDAK bikin pingsan atau tidur. Anda sadar 100%, bahkan fokus Anda meningkat tajam. Anda tetap punya kontrol penuh. Jika terapis minta password ATM atau hal yang bertentangan moral Anda, \'Critical Factor\' di otak Anda akan langsung menolak dan Anda akan terbangun. Anda hanya akan menceritakan apa yang memang INGIN Anda ceritakan.','mitos,sadar,pingsan,kontrol',9,1,'2025-12-25 17:55:48','2025-12-25 17:55:48'),
(33,'myths','Mitos: Permanen','Apa hasilnya permanen atau bisa kambuh?','Hasil hipnoterapi cenderung permanen karena kita mengubah \'software\' di akarnya. Ibarat komputer yang sudah di-install ulang, virusnya hilang. NAMUN, manusia itu dinamis. Jika setelah sembuh Anda kembali ke lingkungan toxic yang sama tanpa menjaga \'imun mental\' (ibadah, pola pikir), bisa saja muncul masalah baru. Makanya kami bekali dengan Self-Hypnosis untuk maintenance seumur hidup.','permanen,kambuh,hasil,awet',9,1,'2025-12-25 17:55:48','2025-12-25 17:55:48'),
(34,'special','Ibu Hamil (Hypnobirthing)','Bisa bantu biar melahirkan gak sakit?','Bisa, metodenya disebut Hypnobirthing. Kami melatih ibu hamil untuk masuk kondisi relaksasi dalam hitungan detik. Prinsipnya: Takut = Tegang = Sakit. Dengan menghilangkan rasa takut dan melatih otot rahim untuk rileks, proses melahirkan bisa jauh lebih nyaman, cepat, dan minim rasa sakit (bahkan tanpa sakit). Kami juga menanamkan ikatan batin (bonding) dengan janin sejak dalam kandungan.','hamil,melahirkan,sakit,bumil',8,1,'2025-12-25 17:55:48','2025-12-25 17:55:48'),
(35,'special','Public Speaking','Besok mau presentasi penting, gugup banget!','Untuk kebutuhan mendesak, kami punya sesi \'Power Confidence\'. Kami akan melakukan teknik \'Circle of Excellence\'. Anda diminta mengingat momen paling percaya diri dalam hidup, lalu emosi itu \'jangkarkan\' ke gerakan tangan tertentu. Besok saat presentasi, cukup lakukan gerakan itu, dan otak akan membanjiri tubuh dengan hormon percaya diri. Kami juga visualisasikan presentasi Anda berjalan sukses berkali-kali sampai otak percaya itu nyata.','bicara,pidato,presentasi,gugup',8,1,'2025-12-25 17:55:49','2025-12-25 17:55:49'),
(36,'special','Berhenti Merokok','Mau berhenti merokok tapi susah banget.','Rokok itu 10% kecanduan nikotin, 90% kebiasaan psikologis (tangan iseng, teman ngopi, buang stres). Hipnoterapi memutus asosiasi \'Rokok = Enak/Tenang\'. Kami ganti persepsi di bawah sadar bahwa \'Rokok = Racun/Menjijikkan\'. Seringkali klien langsung mual atau terasa pahit saat mencoba merokok setelah sesi pertama. Success rate tinggi jika NIAT dari diri sendiri, bukan disuruh istri/suami.','rokok,berhenti,smoking,paru',9,1,'2025-12-25 17:55:49','2025-12-25 17:55:49'),
(37,'conditions','Weight Loss (Langsing)','Diet selalu gagal, bisa bantu kurus?','Hypnoslimming bukan diet ketat, tapi mengubah \'Mindset Makan\'. Kami memprogram ulang bawah sadar untuk: (1) Berhenti makan saat kenyang (Stop signal), (2) Tidak \'Emotional Eating\' (makan saat stres/bosan), (3) Craving makanan sehat. Tanpa obat, tanpa siksaan. Anda akan otomatis memilih makanan sehat karena \'ingin\', bukan karena \'terpaksa\'. Berat badan turun alami dan stabil.','kurus,langsing,diet,gendut',8,1,'2025-12-25 17:55:49','2025-12-25 17:55:49'),
(38,'conditions','Disfungsi Seksual (Psikologis)','Punya masalah ranjang karena cemas, bisa?','Bisa, selama sudah cek medis dan dokter bilang fisik normal (penyebab psikologis). Kecemasan performa (Performance Anxiety) sering jadi biang kerok impoten atau ejakulasi dini psikogenik. Kami bantu rilekskan pikiran, buang trauma masa lalu, dan bangun kepercayaan diri. Privasi dijamin super ketat untuk kasus sensitif seperti ini. Terapi bisa dilakukan tanpa menyentuh area sensitif sama sekali.','seks,lemah,cemas,pasutri',7,1,'2025-12-25 17:55:49','2025-12-25 17:55:49'),
(39,'islamic','Qolbun Salim','Apa goal akhir terapi secara Islam?','Goal akhirnya adalah mencapai *Qolbun Salim* (Hati yang Selamat/Sehat). Bukan sekadar bebas dari cemas/depresi, tapi memiliki hati yang tenang, ridho dengan takdir Allah, dan optimis menatap masa depan. Terapi Albashiro adalah ikhtiar membersihkan cermin hati dari debu-debu masalah duniawi agar bisa memantulkan cahaya Ilahi dengan sempurna. Sembuh mental, bangkit spiritual.','hati,sehat,tujuan,akhirat',9,1,'2025-12-25 17:55:49','2025-12-25 17:55:49'),
(40,'faq_general','Persiapan Sesi','Apa yang harus disiapkan sebelum datang?','(1) Niat yang kuat untuk sembuh. (2) Istirahat cukup, jangan begadang malam sebelumnya. (3) Jangan makan terlalu kenyang (bikin ngantuk) atau perut kosong (bikin gak fokus). (4) Kenakan pakaian yang longgar dan nyaman. (5) Matikan HP selama sesi. (6) Datang 15 menit lebih awal agar napas sudah tenang saat sesi dimulai.','siap,bawa,baju,makan',7,1,'2025-12-25 17:55:50','2025-12-25 17:55:50'),
(41,'special','Mahasiswa Skripsi','Stres ngerjain skripsi, jadi nunda terus (procrastination).','Procrastination (menunda) sebenarnya adalah rasa takut: takut gagal, takut salah, atau takut dinilai dosen. Kami bantu bongkar blok mental \'Writer\'s Block\' ini. Kami tanamkan sugesti \'Flow State\' di mana saat Anda buka laptop, ide mengalir lancar. Kami juga ubah persepsi \'Skripsi = Beban\' menjadi \'Skripsi = Tiket Kesuksesan\'. Semangat Anda akan balik lagi!','skripsi,malas,nunda,kuliah',8,1,'2025-12-25 17:55:50','2025-12-25 17:55:50'),
(42,'conditions','OCD (Was-was)','Saya harus cek kunci pintu 10x baru tenang.','Itu gejala OCD (Obsessive-Compulsive Disorder) atau dalam Islam penyakit \'Was-was\'. Penderitanya tersiksa oleh pikiran berulang. Terapi kami memutus loop \'Obsesi -> Kompulsi\'. Kami ajarkan teknik \'Stop Thought\' dan menunda respon. Secara spiritual, kami perkuat keyakinan bahwa \'Satu kali cek dengan Bismillah sudah cukup\', menyerahkan sisanya pada penjagaan Allah (Tawakkal).','ocd,cek,ulang,waswas',8,1,'2025-12-25 17:55:50','2025-12-25 17:55:50'),
(43,'conditions','Gerd & Psikosomatis','Kata dokter lambung saya bagus, tapi sakit terus.','Itu klasik Psikosomatis. Emosi yang dipendam (marah/sedih) tidak bisa keluar lewat mulut, akhirnya \'menyerang\' organ tubuh (seringnya lambung/kepala). Obat dokter hanya meredakan gejala fisik. Hipnoterapi menyembuhkan \'luka batin\' penyebabnya. Saat emosi negatif dirilis (biasanya lewat nangis saat terapi), ajaibnya sakit lambung (GERD) seringkali sembuh total tanpa obat lagi.','gerd,lambung,maag,fisik',9,1,'2025-12-25 17:55:50','2025-12-25 17:55:50'),
(44,'pricing','Refund Policy','Kalau gak sembuh uang kembali?','Dalam dunia medis dan terapi, kode etik melarang garansi kesembuhan karena kesembuhan adalah hak prerogatif Allah dan tergantung kerjasama klien. Kami menjamin \'Garansi Layanan\': Terapis kami akan memberikan usaha 100% terbaik, teknik yang tepat, dan waktu yang full. Anda membayar untuk waktu dan keahlian profesional terapis, bukan hasil akhir yang di luar kendali manusia.','garansi,uang,kembali,jamin',7,1,'2025-12-25 17:55:51','2025-12-25 17:55:51'),
(45,'process','Pasca Terapi','Habis terapi rasanya gimana?','Umumnya Anda akan merasa sangat \'Plong\', ringan, seperti beban berat diangkat dari pundak. Badan mungkin terasa sedikit lelah (seperti habis olahraga) karena pelepasan emosi menguras energi, tapi pikiran sangat jernih. Malamnya biasanya tidur sangat nyenyak. Beberapa orang mengalami \'Healing Crisis\' (emosi naik turun) selama 1-2 hari, itu wajar tanda proses detoks mental sedang bekerja.','rasa,hasil,efek,setelah',8,1,'2025-12-25 17:55:51','2025-12-25 17:55:51'),
(46,'islamic','Sholat Khusyuk','Bisa bantu biar sholat lebih khusyuk?','Bisa. Ketidakkhusyukan sering karena \'Monkey Mind\' (pikiran loncat-loncat). Kami latih fokus Anda dengan teknik \'Mindfulness\' yang diadaptasi secara Islami. Kami bantu Anda masuk kondisi Alpha sebelum Takbiratul Ihram, sehingga dunia luar \'mute\' dan Anda hanya fokus pada dialog dengan Allah. Klien sering menangis haru saat sholat setelah menjalani sesi ini.','sholat,ibadah,fokus,khusyuk',8,1,'2025-12-25 17:55:51','2025-12-25 17:55:51'),
(47,'category','topic','question','answer','keywords',0,1,'2025-12-25 17:55:51','2025-12-25 17:55:51'),
(48,'conditions','Phobia: Trypanophobia (Jarum Suntik)','Saya takut banget disuntik atau lihat jarum, sampai pingsan.','Trypanophobia sangat umum. Kami menggunakan teknik \'Dissociation\', di mana Anda dilatih untuk memisahkan sensasi fisik dari respon emosional. Dalam kondisi trance, kami mensugestikan bahwa lengan Anda menjadi \'kebas\' atau \'dingin seperti es\' (anestesi mental), sehingga saat jarum masuk, rasanya netral. Sangat efektif untuk persiapan vaksinasi atau tes darah.','jarum,suntik,dokter,vaksin',8,1,'2025-12-25 17:55:52','2025-12-25 17:55:52'),
(49,'conditions','Phobia: Claustrophobia (Ruang Sempit)','Gak berani naik lift atau masuk ruang sempit (Claustrophobia).','Claustrophobia memicu rasa tercekik. Terapi kami fokus meluaskan persepsi ruang internal. Meski fisik di ruang sempit, pikiran Anda dilatih untuk merasa berada di padang rumput luas (Mental Expansion). Kami juga merilis trauma masa lalu (mungkin pernah terkunci) yang menjadi akar masalahnya.','sempit,lift,tutup,sesak',8,1,'2025-12-25 17:55:52','2025-12-25 17:55:52'),
(50,'conditions','Phobia: Glossophobia (Bicara Depan Umum)','Badan gemetar dan blank saat harus bicara di depan orang banyak.','Glossophobia diatasi dengan \'Circle of Excellence\'. Kami memprogram ulang respon saraf Anda. Alih-alih \'Takut = Bahaya\', kami ubah menjadi \'Gugup = Energi/Adrenalin Positif\'. Kami visualisasikan Anda sukses presentasi berkali-kali di bawah sadar, sehingga saat hari-H, otak merasa \'ini sudah biasa\'.','bicara,pidato,gugup,panggung',9,1,'2025-12-25 17:55:52','2025-12-25 17:55:52'),
(51,'conditions','Phobia: Aviophobia (Takut Terbang)','Besok harus dinas luar kota tapi takut naik pesawat.','Aviophobia seringkali karena takut kehilangan kendali dan suara mesin. Kami berikan audio terapi khusus untuk didengarkan di pesawat. Tekniknya meliputi relaksasi otot progresif saat take-off dan mengubah persepsi guncangan turbulensi menjadi seperti \'ayunan bayi\' yang menenangkan, bukan tanda bahaya.','pesawat,terbang,bandara,jatuh',8,1,'2025-12-25 17:55:52','2025-12-25 17:55:52'),
(52,'conditions','Phobia: Arachnophobia (Laba-laba)','Histeris kalau lihat laba-laba atau serangga.','Kami menggunakan teknik \'Visual Swish\'. Bayangan laba-laba yang menyeramkan di otak Anda akan dikecilkan ukurannya menjadi hitam putih, lalu diberi musik latar lucu (seperti sirkus), sehingga respon otak berubah dari takut menjadi geli atau netral. Ini memutus jalur saraf ketakutan secara instan.','laba-laba,serangga,jijik,takut',7,1,'2025-12-25 17:55:53','2025-12-25 17:55:53'),
(53,'conditions','Phobia: Nyctophobia (Gelap)','Anak saya gak berani tidur sendiri kalau lampu mati.','Nyctophobia pada anak diatasi dengan teknik \'Magic Protector\'. Dalam kondisi alpha, kami ajak anak menciptakan pelindung imajiner atau menghadirkan rasa aman dari Allah (Malaikat Penjaga). Kami ubah persepsi \'Gelap = Ada Hantu\' menjadi \'Gelap = Waktunya Istirahat Nyaman\'.','gelap,lampu,hantu,tidur',8,1,'2025-12-25 17:55:53','2025-12-25 17:55:53'),
(54,'conditions','Phobia: Hemophobia (Darah)','Lihat darah sedikit langsung lemas dan mual.','Hemophobia terkait respon vasovagal. Hipnoterapi melatih tubuh untuk tetap menjaga tekanan darah stabil saat melihat visual darah. Kami desensitisasi bertahap: dari membayangkan warna merah, melihat gambar, hingga visualisasi darah realistik, sambil mempertahankan kondisi rileks total.','darah,luka,merah,pingsan',7,1,'2025-12-25 17:55:53','2025-12-25 17:55:53'),
(55,'conditions','Phobia: Emetophobia (Muntah)','Takut banget kalau mau muntah atau lihat orang muntah.','Emetophobia sering membuat orang takut makan (takut keracunan). Terapi fokus pada \'Trust your Body\'. Kami tanamkan sugesti bahwa tubuh punya mekanisme cerdas dan muntah adalah proses pembersihan, bukan bahaya. Kami kurangi hiper-vigilance (kewaspadaan berlebih) terhadap sensasi perut.','muntah,mual,jijik,sakit',7,1,'2025-12-25 17:55:53','2025-12-25 17:55:53'),
(56,'conditions','Phobia: Astraphobia (Petir)','Ketakutan berlebihan saat hujan deras dan petir.','Astraphobia diatasi dengan mengubah asosiasi suara. Suara guntur yang menggelegar di-reframe (bingkai ulang) menjadi suara tepuk tangan alam atau dzikir semesta. Klien diajarkan anchor ketenangan di dada yang diaktifkan setiap kali melihat kilatan cahaya.','petir,hujan,badai,kilat',7,1,'2025-12-25 17:55:53','2025-12-25 17:55:53'),
(57,'conditions','Phobia: Dentophobia (Dokter Gigi)','Gigi sakit tapi takut ke dokter gigi.','Dentophobia bisa menghambat kesehatan. Kami gunakan \'Hypno-Anesthesia\' (bius mental). Anda diajarkan cara mematikan rasa sakit di gusi secara mental dan mengalihkan fokus pikiran ke tempat liburan favorit saat dokter bekerja. Suara bor dokter disugestikan sebagai suara background yang tidak mengganggu.','gigi,dokter,bor,sakit',8,1,'2025-12-25 17:55:54','2025-12-25 17:55:54'),
(58,'conditions','Habit: Gigit Kuku (Onychophagia)','Susah berhenti gigit kuku sampai berdarah.','Gigit kuku adalah respon bawah sadar terhadap stres atau kebosanan. Kami gunakan \'Aversion Therapy\': mensugestikan rasa pahit yang luar biasa di lidah setiap kali jari mendekat ke mulut. Sekaligus, kami berikan alternatif gerakan tangan baru (seperti menyatukan jari) sebagai penyalur stres yang lebih sehat.','kuku,gigit,jorok,kebiasaan',8,1,'2025-12-25 17:55:54','2025-12-25 17:55:54'),
(59,'conditions','Habit: Mencabut Rambut (Trichotillomania)','Suka tanpa sadar cabutin rambut atau alis.','Trichotillomania adalah gangguan kontrol impuls. Hipnoterapi membantu meningkatkan kesadaran (awareness) tepat sebelum tangan menyentuh rambut. Kami mencari akar kecemasan yang memicu impuls ini dan menyelesaikannya. Teknik \'Hand Anchor\' digunakan untuk membekukan tangan secara mental saat ingin mencabut.','rambut,cabut,botak,alis',8,1,'2025-12-25 17:55:54','2025-12-25 17:55:54'),
(60,'conditions','Habit: Belanja Impulsif (Shopaholic)','Gak bisa nahan belanja, gaji lewat doang.','Belanja impulsif seringkali untuk menambal rasa sepi atau kurang berharga (low self-esteem). Kami bantu Anda merasa \'Cukup\' dan \'Berharga\' tanpa barang baru. Kami pasang \'Mental Stop Sign\' yang otomatis muncul saat Anda melihat tulisan DISKON, memberi jeda waktu bagi logika untuk bekerja sebelum checkout.','belanja,boros,uang,shopping',8,1,'2025-12-25 17:55:54','2025-12-25 17:55:54'),
(61,'conditions','Habit: Kecanduan Gula/Manis','Mau diet tapi craving manis terus.','Sugar craving mirip kecanduan narkoba di otak. Kami putus asosiasi \'Manis = Bahagia\'. Kami ganti dengan sugesti bahwa makanan manis berlebih terasa \'enek\' atau terlalu giung. Di sisi lain, kami tingkatkan kenikmatan saat minum air putih dan makan sayur segar di pikiran bawah sadar Anda.','gula,manis,coklat,permen',8,1,'2025-12-25 17:55:54','2025-12-25 17:55:54'),
(62,'conditions','Habit: Menunda (Procrastination)','Suka nunda pekerjaan sampai deadline mepet.','Menunda bukan malas, tapi regulasi emosi yang buruk (takut gagal/sulit). Kami gunakan teknik \'Timeline Therapy\' untuk melihat dampak buruk penundaan di masa depan, lalu membawa motivasi itu ke masa kini. Kami pecah mental block yang membuat pekerjaan terasa berat menjadi langkah-langkah kecil yang menyenangkan.','nunda,malas,kerja,tugas',9,1,'2025-12-25 17:55:55','2025-12-25 17:55:55'),
(63,'conditions','Habit: Merokok Chain-smoker','Sehari bisa 2-3 bungkus rokok, tolong.','Untuk perokok berat, kami gunakan metode \'Spiritual Detachment\'. Kami ajak Anda melihat tubuh sebagai amanah Allah yang sedang didzalimi asap. Sugesti yang ditanamkan bukan hanya \'rokok jahat\', tapi \'Saya Penjaga Amanah\'. Seringkali kami kaitkan rasa rokok dengan sesuatu yang Anda benci (misal: rasa knalpot), sehingga fisik menolak otomatis.','rokok,asap,paru,berhenti',9,1,'2025-12-25 17:55:55','2025-12-25 17:55:55'),
(64,'conditions','Habit: Begadang','Suka begadang padahal gak ngapa-ngapain (Revenge Bedtime Procrastination).','Ini biasanya karena merasa \'waktu siang bukan milik sendiri\'. Kami bantu Anda merasa puas dengan hari Anda (fulfillment). Sugesti relaksasi dipasang jam 10 malam, di mana mata akan terasa berat alami dan gadget menjadi tidak menarik. Kami sinkronkan kembali ritme sirkadian tubuh Anda.','begadang,malam,tidur,ponsel',8,1,'2025-12-25 17:55:55','2025-12-25 17:55:55'),
(65,'conditions','Habit: Suka Marah/Emosian','Dikit-dikit emosi meledak, kasihan anak istri.','Anger management dengan hipnoterapi sangat efektif. Kami cari \'tombol\' pemicunya. Kami pasang \'Cooling System\' di otak: saat amarah naik, otomatis napas melambat dan pikiran berucap Istighfar. Anda akan memiliki jeda kesadaran antara Pemicu dan Respon, sehingga bisa memilih untuk sabar daripada meledak.','marah,emosi,galak,bentak',9,1,'2025-12-25 17:55:55','2025-12-25 17:55:55'),
(66,'conditions','Habit: Mengeluh','Hidup rasanya berat, saya jadi sering ngeluh.','Mengeluh adalah pemrograman negatif yang berulang. Kami lakukan \'Gratitude Conditioning\'. Setiap kali mau mengeluh, pikiran bawah sadar akan otomatis mengalihkannya mencari 3 hal yang bisa disyukuri saat itu juga. Ini mengubah vibrasi energi Anda dan menarik lebih banyak hal positif dalam hidup.','ngeluh,capek,nasib,sial',7,1,'2025-12-25 17:55:56','2025-12-25 17:55:56'),
(67,'conditions','Habit: Kecanduan Sosmed','Tiap menit scroll TikTok/IG, lupa waktu.','Dopamin detox mental. Kami ubah persepsi gadget dari \'sumber hiburan\' menjadi \'alat kerja\'. Kami tanamkan rasa bosan atau jenuh jika menatap layar lebih dari 15 menit tanpa tujuan. Anda akan merasa lebih \'hidup\' saat berinteraksi di dunia nyata daripada dunia maya.','sosmed,hp,scroll,candu',9,1,'2025-12-25 17:55:56','2025-12-25 17:55:56'),
(68,'kids','Anak: Ngompol (Enuresis)','Anak SD masih ngompol, malu sama teman.','Ngompol pada anak besar biasanya karena tidur terlalu nyenyak sehingga sinyal kandung kemih tidak membangunkan otak. Kami memprogram ulang \'Bladder Alarm\'. Sugestinya: \'Saat kandung kemih penuh, mata terbuka, bangun, jalan ke kamar mandi\'. Ini dilakukan tanpa obat, murni komunikasi pikiran bawah sadar.','ngompol,pipis,kasur,malu',8,1,'2025-12-25 17:55:56','2025-12-25 17:55:56'),
(69,'kids','Anak: Mogok Sekolah','Tiba-tiba gak mau sekolah, nangis terus.','Mogok sekolah pasti ada pemicunya (bullying, takut guru, atau cemas pisah). Kami gali penyebabnya lewat cerita metafora. Lalu kami berikan \'Mental Armor\' (baju zirah mental) agar anak merasa berani dan tangguh menghadapi lingkungan sekolah. Kami bangkitkan lagi rasa ingin tahunya yang menyenangkan tentang belajar.','sekolah,bolos,takut,guru',9,1,'2025-12-25 17:55:56','2025-12-25 17:55:56'),
(70,'kids','Anak: Susah Makan (GTM)','Anak susah makan, pilih-pilih banget (Picky Eater).','Kami gunakan imajinasi kreatif. Sayur disugestikan sebagai \'makanan superhero\' yang bikin kuat. Kami ubah persepsi tekstur atau rasa yang tidak disukai menjadi netral. Hipnoterapi juga bisa menstimulasi sinyal lapar alami di otak anak agar makan dengan lahap.','makan,gtm,sayur,kurus',8,1,'2025-12-25 17:55:56','2025-12-25 17:55:56'),
(71,'kids','Anak: Sibling Rivalry','Kakak adik berantem terus, saling benci.','Kami damaikan di level bawah sadar. Sesi bisa dilakukan bersama atau terpisah. Kami tanamkan rasa \'Satu Tim\' dan kasih sayang. Untuk kakak, kami beri peran \'Pelindung\', untuk adik peran \'Pendukung\'. Emosi cemburu (merasa kasih sayang ortu tidak adil) dinetralkan dan diganti rasa aman.','berantem,kakak,adik,rebut',7,1,'2025-12-25 17:55:57','2025-12-25 17:55:57'),
(72,'kids','Anak: Korban Bullying','Anak jadi pendiam setelah dibully teman.','Pemulihan trauma bullying sangat krusial agar tidak membekas sampai dewasa. Kami bantu anak melepaskan rasa malu dan takut. Kami \'Delete\' kata-kata jahat pembully dari belief system mereka, dan ganti dengan afirmasi positif. Kami latih postur tubuh percaya diri agar tidak jadi target bully lagi.','bully,ejek,sekolah,diam',10,1,'2025-12-25 17:55:57','2025-12-25 17:55:57'),
(73,'kids','Anak: Fokus Belajar/ADHD','Anak gak bisa diam, susah fokus belajar.','Untuk anak aktif/ADHD, kami tidak mematikan energi mereka, tapi mengarahkannya. Teknik \'Laser Focus\' diajarkan: saat belajar, dunia luar menjadi buram, hanya buku yang jelas. Kami gunakan anchor (misal: topi belajar) yang saat dipakai, otomatis mode fokus aktif.','fokus,belajar,aktif,adhd',9,1,'2025-12-25 17:55:57','2025-12-25 17:55:57'),
(74,'kids','Anak: Kecanduan Gadget','Kalau HP diambil ngamuk tantrum parah.','Ini gejala withdrawal. Kami kurangi level ketergantungan dopamin secara bertahap. Kami tanamkan sugesti bahwa dunia nyata (main bola, lego, gambar) jauh lebih seru warnanya dan rasanya. Tantrum diatasi dengan teknik \'Calm Down Anchor\' yang bisa diaktifkan orang tua dengan sentuhan tertentu (yang sudah diprogram di sesi).','hp,gadget,game,tantrum',9,1,'2025-12-25 17:55:57','2025-12-25 17:55:57'),
(75,'teen','Remaja: Patah Hati','Anak remaja saya depresi putus cinta.','Patah hati pertama rasanya seperti kiamat bagi remaja. Hipnoterapi membantu \'Cord Cutting\' (memutus ikatan emosi) dengan mantan. Kami bantu mereka melihat masa depan yang masih panjang dan cerah. Self-worth dinaikkan agar tidak merasa \'tidak laku\' atau hancur harga dirinya.','pacar,putus,galau,sedih',8,1,'2025-12-25 17:55:57','2025-12-25 17:55:57'),
(76,'teen','Remaja: Minder Jerawat','Minder gak mau keluar kamar karena jerawatan.','Body Dysmorphia ringan. Kami bantu remaja menerima diri (Self-Acceptance). Fokus dialihkan dari \'penampilan fisik\' ke \'potensi diri/bakat\'. Uniknya, saat stres berkurang karena hipnoterapi, hormon seimbang, dan jerawat seringkali malah berkurang kesembuhannya.','jerawat,minder,wajah,malu',7,1,'2025-12-25 17:55:58','2025-12-25 17:55:58'),
(77,'teen','Remaja: Ujian/SBMPTN','Stres berat mau ujian masuk kuliah.','Exam Anxiety bisa bikin blank saat ujian. Kami lakukan simulasi mental ujian berkali-kali dengan perasaan tenang. Kami tanamkan \'Recall Anchor\' untuk memudahkan memanggil memori pelajaran yang sudah dipelajari. Kondisi otak Alpha saat ujian justru meningkatkan IQ dan kreativitas menjawab soal.','ujian,tes,kuliah,stres',9,1,'2025-12-25 17:55:58','2025-12-25 17:55:58'),
(78,'adult','Dewasa: Masalah Kesuburan (Infertilitas)','Sudah promil lama belum hamil, dokter bilang stres.','Unexplained Infertility sering karena blok mental (takut jadi ibu, takut melahirkan, atau trauma masa lalu). Hipno-Fertility membantu menyiapkan \'Rumah Rahim\' yang nyaman secara mental. Kami instruksikan tubuh untuk menyeimbangkan hormon reproduksi dan menerima kehadiran janin dengan sukacita.','hamil,mandul,anak,promil',8,1,'2025-12-25 17:55:58','2025-12-25 17:55:58'),
(79,'adult','Dewasa: Vaginismus','Sakit luar biasa saat berhubungan intim (Vaginismus).','Vaginismus adalah refleks otot vagina yang menolak penetrasi karena takut/trauma. Ini murni di bawah sadar, bukan dibuat-buat. Terapi kami BUKAN pijat, tapi memprogram ulang respon otot panggul untuk rileks. Kami buang memori bahwa \'Seks = Sakit/Dosa\' dan ganti dengan \'Seks = Ibadah/Nikmat\'.','seks,sakit,vaginismus,istri',9,1,'2025-12-25 17:55:58','2025-12-25 17:55:58'),
(80,'adult','Dewasa: Ejakulasi Dini','Suami sering \'keluar\' duluan, jadi minder.','Jika fisik sehat, ini masalah kontrol pikiran. Kami ajarkan teknik \'Time Distortion\' (memperlambat persepsi waktu) dan kontrol sensitivitas. Kami kurangi kecemasan performa yang justru mempercepat ejakulasi. Kepercayaan diri suami dipulihkan, keharmonisan pasutri kembali.','suami,cepat,seks,ejakulasi',8,1,'2025-12-25 17:55:58','2025-12-25 17:55:58'),
(81,'adult','Dewasa: Takut Sukses','Aneh, tiap mau sukses bisnis pasti saya sabotase sendiri.','Itu \'Self-Sabotage\' atau \'Fear of Success\'. Mungkin bawah sadar Anda percaya \'Kalau kaya nanti sombong\' atau \'Kalau sukses nanti banyak yang iri\'. Kami cari \'Mental Block\' ini dan hancurkan (reframe). Kami selaraskan tujuan sadar (mau kaya) dengan tujuan bawah sadar (tetap aman/mulia).','sukses,gagal,bisnis,uang',9,1,'2025-12-25 17:55:59','2025-12-25 17:55:59'),
(82,'adult','Dewasa: Public Speaking Eksekutif','Saya direktur tapi gagap kalau meeting besar.','Executive Presence bisa dibangun. Kami hilangkan \'Imposter Syndrome\' (merasa tidak pantas memimpin). Teknik \'Circle of Excellence\' membuat kharisma Anda keluar alami. Suara menjadi lebih berwibawa dan pikiran tetap tenang meski dicecar pertanyaan sulit.','bos,rapat,gagap,pemimpin',9,1,'2025-12-25 17:55:59','2025-12-25 17:55:59'),
(83,'islamic','Gangguan Jin vs Psikologis','Saya sering mimpi buruk, ini jin atau stres?','Bisa dua-duanya. Di Albashiro, kami screening dulu. Jika saat didengarkan ayat Ruqyah ada reaksi fisik ekstrem, kami sarankan Ruqyah. Tapi seringkali mimpi buruk adalah \'sampah emosi\' siang hari yang belum tuntas. Dengan membersihkan emosi dan memaafkan sebelum tidur (Sleep Hypnosis Islami), mimpi buruk biasanya hilang tanpa perlu pengusiran jin.','mimpi,buruk,jin,setan',8,1,'2025-12-25 17:55:59','2025-12-25 17:55:59'),
(84,'islamic','Terapi Ikhlas','Gimana caranya ikhlas? Susah banget teorinya.','Ikhlas itu \'keterampilan jiwa\', bisa dilatih. Dalam trance, kami ajak Anda melepas kemelekatan (attachment) pada objek/orang yang hilang. Kami visualisasikan Anda menyerahkan beban itu langsung ke \'Tangan\' Allah. Rasa ringan yang muncul setelahnya adalah indikator ikhlas. Bukan melupakan, tapi tidak lagi sakit saat mengingatnya.','ikhlas,rela,lepas,berat',10,1,'2025-12-25 17:55:59','2025-12-25 17:55:59'),
(85,'islamic','Khusyuk dalam Dzikir','Dzikir cuma di lisan, hati kemana-mana.','Kami ajarkan \'Dzikir Nafas\'. Menyelaraskan lafaz Allah dengan irama napas dalam kondisi Alpha. Saat tubuh rileks, hijab-hijab duniawi tersingkap, rasa manisnya iman (Halawatul Iman) bisa dirasakan. Dzikir menjadi getaran di dada, bukan cuma suara di mulut.','dzikir,ingat,allah,hati',9,1,'2025-12-25 17:55:59','2025-12-25 17:55:59'),
(86,'islamic','Menghapus Dendam','Saya benci sekali sama orang yang menipu saya.','Dendam itu seperti minum racun tapi berharap orang lain yang mati. Terapi \'Forgiveness\' kami bukan untuk membenarkan perbuatan penipu, tapi untuk membebaskan DIRI ANDA dari penjara kebencian. Kami memutus tali emosi dengan penipu itu, sehingga Anda bisa move on dan rezeki kembali lancar. Hati yang sempit susah menarik rezeki.','dendam,benci,maaf,tipu',9,1,'2025-12-25 17:56:00','2025-12-25 17:56:00'),
(87,'islamic','Syukur Therapy','Merasa hidup gak adil, iri sama orang lain.','Penyakit hati \'Hasad\' membakar kebaikan. Kami lakukan terapi \'Re-orientasi Fokus\'. Bawah sadar dilatih untuk melihat nikmat yang ADA, bukan yang HILANG. Kami ajak Anda mensyukuri hal kecil (napas, detak jantung) dalam kondisi deep trance, yang efeknya ribuan kali lebih kuat daripada sekadar mengucap Alhamdulillah di bibir.','syukur,iri,adil,nikmat',8,1,'2025-12-25 17:56:00','2025-12-25 17:56:00'),
(88,'islamic','Taubat Nasuha Therapy','Merasa dosa banyak, putus asa dari rahmat Allah.','Rasa bersalah berlebihan bisa jadi penyakit. Kami bimbing Anda dalam sesi \'Spiritual Rebirth\'. Mengakui dosa, menangisinya, lalu menerima janji Allah yang Maha Pengampun. Kami bantu Anda memaafkan diri sendiri (Self-Forgiveness) agar bisa memulai lembaran baru tanpa bayang-bayang masa lalu.','dosa,taubat,hina,allah',9,1,'2025-12-25 17:56:00','2025-12-25 17:56:00'),
(89,'conditions','LGBT (Ego-Dystonic)','Saya punya ketertarikan sesama jenis tapi ingin berubah (ingin normal).','Kami melayani klien yang mengalami konflik batin (Ego-Dystonic) dan secara sadar INGIN berubah kembali ke fitrah. Pendekatan kami non-judgmental. Kami telusuri akar (misal: trauma figur ayah/ibu, pelecehan masa kecil). Kami kuatkan identitas maskulin/feminin asli Anda dan kurangi ketertarikan yang tidak diinginkan secara bertahap. *Hanya bagi yang sukarela.*','lgbt,gay,lesbi,normal',9,1,'2025-12-25 17:56:00','2025-12-25 17:56:00'),
(90,'conditions','Gagap (Stuttering)','Saya gagap sejak kecil kalau ngomong.','Gagap seringkali masalah kecemasan, bukan lidah. Otak berpikir lebih cepat dari mulut. Kami ajarkan teknik relaksasi pita suara dan \'Slow Talk\'. Kami cari trauma masa kecil (mungkin pernah ditertawakan/dibentak) dan sembuhkan. Saat kepercayaan diri tumbuh, bicara menjadi jauh lebih lancar.','gagap,bicara,bata,lidah',8,1,'2025-12-25 17:56:01','2025-12-25 17:56:01'),
(91,'conditions','Tinnitus (Telinga Berdenging)','Telinga berdenging terus kata dokter karena stres.','Tinnitus psikosomatis bisa dikelola. Kami gunakan teknik \'Dial Control\'. Dalam imajinasi, Anda memutar tombol volume dengingan itu menjadi kecil. Atau teknik \'Reframing\', mengubah suara denging menjadi suara jangkrik malam yang menenangkan, sehingga otak mengabaikannya (habituasi) dan Anda bisa tidur nyenyak.','telinga,denging,bunyi,stres',7,1,'2025-12-25 17:56:01','2025-12-25 17:56:01'),
(92,'process','Rekaman Audio','Bolehkah saya rekam sesinya?','Demi privasi dan efektivitas, rekaman video/suara full sesi oleh klien tidak disarankan karena bisa mengganggu fokus Anda (mikirin rekaman). TAPI, terapis kami AKAN membuatkan rekaman audio khusus (Anchor/Sugesti) di akhir sesi yang memang didesain untuk Anda bawa pulang dan dengarkan setiap hari.','rekam,audio,bawa,pulang',7,1,'2025-12-25 17:56:01','2025-12-25 17:56:01'),
(93,'process','Jumlah Sesi','Berapa sesi sampai sembuh total?','Tiap orang beda (unik). Kasus ringan (fobia simpel) bisa 1-2 sesi. Kasus kompleks (depresi, trauma masa kecil) rata-rata 4-8 sesi. Kami tidak pernah menahan klien lama-lama. Prinsip kami: \'Secepat mungkin, seefektif mungkin\'. Kemajuan biasanya sudah terasa signifikan sejak sesi pertama.','berapa,kali,sesi,lama',9,1,'2025-12-25 17:56:01','2025-12-25 17:56:01'),
(94,'process','Pendamping','Boleh ditemani masuk ruangan?','Untuk klien dewasa, sesi terapi dilakukan \'One-on-One\' agar privasi total dan klien bisa jujur tanpa sungkan. Pendamping menunggu di ruang tunggu. KECUALI untuk anak-anak, orang tua boleh mendampingi di awal (induksi), lalu menunggu di luar saat terapi inti, atau sesuai kebijakan terapis demi hasil terbaik.','teman,antar,masuk,ruang',7,1,'2025-12-25 17:56:01','2025-12-25 17:56:01'),
(95,'policies','Jadwal Weekend','Buka hari Sabtu/Minggu? Saya kerja.','Ya, Albashiro buka setiap hari termasuk Sabtu dan Minggu untuk memfasilitasi karyawan. Namun, slot weekend adalah yang paling cepat penuh (best seller). Kami sarankan booking minimal 1-2 minggu sebelumnya untuk jadwal weekend.','sabtu,minggu,libur,buka',8,1,'2025-12-25 17:56:02','2025-12-25 17:56:02'),
(96,'policies','Home Visit','Bisa panggil terapis ke rumah?','Kami menyediakan layanan Home Visit untuk kasus khusus (misal: stroke, agoraphobia parah, atau privasi VIP). Ada biaya tambahan untuk transport dan waktu perjalanan (charge per jam). Lingkungan rumah harus kondusif (tenang, tidak berisik, ada kursi nyaman) agar terapi efektif.','rumah,panggil,datang,visit',7,1,'2025-12-25 17:56:02','2025-12-25 17:56:02'),
(97,'faq_general','Skeptis','Saya orangnya logis dan susah percaya, bisa dihipnotis?','Justru orang cerdas dan logis paling mudah dihipnotis! Karena hipnosis butuh fokus. Orang yang \'susah\' adalah yang punya gangguan fokus atau takut berlebihan. Di Albashiro, kami jelaskan mekanisme ilmiahnya dulu sampai logika Anda menerima (Critical Factor terbuka), baru kita mulai terapi. Jadi gak perlu \'percaya buta\', cukup ikuti instruksi.','logis,susah,kritis,percaya',8,1,'2025-12-25 17:56:02','2025-12-25 17:56:02'),
(98,'faq_general','Tidur Saat Sesi','Kalau saya ketiduran pas terapi gimana?','Gak masalah. Bawah sadar tetap mendengar (pendengaran adalah indra terakhir yang tidur). Terapis kami terlatih membedakan \'trance dalam\' dan \'tidur pulas\'. Jika Anda tidur pulas (mengorok), kami akan bangunkan sedikit atau menggunakan teknik \'Sleep Hypnosis\'. Sesi tetap efektif.','tidur,ngorok,dengar,bablas',7,1,'2025-12-25 17:56:02','2025-12-25 17:56:02'),
(99,'conditions','Nervous Mengemudi','Baru bisa nyetir tapi takut bawa mobil ke jalan raya.','Driving Anxiety wajar bagi pemula. Kami bantu percepat adaptasi mental. Kami visualisasikan Anda menyetir dengan tenang, refleks bagus, dan waspada. Kami hilangkan bayangan kecelakaan yang menghantui. Anda akan merasa menyatu dengan mobil dan jalan raya, bukan melawannya.','nyetir,mobil,takut,jalan',7,1,'2025-12-25 17:56:02','2025-12-25 17:56:02'),
(100,'conditions','Takut Hamil (Tokophobia)','Nikah lama tapi nunda hamil karena takut melahirkan.','Tokophobia bisa diatasi. Kami bongkar \'cerita horor\' melahirkan yang pernah Anda dengar/tonton. Kami ganti dengan pemahaman bahwa tubuh wanita didesain sempurna untuk melahirkan. Kami tanamkan anchor relaksasi rahim. Banyak klien kami akhirnya hamil dan melahirkan dengan nyaman (Gentle Birth) setelah terapi.','hamil,lahir,sakit,takut',8,1,'2025-12-25 17:56:03','2025-12-25 17:56:03'),
(101,'conditions','Homesick','Anak mau mondok tapi nangis minta pulang terus (Homesick).','Persiapan mental santri baru. Kami bantu anak membangun kemandirian dan tujuan mulia menuntut ilmu (Big Why). Rasa rindu pada orang tua divalidasi, tapi diubah energinya menjadi doa dan semangat belajar. Kami beri teknik \'Telepati Hati\' (kirim doa) saat rindu, agar anak merasa ortu selalu dekat di hati.','pondok,pulang,rindu,nangis',8,1,'2025-12-25 17:56:03','2025-12-25 17:56:03'),
(102,'conditions','Takut Menelan (Phagophobia)','Pernah keselek, sekarang jadi takut nelan nasi.','Trauma tersedak bisa bikin berat badan turun drastis. Kami gunakan regresi ke momen tersedak itu, lalu \'menetralkan\' rasa paniknya. Kami ajarkan relaksasi otot tenggorokan. Dimulai dari membayangkan menelan air, bubur, hingga nasi, sampai bawah sadar yakin bahwa menelan itu refleks alami yang aman.','makan,telan,keselek,takut',8,1,'2025-12-25 17:56:03','2025-12-25 17:56:03'),
(103,'conditions','Takut Dokter (White Coat Syndrome)','Tensi selalu tinggi kalau diperiksa dokter, padahal di rumah normal.','White Coat Hypertension terjadi karena cemas lihat jas putih/RS. Kami latih Anda untuk rileks instan saat mencium bau RS atau melihat dokter. Visualisasikan dokter sebagai \'teman yang membantu\', bukan \'hakim yang memvonis\'. Hasil cek kesehatan jadi lebih akurat.','dokter,tensi,darah,rs',7,1,'2025-12-25 17:56:03','2025-12-25 17:56:03'),
(104,'conditions','Sindrom Pensiun (Post Power)','Stres setelah pensiun, merasa gak berguna.','Post Power Syndrome adalah krisis identitas. Kami bantu Anda menemukan \'Tujuan Baru\' pasca kerja. Menggeser nilai diri dari \'Apa Jabatan Saya\' menjadi \'Siapa Saya & Apa Manfaat Saya\'. Mempersiapkan masa tua yang bahagia, produktif, dan dekat dengan Allah.','pensiun,tua,kerja,stres',8,1,'2025-12-25 17:56:03','2025-12-25 17:56:03'),
(105,'islamic','Gangguan Tidur (Tindihan)','Sering \'tindihan\' (Sleep Paralysis), takut tidur.','Secara medis ini kelumpuhan tidur (otak bangun, badan belum). Secara budaya sering dikaitkan makhluk halus. Kami edukasi mekanismenya agar tidak takut. Kami ajarkan teknik: \'Jangan lawan, rileks saja, gerakkan kelingking kaki\'. Ditambah doa perlindungan sebelum tidur, frekuensi tindihan biasanya berkurang drastis karena stres (pemicu utamanya) hilang.','tindihan,paralysis,setan,bangun',8,1,'2025-12-25 17:56:04','2025-12-25 17:56:04'),
(106,'conditions','Takut Kematian (Thanatophobia)','Cemas berlebih mikirin mati atau kiamat.','Thanatophobia sering dialami orang yang merasa \'belum siap\'. Pendekatan kami spiritual: Memperbaiki hubungan dengan Allah. Mengubah persepsi \'Mati = Akhir Menakutkan\' menjadi \'Mati = Gerbang Pertemuan dengan Sang Kekasih\'. Saat iman dan amal disiapkan, rasa takut berubah menjadi rasa harap (Raja\') dan tenang.','mati,kiamat,takut,ajal',9,1,'2025-12-25 17:56:04','2025-12-25 17:56:04'),
(107,'process','Jarak Sesi','Berapa jarak ideal antar sesi?','Idealnya 1 minggu sekali. Ini memberi waktu bagi pikiran bawah sadar untuk memproses sugesti (inkubasi) dan Anda mempraktekkan PR di dunia nyata. Kalau terlalu dekat (tiap hari) kurang efektif, kalau terlalu jauh (sebulan sekali) momentumnya hilang.','jarak,waktu,minggu,jadwal',7,1,'2025-12-25 17:56:04','2025-12-25 17:56:04'),
(108,'pricing','Asuransi','Bisa pakai BPJS atau asuransi kantor?','Saat ini hipnoterapi belum dicover BPJS Kesehatan. Namun, beberapa asuransi swasta dengan plafon \'Reimburse Mental Health/Psikolog\' mungkin bisa, tergantung polis Anda (kami bisa bantu buatkan invoice resmi). Silakan cek ke agen asuransi Anda dulu.','bpjs,asuransi,klaim,bayar',8,1,'2025-12-25 17:56:04','2025-12-25 17:56:04'),
(109,'faq_general','Tidak Bisa Visualisasi','Saya gak bisa bayangin gambar (Aphantasia), bisa terapi?','Bisa! Hipnoterapi tidak harus visual. Kalau gak bisa \'melihat\', Anda bisa \'merasakan\' (kinestetik) atau \'berpikir\' (auditori). Contoh: Terapis bilang \'Bayangkan jeruk\', kalau gak muncul gambar jeruk, cukup pikirkan \'Saya sedang pegang jeruk\'. Efeknya ke otak sama saja. Terapis kami fleksibel menyesuaikan modalitas Anda.','bayang,gambar,visual,susah',7,1,'2025-12-25 17:56:04','2025-12-25 17:56:04'),
(110,'faq_general','Anak Autis','Bisa terapi untuk anak Autis/ABK?','Hipnoterapi TIDAK bisa menyembuhkan Autisme (karena itu kondisi neurobiologis). TAPI, kami bisa membantu mengelola *gejala penyertanya*: mengurangi tantrum, melatih fokus, atau mengurangi kecemasan sosial pada anak ABK yang High Functioning. Perlu konsultasi awal untuk melihat potensi keberhasilannya.','autis,abk,special,tantrum',7,1,'2025-12-25 17:56:05','2025-12-25 17:56:05'),
(111,'conditions','Takut Anjing','Sangat takut anjing, lihat dari jauh aja keringat dingin.','Fobia anjing (Cynophobia) umum terjadi. Desensitisasi dilakukan dengan visualisasi. Anda akan dibimbing untuk merasa aman melihat gambar anjing lucu, lalu anjing di seberang jalan, dst. Kami netralkan memori pernah dikejar/digigit anjing di masa lalu.','anjing,guguk,takut,gigit',8,1,'2025-12-25 17:56:05','2025-12-25 17:56:05'),
(112,'conditions','Takut Kecoak (Katsaridaphobia)','Jijik dan takut setengah mati sama kecoak.','Kecoak sering diasosiasikan dengan kotoran. Kami ubah respon \'Fight or Flight\' (lari/teriak) menjadi respon \'Calm & Handle\' (tenang & atasi/menghindar santai). Sugesti visual bisa mengubah kecoak terlihat seperti mainan plastik yang tidak berbahaya di mata pikiran Anda.','kecoak,serangga,jijik,terbang',7,1,'2025-12-25 17:56:05','2025-12-25 17:56:05'),
(113,'islamic','Marah pada Allah','Saya kecewa sama takdir Allah, kenapa saya diuji berat?','Ini fase wajar saat duka mendalam. Kami sediakan ruang aman (holding space) untuk Anda menumpahkan kekecewaan tanpa dihakimi \'kurang iman\'. Setelah emosi validasi keluar, baru kami bimbing perlahan melihat Hikmah di balik ujian. Rekonsiliasi hubungan dengan Allah adalah puncak kesembuhan jiwa.','marah,takdir,allah,kecewa',9,1,'2025-12-25 17:56:05','2025-12-25 17:56:05'),
(114,'conditions','Hypno-Beauty','Bisa bikin cantik/awet muda (Inner Beauty)?','Stres bikin tua cepat. Hipnoterapi melepas tegangan otot wajah (botox alami) dan memancarkan aura ketenangan. Saat Anda merasa damai dan percaya diri (Self-Love), orang lain akan melihat Anda lebih menarik dan \'bercahaya\'. Cantik itu dimulai dari pikiran (Inner Beauty).','cantik,muda,aura,wajah',7,1,'2025-12-25 17:56:06','2025-12-25 17:56:06'),
(115,'category','topic','question','answer','keywords',0,1,'2025-12-25 17:56:06','2025-12-25 17:56:06'),
(116,'relationships','Selingkuh: Trauma Pengkhianatan','Suami ketahuan selingkuh, hati saya hancur tapi demi anak bertahan.','Bertahan dengan luka itu menyiksa. Terapi kami fokus pada \'Trauma Release\' untuk istri. Kami bantu Anda membuang rasa sakit, marah, dan perasaan \'tidak berharga\' akibat pengkhianatan. Tujuannya bukan membenarkan perilaku suami, tapi agar Anda bisa mengambil keputusan (bertahan atau pisah) dengan hati tenang dan logis, bukan karena emosi sesaat.','selingkuh,khianat,suami,sakit hati',10,1,'2025-12-25 17:56:06','2025-12-25 17:56:06'),
(117,'relationships','Trust Issue','Susah percaya pasangan karena masa lalu.','Trust issue adalah mekanisme pertahanan diri yang \'kebablasan\'. Kami ajak Anda berdamai dengan masa lalu (mantan atau orang tua). Kami program ulang bahwa \'Pasangan Sekarang\' berbeda dengan \'Masa Lalu\'. Kami bangun rasa aman dari dalam diri, sehingga Anda tidak posesif berlebihan yang justru merusak hubungan.','percaya,curiga,cemburu,posesif',9,1,'2025-12-25 17:56:06','2025-12-25 17:56:06'),
(118,'relationships','Komunikasi Pasutri','Kami sering ribut masalah sepele, gak nyambung.','Masalah komunikasi seringkali karena beda \'Bahasa Kasih\' dan ego. Hipnoterapi Pasutri (Couple Session) membantu menyelaraskan frekuensi. Kami hilangkan blok mental yang membuat Anda defensif saat dikritik. Kami tanamkan anchor \'Kasih Sayang\' agar saat debat memanas, otomatis salah satu bisa meredakan suasana dengan tenang.','ribut,cekcok,komunikasi,suami istri',8,1,'2025-12-25 17:56:06','2025-12-25 17:56:06'),
(119,'relationships','Mertua Toxic','Stres menghadapi mertua yang selalu ikut campur.','Konflik mertua-menantu sangat menguras energi. Kami bantu Anda membangun \'Shield Mental\'. Ucapan pedas mertua disugestikan hanya sebagai \'suara angin\' yang tidak menembus hati. Kami juga bantu Anda bersikap asertif (tegas tapi santun) tanpa rasa bersalah, menjaga batas privasi rumah tangga Anda.','mertua,ipar,konflik,keluarga',8,1,'2025-12-25 17:56:07','2025-12-25 17:56:07'),
(120,'relationships','Sexless Marriage','Sudah lama tidak berhubungan intim, rasanya hambar.','Hilangnya gairah seringkali bukan masalah fisik, tapi tumpukan kekecewaan kecil yang tidak selesai. Kami lakukan \'Emotional Detox\' untuk pasutri. Membuang sampah emosi lama agar rasa cinta dan ketertarikan fisik bisa tumbuh kembali seperti awal menikah.','seks,hambar,dingin,bosan',8,1,'2025-12-25 17:56:07','2025-12-25 17:56:07'),
(121,'relationships','Sandwich Generation','Stres biayain orang tua dan anak sekaligus, capek banget.','Beban Sandwich Generation rentan burnout. Kami bantu Anda mengelola stres dan rasa bersalah (Guilt Trip). Kami perkuat \'Wadah Mental\' Anda agar kapasitas sabar meningkat. Penting juga memprogram mindset \'Rezeki Berkah\' agar Anda tidak merasa membiayai orang tua sebagai beban, tapi sebagai pintu rezeki.','sandwich,beban,biaya,orang tua',9,1,'2025-12-25 17:56:07','2025-12-25 17:56:07'),
(122,'relationships','Jodoh (Mental Block)','Umur sudah matang tapi susah dapat jodoh, selalu gagal.','Seringkali ada blok bawah sadar seperti \'Nikah = Sengsara\' (mungkin lihat ortu dulu sering berantem). Kami hancurkan blok ini. Kami pasang magnet \'Love Attraction\'. Anda akan memancarkan aura siap menikah yang positif, bukan aura \'desperate/ngarep\' yang justru menjauhkan jodoh berkualitas.','jodoh,nikah,single,jomblo',9,1,'2025-12-25 17:56:07','2025-12-25 17:56:07'),
(123,'career','Money Block: Susah Kaya','Kerja keras banting tulang tapi uang gak kumpul-kumpul.','Mungkin Anda punya \'Money Block\' seperti keyakinan \'Uang adalah akar kejahatan\' atau \'Orang kaya itu pelit\'. Bawah sadar Anda akan menolak kekayaan demi menjaga Anda tetap \'baik\'. Kami re-install mindset: \'Uang adalah alat ibadah\' dan \'Saya pantas kaya & dermawan\'. Rezeki akan mengalir lebih lancar saat blok mental dibuka.','kaya,uang,rezeki,miskin',9,1,'2025-12-25 17:56:07','2025-12-25 17:56:07'),
(124,'career','Interview Kerja','Selalu gagal pas wawancara kerja karena grogi.','Interview adalah ajang jual diri. Kami gunakan teknik \'Mirroring Confidence\'. Anda dilatih masuk ke ruangan dengan postur dan vibrasi pemenang. Jawaban-jawaban cerdas akan keluar otomatis (unconscious competence) tanpa tersendat. Kami hilangkan rasa terintimidasi oleh HRD/User.','kerja,interview,wawancara,gugup',8,1,'2025-12-25 17:56:08','2025-12-25 17:56:08'),
(125,'career','Burnout Pekerjaan','Rasanya muak banget sama kantor, mau resign tapi butuh gaji.','Burnout tanda jiwa lelah, bukan cuma badan. Sesi relaksasi mendalam (Deep Rest) setara tidur berkualitas berjam-jam. Kami bantu Anda menemukan kembali \'Makna\' dalam pekerjaan atau keberanian menyusun rencana exit strategy yang matang tanpa rasa takut berlebihan.','burnout,lelah,kerja,stres',8,1,'2025-12-25 17:56:08','2025-12-25 17:56:08'),
(126,'career','Bossy/Leadership','Saya baru jadi manajer tapi sungkan sama bawahan.','Leadership butuh ketegasan. Kami install program \'Charismatic Leader\'. Anda akan merasa nyaman memberi perintah dan teguran secara objektif. Rasa \'Gak Enakan\' (People Pleaser) dikurangi proporsinya, diganti dengan profesionalisme yang disegani, bukan ditakuti.','bos,pemimpin,manajer,sungkan',8,1,'2025-12-25 17:56:08','2025-12-25 17:56:08'),
(127,'career','Korban PHK','Depresi habis di-PHK, merasa tidak berguna.','PHK bisa meruntuhkan harga diri pria/wanita karir. Kami bantu proses penerimaan (Acceptance). Kami ubah mindset \'Korban\' menjadi \'Pemenang yang sedang istirahat\'. Kami bangkitkan motivasi dan kreativitas untuk melihat peluang usaha atau karir baru. Rezeki Allah tidak putus karena putusnya hubungan kerja.','phk,pecat,kerja,nganggur',9,1,'2025-12-25 17:56:08','2025-12-25 17:56:08'),
(128,'career','Bisnis Bangkrut','Trauma buka usaha lagi karena pernah bangkrut total.','Trauma kegagalan bisnis mirip trauma kecelakaan. Kami netralkan rasa sakit kehilangan aset itu. Kami ambil hikmah/pembelajarannya, buang emosi negatifnya. Anda akan siap melangkah lagi dengan kalkulasi yang lebih matang, tanpa bayang-bayang ketakutan masa lalu.','bangkrut,rugi,usaha,trauma',8,1,'2025-12-25 17:56:09','2025-12-25 17:56:09'),
(129,'addiction','Judi Online (Judol)','Saya hancur gara-gara slot/judol, utang numpuk, mau berhenti.','Kecanduan judi merusak sistem reward otak. Kami harus \'Merusak\' kenikmatan judi di otak Anda. Sugesti: \'Judi = Miskin/Hina\'. Kami putus ilusi \'Bisa menang lagi/Balik modal\'. Terapi juga fokus menenangkan kecemasan akibat teror utang/pinjol agar Anda bisa berpikir jernih menyusun rencana pelunasan, bukan lari ke judi lagi.','judi,slot,gacor,utang',10,1,'2025-12-25 17:56:09','2025-12-25 17:56:09'),
(130,'addiction','Pornografi (PMO)','Kecanduan bokep/PMO, otak rasanya lemot & malas.','Pornografi merusak Prefrontal Cortex (pusat logika). Hipnoterapi membantu \'Reboot Otak\'. Kami lakukan Aversion Therapy (membuat pornografi terlihat menjijikkan/membosankan). Kami alihkan energi seksual yang meluap menjadi energi kreatif atau olahraga. Self-control dikuatkan untuk menundukkan pandangan.','porno,bokep,pmo,candu',9,1,'2025-12-25 17:56:09','2025-12-25 17:56:09'),
(131,'addiction','Alkohol/Miras','Susah lepas dari alkohol kalau lagi stres/nongkrong.','Alkohol sering jadi kruk emosi. Kami cari akar masalahnya: apa yang ingin Anda lupakan saat mabuk? Masalah itu yang kami bereskan. Kami tanamkan sugesti bahwa air mineral/jus jauh lebih nikmat dan menyegarkan. Rasa percaya diri dibangun tanpa perlu bantuan alkohol.','mabuk,alkohol,miras,minum',8,1,'2025-12-25 17:56:09','2025-12-25 17:56:09'),
(132,'addiction','Belanja Online (Paylater)','Gaji habis buat bayar Paylater, gak bisa ngerem check-out.','Paylater memancing impulsif. Kami tanamkan \'Pause Button\' di pikiran. Saat mau klik bayar, muncul pertanyaan: \'Butuh atau Ingin?\'. Kami bantu Anda merasakan nikmatnya menabung dan melihat saldo bertambah, menggantikan nikmatnya menerima paket belanjaan.','belanja,boros,paylater,utang',8,1,'2025-12-25 17:56:09','2025-12-25 17:56:09'),
(133,'trauma','KDRT (Kekerasan)','Saya korban KDRT, trauma sama laki-laki/pasangan.','Luka KDRT sangat dalam. Prioritas kami adalah mengembalikan rasa \'AMAN\' pada diri sendiri. Kami bantu Anda melepaskan identitas \'Korban\' menjadi \'Survivor\' (Penyintas). Ketakutan pada lawan jenis diredakan perlahan agar Anda bisa berinteraksi sosial lagi tanpa gemetar/cemas.','kdrt,pukul,kasar,suami',10,1,'2025-12-25 17:56:10','2025-12-25 17:56:10'),
(134,'trauma','Pelecehan Seksual','Punya masa lalu kelam dilecehkan, merasa kotor/hina.','Ini area sensitif yang kami tangani dengan sangat hati-hati. Teknik \'Washing Machine of the Mind\' membantu membersihkan perasaan kotor/najis. Kami tegaskan bahwa \'Itu bukan salah Anda, itu bukan aib Anda\'. Kehormatan Anda kembali utuh. Anda berhak bahagia dan dicintai suci.','leceh,perkosa,kotor,aib',10,1,'2025-12-25 17:56:10','2025-12-25 17:56:10'),
(135,'trauma','Kecelakaan','Takut nyetir lagi habis tabrakan parah.','PTSD pasca kecelakaan (flashback suara benturan/darah). Kami gunakan teknik \'Cinema Technique\'. Anda menonton kejadian itu di layar bioskop mental hitam-putih dari jarak jauh, sampai rasanya netral. Setelah emosi takut hilang, baru kita simulasi nyetir lagi dengan tenang.','tabrak,celaka,mobil,takut',8,1,'2025-12-25 17:56:10','2025-12-25 17:56:10'),
(136,'trauma','Kehilangan Orang Dicinta (Grief)','Istri meninggal, saya tidak punya semangat hidup lagi.','Grief (duka) ada tahapannya. Hipnoterapi bukan untuk melupakan almarhum, tapi mengikhlaskan kepergiannya. Kami bantu Anda melewati fase denial dan anger lebih cepat. Kami fasilitasi \'Dialog Perpisahan\' yang indah di alam bawah sadar untuk melepas rindu, sehingga Anda bisa melanjutkan hidup dengan damai.','meninggal,duka,sedih,istri',9,1,'2025-12-25 17:56:10','2025-12-25 17:56:10'),
(137,'students','Bullying di Sekolah','Anak saya takut ke sekolah karena diejek teman.','Kami bekali anak dengan \'Mental Shield\'. Ejekan teman dibayangkan seperti bola pingpong yang memantul tidak kena badan. Kami naikkan level percaya diri (Self-Esteem) anak agar dia berani berkata \'STOP\' atau mengabaikan dengan elegan. Postur tubuh yang tegap dilatih untuk mengurangi potensi dibully.','bully,sekolah,ejek,takut',9,1,'2025-12-25 17:56:10','2025-12-25 17:56:10'),
(138,'students','Kecanduan Anime/Komik','Anak hidup di dunia fantasi terus, susah sosialisasi.','Escapism (pelarian). Kami tidak melarang hobi, tapi menyeimbangkan. Kami buat kesepakatan dengan bagian diri anak (Parts Therapy): \'Waktu fantasi ada jamnya, waktu realita ada jamnya\'. Kami cari potensi dari hobi itu (misal: belajar bahasa Jepang/Gambar) agar jadi produktif, bukan konsumtif.','anime,wibu,kartun,nonton',7,1,'2025-12-25 17:56:11','2025-12-25 17:56:11'),
(139,'students','Takut Guru Killer','Nilai jelek cuma di pelajaran guru yang galak.','Ketakutan memblokir akses ke memori pelajaran. Kami lakukan \'Reframing\' terhadap sosok guru itu. Mungkin dibayangkan guru itu pakai baju badut lucu di pikiran anak, supaya rasa takut hilang. Saat rileks, anak bisa mencerna pelajaran dari guru tersebut dengan baik.','guru,galak,takut,nilai',7,1,'2025-12-25 17:56:11','2025-12-25 17:56:11'),
(140,'students','Salah Jurusan','Mahasiswa merasa salah jurusan, stres mau DO.','Dilema lanjut atau pindah. Kami bantu \'Clarity\' (kejernihan) berpikir. Mengakses kebijaksanaan batin untuk melihat potensi karir ke depan. Apakah benar salah jurusan, atau hanya kaget dengan beban tugasnya? Keputusan diambil dengan mantap, meminimalkan penyesalan di masa depan.','kuliah,jurusan,salah,stres',8,1,'2025-12-25 17:56:11','2025-12-25 17:56:11'),
(141,'health','Vape/Rokok Elektrik','Katanya vape aman, tapi saya ngerasa candu banget.','Vape tetap mengandung nikotin dan aditif candu. Terapi sama dengan rokok konvensional. Kami hilangkan sugesti \'Vape itu Keren/Gaul\'. Kami munculkan kesadaran akan kesehatan paru-paru jangka panjang. Oral fixation (kebiasaan mulut) dialihkan ke minum air atau permen karet xylitol.','vape,pod,rokok,asap',8,1,'2025-12-25 17:56:11','2025-12-25 17:56:11'),
(142,'health','Biting/Ngemil Malam','Gak bisa tidur kalau belum ngemil, berat badan naik terus.','Night Eating Syndrome. Biasanya karena emosi sepi di malam hari. Kami ganti asosiasi \'Kenyang = Nyaman Tidur\' menjadi \'Perut Ringan = Tidur Pulas\'. Sugesti dipasang agar jam 8 malam \'dapur tutup\' secara mental. Air putih jadi satu-satunya opsi yang diinginkan.','ngemil,malam,gendut,makan',8,1,'2025-12-25 17:56:11','2025-12-25 17:56:11'),
(143,'health','Takut Obat (Pill Phobia)','Gak bisa nelan obat pil, selalu dimuntahkan.','Refleks muntah (Gag Reflex) yang terlalu sensitif. Kami ajarkan relaksasi tenggorokan. Teknik visualisasi: membayangkan tenggorokan seluas pipa besar yang licin, sehingga pil sekecil apapun lewat dengan mudah. Latihan mental dilakukan sampai refleks muntah hilang.','obat,pil,telan,muntah',7,1,'2025-12-25 17:56:12','2025-12-25 17:56:12'),
(144,'islamic','Poligami (Sisi Istri)','Suami mau poligami/sudah poligami, saya tidak siap mental.','Isu sangat kompleks. Kami tidak masuk ranah hukum fikih, tapi mengelola *emosi* istri. Rasa cemburu, tidak adil, dan insecure divalidasi dan diredakan. Tujuannya agar istri bisa berpikir jernih & spiritual: Apakah sanggup menerima? Atau memilih jalan lain? Keputusan diambil dalam kondisi Qolbun Salim (hati tenang), bukan amarah.','poligami,madu,istri,cemburu',9,1,'2025-12-25 17:56:12','2025-12-25 17:56:12'),
(145,'islamic','Istikharah Clarity','Sudah sholat istikharah tapi masih bingung jawabannya.','Istikharah butuh wadah hati yang bersih dari \'Kecenderungan Awal\'. Hipnoterapi membantu menetralkan ego dan keinginan pribadi (Zero State). Dalam kondisi netral ini, intuisi/petunjuk Allah (lewat mimpi atau kemantapan hati) biasanya lebih mudah terbaca dan dirasakan.','istikharah,bingung,pilih,jodoh',8,1,'2025-12-25 17:56:12','2025-12-25 17:56:12'),
(146,'islamic','Husnuzon Therapy','Susah berbaik sangka sama Allah dan orang lain.','Pikiran negatif (Suudzon) adalah racun. Kami latih otot mental \'Positive Reframing\'. Setiap kejadian buruk, otomatis pikiran mencari 1 sisi baik/hikmahnya. Ini adalah aplikasi psikologis dari sifat Husnuzon. Hidup jadi lebih ringan dan bahagia.','sangka,buruk,curiga,allah',8,1,'2025-12-25 17:56:12','2025-12-25 17:56:12'),
(147,'misc','Hypno-Teaching (Guru)','Saya guru, mau belajar cara mengajar yang hipnotik.','Kami ajarkan prinsip hipnosis untuk mengajar: (1) Building Rapport (koneksi), (2) Pola bahasa persuasif, (3) Menggunakan intonasi suara, (4) Storytelling. Murid akan lebih antusias, penurut, dan materi masuk ke long-term memory mereka tanpa paksaan.','guru,mengajar,kelas,murid',8,1,'2025-12-25 17:56:12','2025-12-25 17:56:12'),
(148,'misc','Sports Performance','Saya atlet, sering drop mental pas tanding.','Mental juara dibentuk di pikiran. Kami gunakan teknik visualisasi \'Perfect Game\'. Latihan mental mengaktifkan jalur saraf yang sama dengan latihan fisik. Kami juga pasang anchor \'Power Mode\' yang diaktifkan sesaat sebelum bertanding untuk membanjiri tubuh dengan fokus dan adrenalin terkontrol.','atlet,lomba,menang,juara',8,1,'2025-12-25 17:56:13','2025-12-25 17:56:13'),
(149,'misc','Lupa Naruh Barang','Sering lupa naruh kunci/dompet, pikun dini?','Seringkali bukan pikun, tapi \'Absent Minded\' (tidak hadir saat meletakkan). Kami latih \'Mindfulness Action\'. Saat meletakkan barang, ucapkan dalam hati \'Saya taruh kunci di meja\'. Kesadaran sesaat ini membuat memori terkunci kuat. Kami juga kurangi multitasking yang memecah fokus otak.','lupa,kunci,pikun,ingat',7,1,'2025-12-25 17:56:13','2025-12-25 17:56:13'),
(150,'misc','Takut Hantu/Mistik','Takut banget di rumah sendirian, parno hantu.','Phasmophobia. Imajinasi liar yang tidak terkontrol. Kami latih Anda mengontrol \'Remote TV\' pikiran. Saat bayangan seram muncul, ganti channel ke bayangan lucu. Kami perkuat keyakinan tauhid: Derajat manusia (Khalifah) lebih tinggi dari jin/setan, jadi tidak perlu takut berlebihan.','hantu,setan,takut,sendiri',7,1,'2025-12-25 17:56:13','2025-12-25 17:56:13'),
(151,'relationships','Long Distance (LDR)','Capek LDR, bawaannya curigaan terus.','LDR butuh kepercayaan ekstra. Kami bantu kurangi \'Insecurity\' dan \'Overthinking\'. Saat tidak ada kabar, latih pikiran untuk berasumsi positif (sibuk/istirahat) bukan negatif (selingkuh). Kami ajarkan cara menikmati \'Me Time\' berkualitas sehingga kebahagiaan Anda tidak 100% bergantung pada chat pasangan.','ldr,jarak,jauh,curiga',8,1,'2025-12-25 17:56:13','2025-12-25 17:56:13'),
(152,'relationships','Toxic Relationship (Pacaran)','Pacar kasar & manipulatif tapi saya gak bisa putus (Bucin).','Ketergantungan emosional (Trauma Bonding). Anda merasa \'tidak bisa hidup tanpa dia\' padahal dia menyakiti. Kami bantu Anda melihat realita objektif. Kami bangun kembali Self-Love yang hancur. Saat Anda sadar betapa berharganya diri Anda, Anda akan otomatis ilfeel dan punya kekuatan untuk pergi (Walk Away).','toxic,pacar,kasar,putus',9,1,'2025-12-25 17:56:13','2025-12-25 17:56:13'),
(153,'conditions','Hypochondria (Cemas Penyakit)','Dikit-dikit Google gejala penyakit, takut kena kanker/sakit keras.','Health Anxiety. Google adalah musuh Anda. Kami stop kebiasaan \'Cyberchondria\' (diagnosa via internet). Kami ajak Anda berkomunikasi dengan tubuh. Rasa nyeri sedikit dimaknai sebagai \'sinyal tubuh butuh istirahat\', bukan \'tanda kematian\'. Kepercayaan pada sistem imun tubuh dikembalikan.','sakit,kanker,takut,google',8,1,'2025-12-25 17:56:14','2025-12-25 17:56:14'),
(154,'conditions','Takut Miskin (Poverty Mindset)','Tabungan ada, tapi pelit banget ke diri sendiri karena takut habis.','Scarcity Mindset (Mentalitas Kelangkaan). Hidup tidak nikmat. Kami ubah ke Abundance Mindset (Mentalitas Berkelimpahan). Meyakini bahwa rezeki Allah luas. Anda dilatih untuk bisa menikmati uang secara wajar (Self-Reward) tanpa rasa bersalah, karena itu bentuk syukur yang justru menarik rezeki lebih banyak.','miskin,pelit,uang,takut',8,1,'2025-12-25 17:56:14','2025-12-25 17:56:14'),
(155,'conditions','Gagap Teknologi (Gaptek)','Takut banget salah pencet kalau pakai komputer/HP.','Technophobia pada lansia/dewasa. Kami hilangkan rasa \'Intimidasi\' dari alat elektronik. Sugesti: \'Salah pencet bisa di-undo/kembali, tidak akan meledak\'. Kami bangun rasa penasaran anak-anak (playful) saat belajar teknologi baru, sehingga proses belajar jadi cepat.','gaptek,hp,komputer,takut',6,1,'2025-12-25 17:56:14','2025-12-25 17:56:14'),
(156,'conditions','Writer\'s Block','Penulis/Content Creator buntu ide, macet total.','Kreativitas macet karena kritik diri (Self-Critic) terlalu cerewet. Kami istirahatkan kritik diri itu. Kami akses \'Creative Source\' di gelombang Theta. Ide-ide liar dibiarkan mengalir dulu tanpa filter. Aliran ide akan kembali deras seperti keran air yang sumbatannya dibuka.','tulis,ide,macet,kreatif',7,1,'2025-12-25 17:56:14','2025-12-25 17:56:14'),
(157,'conditions','Takut Tua (Gerascophobia)','Stres lihat kerutan di wajah, takut jadi tua.','Kami reframe makna \'Tua\'. Tua bukan berarti jelek/lemah, tapi berarti \'Matang & Bijaksana\'. Kami bantu Anda menerima perubahan fisik dengan graceful (anggun). Fokus dialihkan ke kecantikan batin dan warisan kebaikan (legacy) yang akan ditinggalkan, bukan sekadar kulit kencang.','tua,keriput,jelek,takut',7,1,'2025-12-25 17:56:15','2025-12-25 17:56:15'),
(158,'islamic','Gangguan Jin Nasab','Katanya ada jin keturunan di badan saya, bisa hilang?','Di Albashiro, kami memutus \'Perjanjian Bawah Sadar\' dengan leluhur. Seringkali jin nasab bertahan karena *kita* merasa butuh perlindungan mereka. Kami kuatkan tauhid: Cukup Allah pelindungku. Saat Anda benar-benar tidak menginginkan mereka dan hanya bergantung pada Allah, ikatan energi itu putus dan mereka pergi.','jin,nasab,leluhur,saka',8,1,'2025-12-25 17:56:15','2025-12-25 17:56:15'),
(159,'islamic','Mimpi Basah Berlebih','Sering mimpi jorok/basah, merasa terganggu ibadahnya.','Jika berlebihan, bisa jadi obsesi pikiran atau gangguan. Kami lakukan \'Mind Purification\' sebelum tidur. Membaca doa, wudhu, dan meniatkan tidur untuk istirahat ibadah. Kami sugestikan agar alam mimpi dijaga oleh malaikat dari visualisasi yang mengundang syahwat.','mimpi,basah,jorok,tidur',7,1,'2025-12-25 17:56:15','2025-12-25 17:56:15'),
(160,'islamic','Niat Istiqomah','Semangat hijrah naik turun, takut balik maksiat lagi.','Istiqomah itu berat. Kami pasang \'Spiritual Anchor\'. Misal: setiap dengar adzan, semangat hijrah di-recharge. Kami bantu Anda menemukan \'Strong Why\' (Alasan Kuat) hijrah yang personal, bukan karena ikut-ikutan teman, sehingga pondasinya kokoh meski lingkungan berubah.','hijrah,istiqomah,maksiat,iman',8,1,'2025-12-25 17:56:15','2025-12-25 17:56:15'),
(161,'pricing','Diskon Pelajar','Saya mahasiswa, ada harga khusus?','Kami sangat peduli kesehatan mental pemuda. Ada \'Student Rate\' dengan diskon khusus (biasanya 15-20%) dengan menunjukkan Kartu Tanda Mahasiswa (KTM) aktif. Berlaku untuk sesi di hari kerja (Weekdays) jam 09.00-15.00. Silakan tanya admin untuk slot yang tersedia.','mahasiswa,diskon,murah,pelajar',8,1,'2025-12-25 17:56:15','2025-12-25 17:56:15'),
(162,'pricing','Couple Package','Paket terapi bareng suami istri berapa?','Paket \'Harmoni Pasutri\' lebih hemat daripada bayar per orang. Sesi mencakup konseling bersama, lalu terapi terpisah (jika perlu), dan penyatuan visi. Investasi ini jauh lebih murah dibandingkan biaya perceraian atau ketidakharmonisan seumur hidup.','pasutri,paket,berdua,couple',8,1,'2025-12-25 17:56:16','2025-12-25 17:56:16'),
(163,'policies','Anak Tanpa Ortu','Anak saya di luar kota, bisa terapi sendiri tanpa saya?','Untuk anak di bawah 17 tahun (belum dewasa hukum), kami butuh *Informed Consent* (izin tertulis) dari orang tua via WA/Email. Sesi bisa dilakukan online atau anak datang sendiri, TAPI kami akan tetap melaporkan progres umum ke orang tua (tanpa melanggar detail rahasia curhat anak).','izin,anak,sendiri,ortu',7,1,'2025-12-25 17:56:16','2025-12-25 17:56:16'),
(164,'policies','Garansi Uang Kembali','Ada garansi uang kembali kalau gagal?','Sama seperti dokter bedah tidak menggaransi operasi pasti sukses 100%, kami juga tidak. Pikiran manusia kompleks. Namun kami garansi **Kepuasan Layanan**: Jika di 30 menit pertama Anda merasa tidak cocok dengan terapis kami, sesi boleh dihentikan dan biaya dikembalikan (potong admin). Lewat dari itu, biaya full.','garansi,uang,kembali,refund',8,1,'2025-12-25 17:56:16','2025-12-25 17:56:16'),
(165,'faq_general','Hipnotis Kejahatan','Takut nanti saya dihipnotis buat nipu orang (gendam).','Hipnoterapi klinis SANGAT BEDA dengan gendam jalanan. Gendam pakai trik kejut (shock) dan mistik. Hipnoterapi pakai persetujuan (consent) dan relaksasi ilmiah. Anda tidak bisa disugesti melakukan hal yang bertentangan dengan moral Anda. Justru hipnoterapi membuat Anda lebih waspada dan sadar, susah kena gendam.','gendam,tipu,jahat,kejahatan',9,1,'2025-12-25 17:56:16','2025-12-25 17:56:16'),
(166,'faq_general','Bisa Lupa Mantan?','Bisa gak bikin saya lupa ingatan tentang mantan 100%?','Kami tidak bisa menghapus memori (amnesia permanen) karena itu bagian sejarah hidup Anda. TAPI, kami bisa \'Menghapus Rasa Sakitnya\'. Anda tetap ingat nama mantan dan wajahnya, tapi rasanya netral, biasa saja, seperti ingat teman SD yang sudah lama gak ketemu. Gak ada lagi nyesek atau nangis.','lupa,mantan,ingatan,hapus',9,1,'2025-12-25 17:56:16','2025-12-25 17:56:16'),
(167,'faq_general','Buka Aura','Apa di sini melayani buka aura?','Kami menyebutnya \'Inner Glow Activation\'. Bukan pakai susuk/mistik. Kami bersihkan sampah emosi (dendam/iri/sedih) yang membuat wajah kusam. Kami bangkitkan rasa percaya diri dan senyum tulus dari hati. Secara alami, wajah Anda akan terlihat lebih cerah, menarik, dan \'ber-aura\' positif.','aura,cantik,susuk,mistik',8,1,'2025-12-25 17:56:17','2025-12-25 17:56:17'),
(168,'category','topic','question','answer','keywords',0,1,'2025-12-25 17:56:17','2025-12-25 17:56:17'),
(169,'conditions','Migrain & Sakit Kepala Tegang','Sering migrain atau sakit kepala kalau lagi banyak pikiran.','Tension Headache atau migrain sering dipicu oleh ketegangan otot leher akibat stres. Hipnoterapi mengajarkan teknik \'Body Scan\' untuk merilis ketegangan mikro di otot kepala yang tidak Anda sadari. Kami juga kurangi sensitivitas saraf nyeri dengan \'Dial Control\' mental, sehingga intensitas sakit berkurang drastis tanpa obat pereda nyeri berlebih.','migrain,pusing,kepala,sakit',8,1,'2025-12-25 17:56:17','2025-12-25 17:56:17'),
(170,'conditions','Asma Psikosomatis','Asma sering kambuh kalau lagi cemas atau panik.','Serangan asma sering diperparah oleh kepanikan (takut tidak bisa napas). Kami putus siklus \'Cemas -> Sesak -> Panik -> Makin Sesak\'. Kami ajarkan teknik napas diafragma dalam kondisi trance yang membuat paru-paru terasa longgar. Klien belajar tetap tenang saat gejala awal muncul, sehingga serangan tidak menjadi parah.','asma,sesak,napas,paru',8,1,'2025-12-25 17:56:17','2025-12-25 17:56:17'),
(171,'conditions','Alergi & Gatal (Neurodermatitis)','Kulit gatal-gatal parah kalau lagi stres, obat salep gak mempan.','Ini Neurodermatitis. Pikiran stres mengirim sinyal peradangan ke kulit. Hipnoterapi menenangkan sistem saraf otonom yang \'overacting\'. Kami gunakan visualisasi \'Cooling Water\' atau cahaya sejuk yang mengalir di bawah kulit, meredakan rasa panas dan gatal dari dalam.','gatal,kulit,alergi,garuk',7,1,'2025-12-25 17:56:17','2025-12-25 17:56:17'),
(172,'conditions','IBS (Usus Sensitif)','Perut melilit dan diare kalau mau meeting atau ujian.','Irritable Bowel Syndrome (IBS) sangat terkait erat dengan otak (Gut-Brain Axis). Kami berkomunikasi dengan \'Otak Perut\' Anda. Sugesti ketenangan dialirkan ke sistem pencernaan. Kami ubah respon \'Fight or Flight\' (yang bikin sakit perut) menjadi \'Rest and Digest\', sehingga pencernaan nyaman di segala situasi.','ibs,perut,diare,mulas',8,1,'2025-12-25 17:56:18','2025-12-25 17:56:18'),
(173,'conditions','Hipertensi (Darah Tinggi)','Tensi susah turun padahal sudah jaga makan.','Jika medis sudah dijalankan, sisanya adalah manajemen emosi. Kemarahan terpendam (repressed anger) sering jadi pemicu hipertensi. Terapi \'Emotional Release\' membantu membuang \'uap panas\' emosi ini. Relaksasi deep trance terbukti secara klinis melebarkan pembuluh darah dan menurunkan tekanan darah secara alami.','darah tinggi,tensi,hipertensi,marah',8,1,'2025-12-25 17:56:18','2025-12-25 17:56:18'),
(174,'conditions','Penyembuhan Pasca Operasi','Mau operasi besar, takut penyembuhannya lama/sakit.','Kami bantu persiapan mental Pre-Op dan percepatan Post-Op. Riset menunjukkan pasien yang dihipnosis pulih 30% lebih cepat. Kami sugéstikan aliran darah membawa nutrisi ke luka operasi untuk merajut jaringan dengan cepat dan sempurna. Rasa nyeri dikelola dengan \'Mental Anesthesia\'.','operasi,bedah,luka,sembuh',7,1,'2025-12-25 17:56:18','2025-12-25 17:56:18'),
(175,'conditions','Mabuk Perjalanan','Gak bisa naik mobil/laut, pasti muntah.','Motion Sickness terjadi karena konflik sinyal mata dan telinga dalam. Kami kalibrasi ulang keseimbangan tubuh Anda di level bawah sadar. Visualisasi perjalanan dibuat menyenangkan. Anchor \'Jeruk Nipis\' atau rasa segar ditanamkan untuk menghilangkan mual seketika saat kendaraan bergerak.','mabuk,mual,mobil,laut',7,1,'2025-12-25 17:56:18','2025-12-25 17:56:18'),
(176,'conditions','Latah (Echolalia)','Malu banget saya latah parah, dikagetin dikit ngomong jorok.','Latah adalah refleks kejut yang \'salah sambung\' ke verbal. Kami perbaiki sirkuit refleks ini. Latihan desensitisasi dengan kejutan-kejutan kecil dalam kondisi rileks. Kami ganti respon kata-kata jorok menjadi gerakan diam atau tarik napas. Butuh latihan repetitif tapi sangat bisa sembuh.','latah,kaget,jorok,malu',8,1,'2025-12-25 17:56:19','2025-12-25 17:56:19'),
(177,'conditions','Tourette Ringan (Tics)','Suka kedip-kedip mata atau gerak bahu tanpa sadar (Tics).','Tics sering memburuk saat stres/lelah. Hipnoterapi mengajarkan kesadaran tubuh (Body Awareness) mendalam. Kami cari \'sensasi awal\' sebelum Tics muncul dan mengajarkan respon alternatif (misal: meremas bola karet) yang lebih socially acceptable. Tingkat kecemasan umum diturunkan agar frekuensi Tics berkurang.','tics,tourette,gerak,mata',7,1,'2025-12-25 17:56:19','2025-12-25 17:56:19'),
(178,'conditions','Gagap (Stuttering)','Bicara tersendat-sendat kalau gugup.','Gagap seringkali masalah \'Timing\' antara otak dan mulut. Kami ajarkan teknik bernyanyi (melodical speech) dalam hati yang membuat bicara lebih lancar. Trauma masa kecil (pernah diejek saat bicara) disembuhkan. Confidence dibangun agar klien tidak takut salah ucap.','gagap,bicara,bata,lidah',8,1,'2025-12-25 17:56:19','2025-12-25 17:56:19'),
(179,'conditions','Sakit Punggung Kronis (Back Pain)','Punggung sakit terus kata dokter tidak ada saraf kejepit.','Tension Myositis Syndrome (TMS). Sakit fisik akibat emosi terpendam. Kami bantu Anda menyadari emosi apa yang sedang \'dipanggul\' di punggung. Dengan melepas beban emosi tersebut, otot punggung yang kaku kronis bisa rileks dan nyeri hilang seketika.','punggung,sakit,pinggang,encok',7,1,'2025-12-25 17:56:19','2025-12-25 17:56:19'),
(180,'conditions','Bau Badan (Psikosomatis)','Merasa bau badan padahal orang bilang enggak (Olfactory Reference Syndrome).','Ini halusinasi penciuman karena social anxiety. Klien merasa orang lain menutup hidung karenanya. Kami re-kalibrasi indra penciuman dan keyakinan diri. Kami ajak klien melihat bukti nyata (tanya orang terpercaya) dan membangun rasa aman di keramaian.','bau,badan,keringat,parfum',6,1,'2025-12-25 17:56:19','2025-12-25 17:56:19'),
(181,'conditions','Hypno-Fertility Pria','Sperma kurang bagus kata dokter karena stres kerja.','Stres oksidatif membunuh kualitas sperma. Hipnoterapi menurunkan kortisol drastis, memungkinkan tubuh memproduksi testosteron optimal. Kami visualisasikan \'Pabrik\' reproduksi bekerja maksimal menghasilkan benih yang sehat, lincah, dan kuat.','hamil,pria,sperma,subur',7,1,'2025-12-25 17:56:20','2025-12-25 17:56:20'),
(182,'conditions','Vaginismus Sekunder','Dulu bisa hubungan intim, sekarang tiba-tiba sakit/takut.','Biasanya ada trauma baru (misal: pasca melahirkan sakit, atau perselingkuhan). Kami cari akar pemicu sekundernya. Kami \'reset\' memori otot vagina agar kembali rileks seperti masa bulan madu. Hubungan emosional dengan suami juga diperbaiki.','seks,sakit,vaginismus,takut',8,1,'2025-12-25 17:56:20','2025-12-25 17:56:20'),
(183,'conditions','Menopause Dini/Gejala','Hot flashes parah dan mood swing karena menopause.','Hipnoterapi sangat efektif meredakan Hot Flashes. Kami ajarkan teknik \'Cooling Visualization\' (membayangkan berada di pegunungan salju) saat hawa panas muncul. Emosi mood swing dikelola dengan anchoring ketenangan, membantu ibu menerima fase baru ini dengan anggun.','menopause,panas,tua,haid',7,1,'2025-12-25 17:56:20','2025-12-25 17:56:20'),
(184,'students','Hafalan Quran (Tahfidz)','Susah hafal ayat, gampang lupa. Mau lancar tahfidz.','Kami aktivasi \'Photographic Memory\' untuk ayat. Dalam kondisi Alpha, otak menyerap hafalan 3x lebih cepat. Kami tanamkan sugesti: \'Ayat Al-Quran mudah dan lekat di hati\'. Blok mental \'Ayat ini susah\' dihancurkan. Kami hubungkan hafalan dengan emosi cinta pada Allah agar awet.','hafal,quran,tahfidz,lupa',9,1,'2025-12-25 17:56:20','2025-12-25 17:56:20'),
(185,'students','Matematika Phobia','Lihat angka langsung pusing dan takut salah.','Trauma guru matematika galak di SD sering jadi penyebab. Kami \'Reframe\' matematika bukan sebagai monster, tapi sebagai teka-teki seru. Rasa takut diganti rasa penasaran. Saat rileks, logika matematika sebenarnya mudah diproses otak.','matematika,hitung,bodoh,takut',8,1,'2025-12-25 17:56:20','2025-12-25 17:56:20'),
(186,'students','Belajar Bahasa Asing','Belajar Inggris bertahun-tahun gak bisa ngomong (pasif).','Mental block \'Takut Grammar Salah\'. Kami jebol dinding ini. Fokus diubah dari \'Benar/Salah\' menjadi \'Komunikasi/Paham\'. Kami install kepercayaan diri untuk *berani* bicara (cas cis cus) dulu. Lidah diluweskan lewat sugesti motorik.','inggris,bahasa,bicara,malu',8,1,'2025-12-25 17:56:21','2025-12-25 17:56:21'),
(187,'students','Homeschooling Motivasi','Anak homeschooling malas, gak ada saingan.','Tantangan HS adalah disiplin diri. Kami bantu anak membuat \'Sekolah Internal\' di pikirannya. Menciptakan motivasi intrinsik (belajar karena butuh/suka, bukan karena disuruh guru). Jadwal harian ditanamkan ke bawah sadar agar otomatis bergerak tanpa disuruh ortu.','sekolah,rumah,malas,belajar',7,1,'2025-12-25 17:56:21','2025-12-25 17:56:21'),
(188,'students','Persiapan Lomba/Olimpiade','Anak mau olimpiade sains, takut blank.','Mental Juara (Winning Mindset). Visualisasi proses mengerjakan soal dengan tenang dan tepat. Kami ajarkan teknik \'Time Distortion\' agar saat lomba, waktu terasa melambat sehingga anak punya banyak waktu berpikir, tapi kerjanya cepat.','lomba,juara,menang,olimpiade',8,1,'2025-12-25 17:56:21','2025-12-25 17:56:21'),
(189,'students','Pindah Sekolah (Adaptasi)','Anak stres pindah sekolah baru, gak punya teman.','Adaptasi sosial. Kami bantu anak meningkatkan \'Social Magnetism\'. Menghilangkan rasa asing dan takut ditolak. Kami visualisasikan dia tersenyum, menyapa, dan diterima baik oleh teman baru. Rasa percaya diri ini akan terpancar dan menarik teman nyata.','pindah,sekolah,teman,asing',7,1,'2025-12-25 17:56:21','2025-12-25 17:56:21'),
(190,'students','Gap Year Anxiety','Stres karena gap year (nganggur setahun) lihat teman kuliah.','Fase \'Social Comparison\' yang menyakitkan. Kami ubah mindset Gap Year dari \'Tertinggal\' menjadi \'Persiapan Matang\'. Kami bantu menyusun visi yang lebih besar. Rasa minder diganti dengan fokus pada pengembangan skill diri selama setahun.','kuliah,gagal,malu,teman',8,1,'2025-12-25 17:56:21','2025-12-25 17:56:21'),
(191,'students','Sidang Skripsi/Tesis','Takut dibantai dosen penguji pas sidang.','Ketakutan berlebih membuat otak \'Freeze\'. Kami latih simulasi sidang berkali-kali di pikiran. Dosen penguji divisualisasikan sebagai mitra diskusi yang ramah. Anchor \'Tenang & Tegas\' dipasang untuk menjawab pertanyaan sulit dengan diplomatis.','sidang,skripsi,dosen,takut',9,1,'2025-12-25 17:56:22','2025-12-25 17:56:22'),
(192,'students','Masuk Asrama/Pesantren','Anak nangis gak mau ditinggal di asrama.','Separation Anxiety. Kami kuatkan mental anak bahwa \'Jauh di mata, dekat di doa\'. Kami berikan teknik telepati hati untuk \'mengirim kangen\' ke orang tua tanpa harus menangis. Kemandirian dan kebanggaan menjadi santri ditanamkan kuat.','pesantren,asrama,pisah,ortu',8,1,'2025-12-25 17:56:22','2025-12-25 17:56:22'),
(193,'students','Kecanduan Komik/Novel','Baca Wattpad/Komik sampai lupa belajar dan tidur.','Escapism ke dunia fiksi. Kami negosiasi dengan bagian diri penikmat cerita. Kami buat kesepakatan: \'Selesaikan tugas dunia nyata dulu, baru boleh masuk dunia cerita sebagai reward\'. Keseimbangan realita dan fantasi dipulihkan.','baca,novel,komik,halu',7,1,'2025-12-25 17:56:22','2025-12-25 17:56:22'),
(194,'career','Tes CPNS/Kedinasan','Gagal berkali-kali tes CPNS, trauma mau coba lagi.','Mental block kegagalan. Kami bersihkan memori gagal sebelumnya. Kami install \'Mentalitas Aparatur\': ketelitian, ketenangan, dan kecepatan dalam mengerjakan soal CAT. Kepercayaan diri dipulihkan bahwa \'Tahun ini jatah saya\'.','cpns,tes,pns,gagal',9,1,'2025-12-25 17:56:22','2025-12-25 17:56:22'),
(195,'career','Tes Masuk Polisi/TNI','Persiapan mental tes pantukhir polisi/tentara.','Seleksi alam bawah sadar. Kami bentuk mental baja yang dibutuhkan aparat. Disiplin, tegas, dan pantang menyerah. Latihan visualisasi fisik yang prima. Mengurangi kecemasan saat tes kesehatan atau wawancara mental ideologi.','polisi,tni,tentara,tes',8,1,'2025-12-25 17:56:23','2025-12-25 17:56:23'),
(196,'career','Sales Target','Stres dikejar target penjualan tiap bulan.','Pressure tinggi bisa bikin lumpuh. Kami ubah \'Target Angka\' menjadi \'Game Seru\'. Penolakan konsumen (Rejection) dimaknai ulang sebagai \'Langkah menuju Closing\'. Motivasi internal dibangkitkan untuk mengejar bonus dengan semangat, bukan dengan ketakutan dipecat.','sales,jualan,target,stres',8,1,'2025-12-25 17:56:23','2025-12-25 17:56:23'),
(197,'career','Tenaga Medis Burnout','Saya nakes (dokter/perawat), lelah mental lihat orang sakit/mati.','Compassion Fatigue. Kami bantu Anda membuat \'Filter Emosi\'. Anda tetap bisa empati melayani pasien, tapi tidak menyerap energi negatif/kesedihan mereka ke dalam hati Anda. Teknik \'Cleansing\' sepulang kerja wajib dilakukan agar rumah tetap ceria.','dokter,perawat,rs,lelah',8,1,'2025-12-25 17:56:23','2025-12-25 17:56:23'),
(198,'career','Programmer Burnout','Coding error terus, otak rasanya ngebul (Mental Fatigue).','Otak kiri over-used. Hipnoterapi menyeimbangkan dengan mengaktifkan otak kanan (kreatif/rileks). Sesi deep trance selama 20 menit setara reset otak total. Fokus dan logika algoritma akan kembali tajam setelah istirahat mental yang berkualitas.','coding,it,komputer,lelah',7,1,'2025-12-25 17:56:23','2025-12-25 17:56:23'),
(199,'career','Shift Malam (Satpam/Nakes)','Susah tidur siang setelah shift malam, badan rontok.','Shift Work Sleep Disorder. Kami ajarkan tubuh untuk \'Switch Mode\' instan. Kami pasang anchor: \'Pakai kacamata tidur = Malam hari\', meski di luar terang. Kualitas tidur deep sleep dimaksimalkan dalam waktu singkat agar bangun segar bugar.','shift,malam,tidur,kerja',7,1,'2025-12-25 17:56:23','2025-12-25 17:56:23'),
(200,'career','Musisi/Seniman Block','Buntu ide, gak bisa bikin lagu/lukisan lagi.','Creative Block. Kami buka akses ke alam bawah sadar tempat gudang inspirasi. Kami hilangkan perfeksionisme yang menghambat aliran karya. Anda akan masuk ke \'Flow State\' di mana karya lahir mengalir begitu saja melalui tangan Anda.','seni,karya,buntu,ide',8,1,'2025-12-25 17:56:24','2025-12-25 17:56:24'),
(201,'career','Grogi Rapat Direksi','Takut bicara depan bos-bos besar/pemilik saham.','Authority Anxiety. Kami setarakan level mental Anda. Di mata Tuhan dan hukum, semua manusia sama. Kami hilangkan rasa \'kecil\' di hadapan jabatan. Anda akan mampu menyampaikan ide dengan hormat namun tetap percaya diri dan berwibawa.','bos,rapat,takut,bicara',8,1,'2025-12-25 17:56:24','2025-12-25 17:56:24'),
(202,'career','Wirausaha Pemula','Takut mulai bisnis, takut rugi, overthinking.','Analysis Paralysis. Kebanyakan mikir gak jalan-jalan. Kami dorong \'Action Mindset\'. Rasa takut rugi diubah menjadi \'Manajemen Risiko\'. Keberanian mengambil langkah pertama ditanamkan. Visi kesuksesan diperjelas untuk menarik semangat.','bisnis,usaha,mulai,takut',8,1,'2025-12-25 17:56:24','2025-12-25 17:56:24'),
(203,'career','Pensiunan Tentara/Polisi','Susah adaptasi jadi warga sipil, emosian/keras.','Post-Service Adjustment. Kebiasaan komando keras tidak cocok di rumah/masyarakat sipil. Kami bantu melembutkan hati dan perilaku tanpa menghilangkan jati diri ksatria. Belajar komunikasi persuasif menggantikan komunikasi instruksi.','pensiun,tentara,keras,emosi',7,1,'2025-12-25 17:56:24','2025-12-25 17:56:24'),
(204,'relationships','Beda Agama (Pacaran)','Galau hubungan beda agama, lanjut atau udahan.','Konflik logika vs perasaan. Kami tidak mengambil keputusan untuk Anda, tapi menjernihkan pikiran Anda dari \'Bucin\'. Kami ajak Anda melihat masa depan realistis 5-10 tahun ke depan. Keputusan (pisah atau lanjut) akan muncul dari kebijaksanaan batin Anda sendiri dengan damai.','beda agama,pacar,nikah,restu',9,1,'2025-12-25 17:56:24','2025-12-25 17:56:24'),
(205,'relationships','Long Distance Marriage','Suami kerja di laut/tambang, kesepian dan curiga.','Tantangan istri pelaut/tambang. Kami kuatkan mental mandiri. Rasa sepi diubah menjadi waktu produktif untuk diri dan anak. Kepercayaan diperkuat. Kami bantu Anda merasa \'terhubung\' secara batin meski fisik berjauhan, mengurangi drama saat komunikasi.','ldr,suami,jauh,sepi',8,1,'2025-12-25 17:56:25','2025-12-25 17:56:25'),
(206,'relationships','Wanita Karir vs Suami','Suami minder gaji saya lebih besar, jadi sering marah.','Ego pria terluka. Kami bantu istri untuk tetap menghormati suami sebagai kepala keluarga (leadership) di rumah, terlepas dari nominal gaji. Kami ajarkan komunikasi yang mengangkat harga diri suami, sehingga keharmonisan terjaga tanpa harus resign kerja.','gaji,istri,karir,suami',8,1,'2025-12-25 17:56:25','2025-12-25 17:56:25'),
(207,'relationships','Child-free Conflict','Saya mau child-free, pasangan/ortu maksa punya anak.','Tekanan sosial berat. Kami bantu Anda untuk yakin dan tenang dengan pilihan hidup Anda (jika sudah final), atau membuka blok jika sebenarnya Anda takut punya anak (tokophobia). Yang utama adalah ketenangan batin menghadapi komentar miring orang lain.','anak,mandul,bebas,nikah',8,1,'2025-12-25 17:56:25','2025-12-25 17:56:25'),
(208,'relationships','Adopsi Anak (Bonding)','Saya adopsi anak tapi kok rasanya belum sayang ya?','Bonding issue. Rasa sayang bisa ditumbuhkan. Kami bantu Anda melihat jiwa anak ini sebagai titipan Allah yang spesial untuk Anda. Kami hapus keraguan \'Bukan darah daging sendiri\'. Perlahan rasa kasih sayang ibu-anak akan mengalir alami dari hati.','adopsi,anak,sayang,bonding',7,1,'2025-12-25 17:56:25','2025-12-25 17:56:25'),
(209,'relationships','Ibu Tiri/Ayah Tiri','Anak tiri benci saya, saya jadi stres di rumah sendiri.','Blended Family challenge. Jangan memaksa menggantikan posisi orang tua kandung. Kami bantu Anda menjadi \'Sahabat Dewasa\' yang asik dulu. Kami kurangi ekspektasi berlebih. Kesabaran dan ketulusan ditanamkan di bawah sadar, yang lama-lama akan meluluhkan hati anak.','tiri,anak,benci,keluarga',7,1,'2025-12-25 17:56:25','2025-12-25 17:56:25'),
(210,'relationships','Mantan Menghantui','Sudah nikah tapi masih kebayang mantan pacar terus.','Emotional Affair di pikiran. Bahaya buat rumah tangga. Kami lakukan \'Cord Cutting\' final. Kenangan mantan diarsipkan di \'Museum Masa Lalu\' yang berdebu dan tidak menarik lagi. Fokus energi cinta dipindahkan sepenuhnya ke pasangan sah sekarang.','mantan,ingat,nikah,selingkuh',9,1,'2025-12-25 17:56:26','2025-12-25 17:56:26'),
(211,'relationships','KDRT Verbal','Suami gak mukul tapi omongannya kasar merendahkan.','Verbal Abuse merusak mental. Kami bangun \'Tembok Harga Diri\'. Kata-kata kasar mental tidak masuk ke hati. Kami juga bangkitkan keberanian Anda untuk menetapkan batasan (boundaries): \'Saya tidak terima dibentak\'. Ketegasan istri seringkali justru menghentikan perilaku suami.','kasar,bentak,suami,sakit hati',9,1,'2025-12-25 17:56:26','2025-12-25 17:56:26'),
(212,'relationships','Istri Dominan','Istri saya terlalu ngatur, saya merasa gak punya wibawa.','Suami takut istri. Kami gali akar ketakutan (mungkin figur ibu galak?). Kami bangkitkan \'Maskulinitas Sehat\'. Bukan jadi kasar, tapi jadi pemimpin yang tegas dan mengayomi. Saat suami berubah wibawa, pola istri biasanya otomatis melunak menyesuaikan.','istri,galak,takut,suami',8,1,'2025-12-25 17:56:26','2025-12-25 17:56:26'),
(213,'relationships','Pasangan Narsistik','Capek hadapi pasangan yang merasa paling benar & manipulatif.','Narcissistic Victim Syndrome. Anda dibuat merasa gila (Gaslighting). Kami pulihkan realita Anda. \'Anda waras, Anda benar\'. Kami latih teknik \'Grey Rock\' (jadi membosankan bagi narsis) dan emotional detachment agar manipulasi dia tidak lagi mempan menyakiti Anda.','narsis,ego,manipulasi,korban',9,1,'2025-12-25 17:56:26','2025-12-25 17:56:26'),
(214,'islamic','Susah Tahajud','Pengen bangun malam tapi berat banget matanya.','Blok mental atau dosa. Kami set \'Spiritual Alarm\'. Niat ditanamkan ke dalam Reticular Activating System (RAS). Tidur lebih awal dengan wudhu. Sugesti: \'Bangun tahajud itu nikmat, seperti janji kencan dengan Allah\'. Otak akan membangunkan fisik dengan segar.','tahajud,tidur,malas,ibadah',8,1,'2025-12-25 17:56:26','2025-12-25 17:56:26'),
(215,'islamic','Riya\' & Ujub','Takut ibadah saya gak diterima karena pamer (Riya).','Penyakit hati halus. Kami bantu meluruskan niat (Rectification of Intention). Latihan: \'Ibadah sembunyi-sembunyi\'. Menanamkan rasa bahwa pujian manusia itu sampah, hanya ridho Allah yang emas. Fokus batin dikembalikan hanya kepada Sang Khalik.','riya,pamer,sombong,ibadah',8,1,'2025-12-25 17:56:27','2025-12-25 17:56:27'),
(216,'islamic','Takabur/Sombong','Merasa lebih baik dari orang lain, hati keras.','Kami lakukan \'Ego Dissolution\'. Membayangkan asal kejadian manusia dari tanah dan air hina. Mengingat kematian yang bisa datang kapan saja. Terapi ini melembutkan hati yang keras, memunculkan sifat tawadhu (rendah hati) yang menyejukkan.','sombong,hebat,krs,hati',8,1,'2025-12-25 17:56:27','2025-12-25 17:56:27'),
(217,'islamic','Was-was Wudhu','Wudhu diulang-ulang takut gak sah, boros air.','OCD Religi. Setan membisikkan keraguan. Kami potong loop keraguan itu. Sugesti: \'Yakin itu kuat, ragu itu lemah\'. Kami tanamkan kaidah Fikih: \'Keyakinan tidak bisa dikalahkan keraguan\'. Sekali basuh rata = SAH. Titik. Hati jadi mantap.','wudhu,ragu,ulang,sah',9,1,'2025-12-25 17:56:27','2025-12-25 17:56:27'),
(218,'islamic','Was-was Kentut Sholat','Lagi sholat terasa kayak kentut, padahal enggak.','Gangguan fisik/psikis umum. Jika tidak ada suara/bau, itu hanya kedutan otot/setan. Kami latih fokus (Khusyuk) mengabaikan sensasi dubur. Fokus dialihkan ke dada/bacaan sholat. Seringkali sensasi itu hilang saat tidak diperhatikan.','sholat,kentut,batal,ragu',8,1,'2025-12-25 17:56:27','2025-12-25 17:56:27'),
(219,'islamic','Takut Mati Suul Khotimah','Cemas berlebih takut mati dalam keadaan buruk.','Kecemasan ini tanda iman (takut dosa), tapi kalau berlebih jadi putus asa. Kami seimbangkan Khauf (Takut) dan Raja\' (Harap). Kami bantu Anda fokus pada persiapan amal hari ini, karena \'Seseorang akan mati sesuai kebiasaan hidupnya\'. Hiduplah baik, insya Allah mati baik.','mati,dosa,neraka,takut',9,1,'2025-12-25 17:56:28','2025-12-25 17:56:28'),
(220,'islamic','Malas Baca Quran','Quran berdebu, berat banget mau buka.','Ada hijab di hati. Kami bersihkan dengan Istighfar Therapy. Kami ubah asosiasi: \'Baca Quran = Charging Jiwa\'. Mulai dari target kecil (One Day One Ayat) yang menyenangkan, bukan beban 1 juz yang berat. Konsistensi dibangun perlahan.','quran,ngaji,malas,baca',8,1,'2025-12-25 17:56:28','2025-12-25 17:56:28'),
(221,'islamic','Sering Mengumpat','Susah ngerem mulut ngomong kotor/kebun binatang.','Kebiasaan verbal refleks. Kami pasang \'Rem Mulut\'. Sebelum kata kotor keluar, lidah terasa kaku atau hati beristighfar. Kami ganti kata kotor dengan kata pengganti yang netral (misal: \'Asem\', \'Waduh\') atau dzikir.','kotor,kasar,mulut,ngomong',7,1,'2025-12-25 17:56:28','2025-12-25 17:56:28'),
(222,'islamic','Dendam Warisan','Keluarga saya musuhan sama paman turun temurun.','Memutus rantai kebencian. Kami bantu Anda menyadari bahwa dosa/masalah orang tua bukan beban Anda. Anda berhak berdamai dan menyambung silaturahmi. Memaafkan demi Allah, membebaskan diri dari kutukan dendam keluarga.','dendam,keluarga,musuh,waris',8,1,'2025-12-25 17:56:28','2025-12-25 17:56:28'),
(223,'islamic','Jodoh Tak Kunjung Datang (Spiritual)','Apa saya kena sihir penghalang jodoh?','Seringkali bukan sihir, tapi \'Aura Tertutup\' karena kesedihan/keputusasaan. Kami lakukan \'Cleansing Aura\'. Membuang mentalitas korban. Memancarkan aura positif, ceria, dan tawakkal. Aura yang cerah adalah magnet jodoh terbaik.','jodoh,sihir,tutup,nikah',9,1,'2025-12-25 17:56:28','2025-12-25 17:56:28'),
(224,'self_dev','Speed Reading','Mau baca buku cepat dan paham (untuk mahasiswa/riset).','Kami relaksasi otot mata agar jangkauan pandang melebar (peripheral vision). Menghilangkan kebiasaan mengeja dalam hati (sub-vocalization) yang bikin lambat. Otak diprogram untuk menyerap keyword halaman dengan cepat seperti scanner.','baca,cepat,buku,belajar',7,1,'2025-12-25 17:56:29','2025-12-25 17:56:29'),
(225,'self_dev','Memory Enhancement','Sering lupa nama orang baru kenal.','Kami ajarkan teknik asosiasi imajinatif. Saat kenalan, wajah orang itu dikaitkan dengan namanya lewat gambar lucu di kepala. Hipnoterapi mempertajam daya ingat jangka pendek dan pemanggilan kembali (recall) data.','lupa,ingat,memori,nama',7,1,'2025-12-25 17:56:29','2025-12-25 17:56:29'),
(226,'self_dev','Bangun Pagi','Susah bangun subuh, alarm dimatiin tidur lagi.','Kami program jam biologis. Niat bangun jam 4 pagi ditanam kuat. Sugesti: \'Saat alarm bunyi, tubuh langsung duduk dan segar\'. Menghilangkan rasa berat/kantuk (sleep inertia) saat membuka mata.','pagi,subuh,bangun,tidur',8,1,'2025-12-25 17:56:29','2025-12-25 17:56:29'),
(227,'self_dev','Public Speaking Humor','Bisa bicara tapi kaku, pengen bisa lucu/santai.','Humor butuh kecerdasan dan rileks. Kami bantu Anda melepas \'Topeng Jaim\'. Menertawakan diri sendiri adalah kunci. Saat Anda rileks dan autentik, humor akan mengalir natural tanpa dipaksa, audiens pun senang.','lucu,humor,kaku,bicara',6,1,'2025-12-25 17:56:29','2025-12-25 17:56:29'),
(228,'self_dev','Belajar Skill Baru (Coding/Desain)','Belajar hal baru rasanya susah masuk otak (Mental Block).','Learning Agility. Kami buka mindset: \'Otak saya plastis dan bisa belajar apa saja\'. Rasa frustrasi saat error diubah menjadi rasa penasaran: \'Hmm, apa solusinya?\'. Proses belajar jadi adiktif positif.','belajar,skill,susah,bisa',7,1,'2025-12-25 17:56:29','2025-12-25 17:56:29'),
(229,'self_dev','Manajemen Waktu','Sehari 24 jam rasanya kurang, keteteran.','Masalah prioritas dan fokus. Kami bantu Anda membedakan \'Penting\' vs \'Mendesak\'. Menghilangkan distraksi digital. Anda akan bekerja dalam mode \'Deep Work\', di mana 1 jam kerja fokus setara 4 jam kerja biasa. Waktu jadi terasa longgar.','waktu,sibuk,telat,jadwal',8,1,'2025-12-25 17:56:30','2025-12-25 17:56:30'),
(230,'self_dev','Charisma Building','Pengen punya wibawa dan disukai banyak orang.','Kharisma adalah pancaran energi \'Hadir Utuh\' (Presence). Kami latih Anda untuk benar-benar hadir saat bicara dengan orang (Active Listening), kontak mata teduh, dan bahasa tubuh terbuka. Orang akan merasa spesial di dekat Anda.','wibawa,kharisma,keren,pemimpin',8,1,'2025-12-25 17:56:30','2025-12-25 17:56:30'),
(231,'self_dev','Decision Making','Plin-plan, susah ambil keputusan sederhana.','Ragu-ragu menghabiskan energi. Kami hubungkan logika dengan intuisi (Gut Feeling). Latihan ambil keputusan kecil cepat (pilih menu makan < 1 menit). Kepercayaan diri pada pilihan sendiri ditingkatkan. \'Salah itu belajar, diam itu mati\'.','ragu,pilih,putus,bingung',7,1,'2025-12-25 17:56:30','2025-12-25 17:56:30'),
(232,'self_dev','Kebersihan/Kerapian','Kamar berantakan banget, malas beres-beres.','Lingkungan cerminan pikiran. Kami tanamkan nilai: \'Bersih itu Nyaman & Berkah\'. Kegiatan menyapu/lipat baju dijadikan meditasi bergerak (Zen Cleaning). Rasa malas diganti kepuasan melihat ruangan rapi.','bersih,rapi,malas,jorok',7,1,'2025-12-25 17:56:30','2025-12-25 17:56:30'),
(233,'self_dev','Tulisan Tangan Bagus','Tulisan ceker ayam, mau perbaiki (Graphotherapy).','Tulisan tangan terkait karakter. Dengan melatih menulis rapi dan teratur secara sadar (latihan motorik halus), kita juga merapikan kekacauan di pikiran. Kesabaran dilatih lewat goresan pena.','tulis,jelek,rapi,baca',6,1,'2025-12-25 17:56:30','2025-12-25 17:56:30'),
(234,'habits','Ngupil di Depan Umum','Sering gak sadar ngupil pas ngobrol, malu-maluin.','Kebiasaan bawah sadar tangan \'main\'. Kami beri \'Alert System\'. Saat tangan naik ke hidung, otomatis muncul rasa sadar atau gatal di telapak tangan sehingga urung dilakukan. Kesadaran sosial ditingkatkan.','ngupil,jorok,tangan,malu',6,1,'2025-12-25 17:56:31','2025-12-25 17:56:31'),
(235,'habits','Gigit Bibir/Kupas Kulit Bibir','Bibir sampai berdarah dikupas terus kalau cemas.','Skin Picking disorder ringan. Penyaluran cemas yang merusak. Kami ganti salurannya. Saat cemas, jari dialihkan memegang tasbih atau stress ball. Bibir disugestikan harus tetap mulus dan licin.','bibir,darah,kupas,cemas',7,1,'2025-12-25 17:56:31','2025-12-25 17:56:31'),
(236,'habits','Membungkuk (Postur)','Jalan bungkuk, sering ditegur orang.','Postur tubuh mempengaruhi emosi (Body-Mind). Kami install \'Tali Imajiner\' yang menarik ubun-ubun ke langit. Tubuh otomatis tegak. Rasa percaya diri juga otomatis naik saat punggung tegak.','bungkuk,tegak,jalan,badan',7,1,'2025-12-25 17:56:31','2025-12-25 17:56:31'),
(237,'habits','Kletek Jari/Leher','Bunyiin jari/leher tiap 5 menit, ganggu orang.','Obsesi bunyi \'kretek\'. Kami bantu menahan dorongan itu. Kami visualisasikan sendi-sendi Anda dilumasi minyak sehingga nyaman tanpa harus dikretek. Rasa pegal diatasi dengan stretching otot yang benar, bukan dipatahkan.','jari,bunyi,kretek,pegal',6,1,'2025-12-25 17:56:31','2025-12-25 17:56:31'),
(238,'habits','Makan Cepat','Makan kayak dikejar setan, kunyah cuma 3x telan.','Penyebab gangguan pencernaan dan obesitas. Kami ajarkan \'Mindful Eating\'. Menikmati setiap tekstur dan rasa. Meletakkan sendok setiap suapan. Makan pelan menjadi ritual kenikmatan baru, perut cepat kenyang.','makan,cepat,kunyah,lambung',7,1,'2025-12-25 17:56:31','2025-12-25 17:56:31'),
(239,'habits','Suka Menyela Bicara','Orang belum selesai ngomong sudah dipotong.','Tanda ketidaksabaran ego. Kami latih \'Active Listening\'. Menahan diri itu tanda kecerdasan. Kami beri sugesti: \'Dengarkan sampai titik, baru bicara\'. Kualitas obrolan akan meningkat drastis.','potong,bicara,sabar,dengar',7,1,'2025-12-25 17:56:32','2025-12-25 17:56:32'),
(240,'habits','Belanja Lapar Mata','Beli makanan banyak tapi gak dimakan (Food Waste).','Lapar mata itu lapar emosi. Kami latih bertanya: \'Perut muat gak?\'. Membayangkan rasa kenyang begah sebelum membeli. Menghargai makanan agar tidak mubazir (dosa temannya setan).','makan,beli,buang,boros',7,1,'2025-12-25 17:56:32','2025-12-25 17:56:32'),
(241,'habits','Tarik-tarik Rambut (Ringan)','Suka mainin rambut diputer-puter sampai rontok.','Kebiasaan soothing (menenangkan diri). Kami ganti objeknya. Mainin rambut diganti mainin gelang atau cincin. Tangan disibukkan dengan aktivitas lain saat sedang bengong/nonton TV.','rambut,putar,tangan,botak',6,1,'2025-12-25 17:56:32','2025-12-25 17:56:32'),
(242,'habits','Menggeretakkan Gigi (Bruxism)','Tidur sambil bunyi gigi (kerot), bangun rahang sakit.','Bruxism tanda stres terpendam keluar saat tidur. Kami relaksasi otot rahang (Jaw Release) sebelum tidur. Emosi siang hari diselesaikan/diikhlaskan sebelum mata terpejam, sehingga tidur tenang tanpa gerinda gigi.','gigi,bunyi,tidur,sakit',7,1,'2025-12-25 17:56:32','2025-12-25 17:56:32'),
(243,'habits','Suka Ngaret (Telat)','Janji jam 9 datang jam 10, teman pada sebel.','Chronic Lateness. Meremehkan waktu orang. Kami ubah jam internal Anda \'Majukan 30 menit\'. Rasa malu datang telat diperbesar. Disiplin waktu dimaknai sebagai integritas diri dan penghormatan pada orang lain.','telat,jam,ngaret,janji',8,1,'2025-12-25 17:56:33','2025-12-25 17:56:33'),
(244,'admin','Voucher Hadiah','Ada voucher buat kado ultah teman?','Ada! \'Gift of Peace\'. Anda bisa membelikan sesi terapi untuk orang tersayang (pasangan/ortu/teman). Voucher fisik cantik atau digital e-card. Berlaku 3 bulan. Kado kesehatan mental adalah kado terbaik.','kado,hadiah,voucher,ultah',6,1,'2025-12-25 17:56:33','2025-12-25 17:56:33'),
(245,'admin','Reschedule Dadakan','Anak sakit, bisa reschedule hari ini?','Untuk *Force Majeure* (sakit mendadak/musibah), kami berikan toleransi reschedule 1x tanpa denda, meski kurang dari 24 jam. Harap kirim bukti (surat dokter/foto) ke admin. Kami doakan lekas sembuh.','jadwal,ganti,sakit,batal',8,1,'2025-12-25 17:56:33','2025-12-25 17:56:33'),
(246,'admin','Telat Datang Sesi','Macet parah, saya telat 30 menit.','Waktu sesi Anda terhitung sesuai jadwal booking (karena ada klien lain setelah Anda). Jika telat 30 menit, maka sisa waktu terapi tinggal 90 menit (dari paket 2 jam). Kami akan maksimalkan sisa waktu yang ada. Harap spare waktu macet.','telat,macet,waktu,rugi',8,1,'2025-12-25 17:56:33','2025-12-25 17:56:33'),
(247,'admin','Parkir Kendaraan','Parkir di Albashiro aman/luas?','Kami menyediakan parkir luas untuk 5 mobil dan 20 motor. Keamanan dijaga satpam & CCTV 24 jam. Parkir Gratis (Free Valet jika penuh). Akses kursi roda juga tersedia dari parkiran ke ruang terapi.','parkir,mobil,motor,aman',7,1,'2025-12-25 17:56:33','2025-12-25 17:56:33'),
(248,'admin','Lokasi Cabang','Ada cabang di Jakarta Selatan/Surabaya?','Saat ini pusat Albashiro ada di [LOKASI UTAMA]. Kami sedang merintis cabang di kota-kota besar. Namun, layanan **Hipnoterapi Online** kami bisa menjangkau seluruh dunia dan terbukti sama efektifnya. Mau coba online dulu?','cabang,lokasi,kota,alamat',9,1,'2025-12-25 17:56:34','2025-12-25 17:56:34'),
(249,'admin','Franchise/Mitra','Bisa buka franchise Albashiro di kota saya?','Kami membuka peluang kemitraan \'Albashiro Point\' bagi psikolog/terapis bersertifikat. Sistem bagi hasil dan standarisasi SOP Islami yang ketat. Silakan kirim proposal ke email bisnis kami untuk dipelajari.','bisnis,mitra,buka,cabang',6,1,'2025-12-25 17:56:34','2025-12-25 17:56:34'),
(250,'admin','Lowongan Terapis','Lagi buka lowongan kerja terapis?','Kami selalu mencari talenta. Syarat: (1) Sertifikasi Hipnoterapi resmi (IBH/Nasional), (2) Paham psikologi Islam, (3) Bebas rokok/narkoba, (4) Lulus tes praktik & wawancara akhlak. Kirim CV ke email HRD kami.','loker,kerja,terapis,karir',7,1,'2025-12-25 17:56:34','2025-12-25 17:56:34'),
(251,'admin','Metode Pembayaran','Bisa bayar pakai Kartu Kredit/QRIS?','Bisa. Kami menerima Transfer Bank (BCA/Mandiri), QRIS (GoPay/OVO/Dana), dan Kartu Kredit (via link payment gateway). Pembayaran lunas atau DP 50% dilakukan sebelum sesi dimulai.','bayar,atm,kredit,qris',8,1,'2025-12-25 17:56:34','2025-12-25 17:56:34'),
(252,'admin','Bawa Anak Kecil','Saya terapi, anak gak ada yang jaga, boleh dibawa?','Jika anak masih balita, disarankan membawa pengasuh/orang lain untuk menjaga di ruang tunggu (ada area bermain anak). Anak tidak boleh masuk ruang terapi saat orang tua diterapi agar Anda bisa fokus total dan rileks tanpa gangguan suara anak.','anak,bawa,jaga,ruang',7,1,'2025-12-25 17:56:34','2025-12-25 17:56:34'),
(253,'admin','Kerahasiaan CCTV','Ada CCTV di ruang terapi? Aman privasi?','Ada CCTV HANYA visual (tanpa suara) yang mengarah ke pintu (bukan ke wajah klien close-up) demi keamanan standar medis & menghindari fitnah (khalwat). Rekaman dijaga super ketat oleh manajemen pusat dan otomatis terhapus tiap 30 hari.','cctv,kamera,rekam,aman',7,1,'2025-12-25 17:56:35','2025-12-25 17:56:35'),
(254,'admin','Bahasa Asing','Terapisnya bisa bahasa Inggris?','Ya, kami memiliki Senior Therapist yang fasih berbahasa Inggris (English Speaking Hypnotherapist) untuk ekspatriat atau klien internasional. Ada tambahan biaya 20% untuk sesi bahasa Inggris.','inggris,english,bule,bahasa',7,1,'2025-12-25 17:56:35','2025-12-25 17:56:35'),
(255,'admin','Paket Bundling Keluarga','Mau terapi sekeluarga (Ayah, Ibu, 2 Anak).','Ambil \'Family Harmony Package\'. Diskon 25% untuk 4 orang. Jadwal bisa diblokir seharian khusus untuk keluarga Anda (VIP). Kami kombinasi sesi individual dan sesi konseling keluarga bersama. Solusi tuntas satu rumah.','keluarga,paket,diskon,promo',8,1,'2025-12-25 17:56:35','2025-12-25 17:56:35'),
(256,'admin','Legalitas Klinik','Albashiro ini resmi ada izinnya?','Resmi. Albashiro berbadan hukum (PT/Yayasan) dan terdaftar di Dinas Kesehatan (STPT - Surat Terdaftar Penyehat Tradisional/Komplementer). Terapis kami juga anggota aktif organisasi profesi hipnoterapi nasional (IBH/PRAHIPTI). Aman dan legal.','izin,legal,resmi,dinkes',9,1,'2025-12-25 17:56:35','2025-12-25 17:56:35'),
(257,'admin','Terapis Wanita/Pria','Saya wanita mau terapis wanita saja, bisa?','Sangat bisa. Sesuai prinsip Syariah, kami utamakan klien wanita dengan terapis wanita (Ukhti), dan pria dengan pria (Akhi). Harap request saat booking agar disesuaikan jadwalnya.','wanita,pria,gender,muhrim',9,1,'2025-12-25 17:56:35','2025-12-25 17:56:35'),
(258,'admin','Konsultasi Gratis','Bisa tanya-tanya dulu gratis sebelum booking?','Bisa! Kami sediakan \'Free Discovery Call\' 15 menit via telepon/WA Call dengan admin/konsultan kami. Anda bisa curhat singkat untuk memastikan apakah hipnoterapi cocok untuk masalah Anda sebelum bayar.','gratis,tanya,telpon,konsul',9,1,'2025-12-25 17:56:36','2025-12-25 17:56:36'),
(259,'admin','Jaminan Kesembuhan','Kalau 10 sesi gak sembuh gimana?','Jika progres stagnan, kami akan lakukan \'Case Conference\' (diskusi tim ahli) untuk bedah kasus Anda. Mungkin perlu pendekatan lain atau rujukan ke Psikiater/Dokter (jika ada kelainan organik). Kami tidak akan membiarkan Anda terkatung-katung tanpa solusi.','gagal,sembuh,jamin,rugi',8,1,'2025-12-25 17:56:36','2025-12-25 17:56:36'),
(260,'admin','Hipnoterapi vs Gendam','Apa bedanya sama gendam di jalanan?','Beda total. Gendam pakai *Shock Induction* (kaget) dan niat jahat. Hipnoterapi pakai *Relaxation* (izin) dan niat mulia. Gendam membuat linglung, Hipnoterapi membuat fokus dan berdaya. Di sini Anda aman.','gendam,beda,jahat,sihir',9,1,'2025-12-25 17:56:36','2025-12-25 17:56:36'),
(261,'admin','Ruangan Dingin/AC','Saya gak kuat dingin AC.','Ruangan kami full AC demi kenyamanan alat dan kedap suara. TAPI, kami sediakan selimut tebal yang nyaman. Anda juga bisa minta terapis menaikkan suhu AC. Kenyamanan fisik Anda adalah prioritas agar bisa trance.','ac,dingin,selimut,suhu',6,1,'2025-12-25 17:56:36','2025-12-25 17:56:36'),
(262,'admin','Toilet/Musholla','Ada tempat sholat?','Ada Musholla bersih terpisah (Ikhwan/Akhwat) lengkap dengan alat sholat. Toilet juga bersih standar hotel. Anda bisa sholat dulu sebelum terapi agar hati lebih tenang.','sholat,musholla,wudhu,wc',7,1,'2025-12-25 17:56:37','2025-12-25 17:56:37'),
(263,'admin','Aftercare Support','Habis terapi kalau bingung tanya siapa?','Kami punya layanan \'WA Support\' selama 7 hari pasca sesi. Anda bisa chat terapis Anda (via admin) jika ada sensasi fisik/emosi yang membingungkan. Kami akan pandu Anda masa integrasi ini.','tanya,chat,wa,dukung',8,1,'2025-12-25 17:56:37','2025-12-25 17:56:37'),
(264,'admin','Media Sosial','IG/TikTok Albashiro apa?','Follow @AlbashiroTherapy di IG dan TikTok. Banyak tips kesehatan mental Islami, video relaksasi 1 menit, dan info promo terbaru. DM kami sering balas lho!','ig,sosmed,tiktok,follow',7,1,'2025-12-25 17:56:37','2025-12-25 17:56:37'),
(265,'admin','Usia Minimal','Anak paling kecil umur berapa bisa terapi?','Idealnya mulai usia 5 tahun (sudah lancar bicara/komunikasi dua arah). Di bawah 5 tahun, kami terapi ORANG TUANYA (Hypnoparenting), karena emosi anak balita 90% menyerap emosi ibunya. Ibu tenang, anak tenang.','umur,kecil,bayi,minimal',8,1,'2025-12-25 17:56:37','2025-12-25 17:56:37'),
(266,'admin','Disabilitas/Tuna Netra','Saya tunanetra, bisa terapi?','Bisa sekali. Hipnoterapi berbasis Auditori (suara) dan Kinestetik (rasa). Saudara tunanetra sangat peka pendengarannya sehingga seringkali lebih cepat masuk kondisi trance yang dalam dan efektif. Kami siap memandu mobilitas Anda di klinik.','buta,netra,disabilitas,bisa',8,1,'2025-12-25 17:56:37','2025-12-25 17:56:37'),
(267,'admin','Pasien Skizofrenia','Kakak saya ODGJ/Skizofrenia (halusinasi), bisa?','Mohon maaf, untuk Skizofrenia/Bipolar fase manik/Psikosis (lepas realita), hipnoterapi KONTRADIKSI (tidak disarankan). Ranahnya Psikiater (obat). Kami hanya bisa bantu keluarganya (Caregiver) untuk mengelola stres mengurus pasien.','gila,odgj,skizo,berat',9,1,'2025-12-25 17:56:38','2025-12-25 17:56:38'),
(268,'admin','Kejang/Epilepsi','Saya punya riwayat ayan/epilepsi.','Wajib lapor saat anamnesis. Kami akan hindari teknik \'Shock Induction\' atau lampu strobo/visualisasi kedip cepat. Kami gunakan induksi relaksasi lambat (Maternal) yang aman untuk saraf otak Anda.','ayan,epilepsi,kejang,sakit',9,1,'2025-12-25 17:56:38','2025-12-25 17:56:38'),
(269,'admin','Makan Sebelum Sesi','Harus puasa sebelum terapi?','JANGAN puasa. Makanlah secukupnya 1 jam sebelum sesi. Kalau perut kosong, asam lambung naik bikin gak fokus. Kalau kekenyangan, malah ngantuk berat (bukan trance). Makan normal saja.','makan,puasa,lapar,siap',7,1,'2025-12-25 17:56:38','2025-12-25 17:56:38'),
(270,'admin','Bawa Rekam Medis','Perlu bawa hasil lab/diagnosa dokter?','Sangat membantu! Jika masalah Anda fisik (psikosomatis), tolong bawa hasil lab/surat dokter yang menyatakan \'Fisik Normal/Sehat\'. Ini meyakinkan bawah sadar bahwa sakitnya murni pikiran, sehingga terapi lebih cepat tembus.','dokter,lab,surat,bawa',8,1,'2025-12-25 17:56:38','2025-12-25 17:56:38'),
(271,'admin','Pakaian','Harus pakai baju putih/tertentu?','Bebas, yang penting sopan, menutup aurat (sesuai syariah), dan NYAMAN. Hindari jeans ketat atau ikat pinggang kencang yang menekan perut. Kita akan banyak duduk/berbaring rileks.','baju,pakaian,celana,ketat',7,1,'2025-12-25 17:56:38','2025-12-25 17:56:38'),
(272,'category','topic','question','answer','keywords',0,1,'2025-12-25 17:56:39','2025-12-25 17:56:39'),
(273,'emotions','Rasa Malu (Shame)','Saya punya aib masa lalu yang bikin malu banget sampai sekarang.','Shame (rasa malu) adalah emosi yang paling merusak karena menyerang identitas (\'Saya produk gagal\'). Di Albashiro, kami bedakan antara \'Guilt\' (Saya berbuat salah) dan \'Shame\' (Saya salah). Kami bantu Anda memisahkan perilaku buruk masa lalu dari diri Anda yang berharga saat ini. Aib ditutup rapat, hati dibersihkan.','malu,aib,hina,kotor',9,1,'2025-12-25 17:56:39','2025-12-25 17:56:39'),
(274,'emotions','Rasa Bersalah (Guilt)','Merasa bersalah terus karena dulu kurang baik sama almarhum orang tua.','Unfinished Business. Rasa bersalah pada yang sudah meninggal sangat menyiksa. Kami gunakan teknik \'Chair Therapy\' atau visualisasi roh. Anda akan berdialog, meminta maaf, dan \'mendengar\' jawaban memaafkan dari mereka di alam bawah sadar. Ini memberikan rasa lega (closure) yang luar biasa.','salah,dosa,nyesal,ortu',9,1,'2025-12-25 17:56:39','2025-12-25 17:56:39'),
(275,'emotions','Kesepian (Loneliness)','Punya banyak teman tapi merasa sepi banget di hati.','Ini \'Existential Loneliness\'. Merasa tidak terkoneksi. Kami bantu Anda membangun koneksi dengan Diri Sendiri (Self-Connection) dan Allah. Saat Anda nyaman dengan diri sendiri, rasa sepi berubah menjadi \'Solitude\' (Kesendirian yang Nikmat). Anda tidak lagi butuh keramaian untuk merasa hidup.','sepi,sendiri,kosong,hampa',8,1,'2025-12-25 17:56:39','2025-12-25 17:56:39'),
(276,'emotions','Iri Hati (Envy/Hasad)','Suka sakit hati kalau lihat teman sukses di IG.','Social Media Envy. Kami reframe: \'Kesuksesan orang lain adalah bukti bahwa sukses itu MUNGKIN, termasuk buat saya\'. Kami ubah energi Iri (mengapa dia?) menjadi Inspirasi (bagaimana caranya?). Hati lebih adem, rezeki lebih mudah mendekat.','iri,dengki,julid,panas',8,1,'2025-12-25 17:56:39','2025-12-25 17:56:39'),
(277,'emotions','Apathy (Mati Rasa)','Gak sedih gak senang, datar aja rasanya hidup ini.','Emotional Numbness adalah mekanisme pertahanan karena pernah sakit terlalu dalam. Hati \'mematikan saklar\' biar gak sakit, tapi jadinya gak bisa bahagia juga. Kami nyalakan lagi saklar perasaan itu perlahan-lahan dalam zona aman, supaya hidup kembali berwarna.','datar,bosan,hambar,rasa',8,1,'2025-12-25 17:56:40','2025-12-25 17:56:40'),
(278,'emotions','Rasa Ditolak (Rejection)','Sering ditolak (kerja/cinta), jadi merasa gak berharga.','Luka penolakan mengaktifkan area otak yang sama dengan nyeri fisik. Kami sembuhkan \'Luka Batin\' ini. Kami tanamkan belief: \'Ditolak itu diselamatkan dari yang tidak cocok\'. Self-worth Anda dibangun dari dalam, bukan dari penerimaan orang lain.','tolak,gagal,sakit,sedih',8,1,'2025-12-25 17:56:40','2025-12-25 17:56:40'),
(279,'emotions','Kewalahan (Overwhelmed)','Kepala mau pecah, terlalu banyak masalah datang barengan.','Mental Congestion. Ibarat komputer kebanyakan buka tab. Kami ajak Anda \'Defrag\' otak. Memilah masalah: Mana yang bisa dikontrol, mana yang harus dilepas. Teknik relaksasi napas dalam 5 menit bisa menurunkan level kortisol instan agar bisa berpikir jernih lagi.','pusing,stres,pecah,banyak',9,1,'2025-12-25 17:56:40','2025-12-25 17:56:40'),
(280,'emotions','Rindu Mantan (Limerence)','Obsesi mikirin mantan padahal dia udah nikah.','Limerence bukan cinta, tapi kecanduan dopamin dari fantasi. Kami putus suplai \'narkoba emosi\' ini. Kami hancurkan idealisasi sosok mantan (membuatnya terlihat biasa saja/banyak kurangnya). Fokus energi ditarik kembali untuk mencintai diri sendiri.','mantan,rindu,kangen,gamon',8,1,'2025-12-25 17:56:40','2025-12-25 17:56:40'),
(281,'emotions','Takut Diabai (Abandonment)','Takut banget ditinggal pasangan, jadi nempel terus (Clingy).','Abandonment Issue biasanya dari masa kecil (sering ditinggal ortu kerja/cerai). Kami penuhi tangki kasih sayang \'Inner Child\' Anda. Saat anak kecil di dalam diri Anda merasa aman, Anda yang dewasa tidak akan lagi posesif atau takut sendirian.','tinggal,pisah,takut,sendiri',9,1,'2025-12-25 17:56:40','2025-12-25 17:56:40'),
(282,'life_events','Quarter Life Crisis','Umur 25 tahun, teman udah nikah/sukses, saya gini-gini aja.','Fase wajar mencari jati diri. Jangan bandingkan \'Behind the scene\' Anda dengan \'Highlight reel\' orang lain. Kami bantu temukan \'Ikigai\' (Tujuan Hidup) Anda. Fokus pada progress diri sendiri sekecil apapun. Crisis diubah menjadi Awakening (Kebangkitan).','umur 25,bingung,krisis,gagal',8,1,'2025-12-25 17:56:41','2025-12-25 17:56:41'),
(283,'life_events','Mid-Life Crisis','Umur 40, karir mapan tapi kok hampa? Pengen selingkuh/aneh-aneh.','Panggilan jiwa untuk makna yang lebih dalam. Daripada lari ke hal destruktif (selingkuh/beli moge boros), kami arahkan energi ini untuk \'Spiritual Growth\' atau kontribusi sosial. Menemukan misi hidup paruh kedua yang lebih memuaskan batin.','umur 40,tua,bosan,nakal',8,1,'2025-12-25 17:56:41','2025-12-25 17:56:41'),
(284,'life_events','Sindrom Sarang Kosong','Anak-anak sudah nikah semua, rumah sepi, ibu sedih.','Empty Nest Syndrome. Ibu kehilangan peran utamanya. Kami bantu Ibu menemukan hobi baru atau peran baru (misal: nenek yang asik, atau aktif sosial). Menggeser fokus dari \'Mengurus Anak\' menjadi \'Menikmati Masa Tua\' bersama suami atau teman.','sepi,anak,nikah,pergi',7,1,'2025-12-25 17:56:41','2025-12-25 17:56:41'),
(285,'life_events','Persiapan Pernikahan (Wedding Jitters)','Mau nikah minggu depan tapi panik, ragu, pengen kabur.','Cold Feet wajar. Cemas menghadapi perubahan status besar. Kami relaksasi saraf yang tegang. Visualisasi hari H berjalan lancar dan indah. Kami kuatkan alasan (Big Why) Anda memilih dia, menenggelamkan keraguan sesaat.','nikah,ragu,panik,kawin',8,1,'2025-12-25 17:56:41','2025-12-25 17:56:41'),
(286,'life_events','Baby Blues Prevention','Takut kena baby blues nanti pas lahiran.','Pencegahan lebih baik. Kami siapkan mental ibu hamil. Edukasi bawah sadar bahwa \'Ibu tidak harus sempurna, cukup ibu yang bahagia\'. Kami tanamkan anchor ketenangan saat mendengar tangisan bayi, agar tidak memicu stres tapi memicu kasih sayang.','bayi,blues,sedih,hamil',8,1,'2025-12-25 17:56:42','2025-12-25 17:56:42'),
(287,'life_events','Pindah Rumah/Kota','Stres adaptasi di lingkungan baru, gak betah.','Homesick dan Culture Shock. Kami percepat adaptasi mental. Visualisasi membuat \'Jalur Neural\' baru bahwa tempat baru ini aman dan nyaman. Menemukan hal-hal positif di kota baru untuk disyukuri.','pindah,rumah,asing,betah',7,1,'2025-12-25 17:56:42','2025-12-25 17:56:42'),
(288,'life_events','Baru Bercerai','Dunia runtuh setelah ketuk palu cerai.','Fase transisi berat. Kami bantu stabilisasi emosi. Melepaskan identitas \'Istri/Suami\' menjadi \'Individu Merdeka\'. Menyusun ulang kepingan hidup satu per satu. Membangun harapan baru bahwa hidup belum berakhir, justru babak baru dimulai.','cerai,pisah,duda,janda',9,1,'2025-12-25 17:56:42','2025-12-25 17:56:42'),
(289,'life_events','Pensiun Dini (Early Retirement)','Ambil pensiun dini tapi takut nyesel/bosan.','Persiapan mental \'Post-Corporate Life\'. Mendefinisikan ulang produktivitas. Kami bantu Anda merancang visi masa pensiun yang aktif (bukan cuma duduk diam). Menyiapkan mental entrepreneur atau investor agar uang pesangon aman.','pensiun,kerja,dini,bosan',7,1,'2025-12-25 17:56:42','2025-12-25 17:56:42'),
(290,'life_events','Kematian Hewan Peliharaan','Sedih banget kucing mati, orang bilang \'lebay\'.','Pet Grief itu nyata dan sakit. Kami validasi kesedihan Anda. Terapi \'Jembatan Pelangi\': Mengikhlaskan hewan kesayangan, berterima kasih atas kebahagiaan yang pernah diberi. Rasa sakit diganti dengan kenangan manis yang menghangatkan hati.','kucing,anjing,mati,sedih',7,1,'2025-12-25 17:56:42','2025-12-25 17:56:42'),
(291,'professions','Trader (Crypto/Saham)','Stres lihat chart merah, FOMO, Cut Loss terus.','Psikologi Trading adalah 80% kunci sukses. Kami atasi \'Revenge Trading\' (balas dendam saat rugi) dan FOMO. Kami latih mental \'Disiplin Dingin\'. Masuk pasar hanya saat sinyal valid, bukan karena emosi. Tidur nyenyak meski market crash.','saham,crypto,rugi,stres',9,1,'2025-12-25 17:56:43','2025-12-25 17:56:43'),
(292,'professions','Programmer (Imposter Syndrome)','Merasa gak jago coding, takut ketahuan bodoh sama tim.','Imposter Syndrome umum di tech industry. Kami reframe: \'Anda di sini karena skill Anda, bukan keberuntungan\'. Kami kurangi perfeksionisme. Error/Bug dimaknai sebagai tantangan logika, bukan kebodohan pribadi.','coding,dev,bodoh,palsu',8,1,'2025-12-25 17:56:43','2025-12-25 17:56:43'),
(293,'professions','Supir/Ojol (Road Rage)','Gampang emosi di jalan, sering maki-maki orang nyetir.','Jalanan adalah trigger stres. Road Rage berbahaya. Kami pasang \'Cooling Anchor\' di setir. Saat ada yang nyalip ngawur, respon otomatis Anda adalah \'Sabar, mungkin dia kebelet\', bukan marah. Hati tenang, selamat sampai tujuan.','supir,ojol,marah,jalan',8,1,'2025-12-25 17:56:43','2025-12-25 17:56:43'),
(294,'professions','Guru TK/SD (Sabar)','Habis kesabaran ngadepin murid zaman now yang aktif banget.','Guru adalah profesi emosional. Kami \'Recharge\' tangki sabar Anda. Teknik \'Bubble of Peace\': Membayangkan Anda dalam gelembung kaca yang kedap suara bising, sehingga teriakan anak-anak tidak menusuk saraf, tapi terdengar seperti musik latar.','guru,murid,nakal,sabar',8,1,'2025-12-25 17:56:43','2025-12-25 17:56:43'),
(295,'professions','Content Creator (Burnout)','Dikejar algoritma tiap hari, harus upload terus, capek.','Creator Burnout. Kami bantu set \'Boundaries\'. Memisahkan Nilai Diri dari Jumlah Views/Likes. Mengembalikan kesenangan berkarya (Joy of Creation). Istirahat mental tanpa rasa bersalah (FOMO) agar kreativitas pulih.','konten,youtube,tiktok,capek',8,1,'2025-12-25 17:56:43','2025-12-25 17:56:43'),
(296,'professions','HRD (Tega Pecat Orang)','Stres harus PHK massal karyawan, gak tega sampai gak bisa tidur.','Beban moral eksekutor. Kami bantu Anda memisahkan \'Peran Profesional\' dan \'Pribadi\'. Anda menjalankan tugas perusahaan demi kelangsungan banyak orang lain. Emosi rasa bersalah divalidasi lalu dilepaskan. Teknik perlindungan energi agar tidak menyerap kesedihan karyawan yang di-PHK.','hrd,phk,pecat,sedih',8,1,'2025-12-25 17:56:44','2025-12-25 17:56:44'),
(297,'professions','Polisi/Tentara (PTSD)','Pernah tugas di daerah konflik, sering kaget suara keras.','Combat PTSD. Suara petasan dikira tembakan. Kami gunakan teknik khusus (seperti RTM - Reconsolidation of Traumatic Memories) untuk memisahkan memori dari respon emosi tubuh. Memori tetap ada, tapi rasanya netral, tidak lagi memicu adrenalin/keringat dingin.','perang,tugas,trauma,kaget',9,1,'2025-12-25 17:56:44','2025-12-25 17:56:44'),
(298,'professions','Artis/Public Figure','Takut kehilangan popularitas, takut dibenci netizen.','Fame Anxiety. Harga diri tergantung komentar orang. Kami kembalikan pondasi ke \'Inner Worth\'. Komentar jahat netizen dibayangkan seperti sampah digital yang langsung di-delete mental. Kebahagiaan dicari di dunia nyata, bukan di notifikasi HP.','artis,netizen,hujat,takut',8,1,'2025-12-25 17:56:44','2025-12-25 17:56:44'),
(299,'professions','Mahasiswa Kedokteran (Koas)','Stres jaga malam, dibentak konsulen, pengen berhenti.','Tekanan mental pendidikan dokter sangat tinggi. Kami kuatkan mental baja. \'Bentakan Konsulen\' dimaknai sebagai \'Ujian Mental\', bukan serangan pribadi. Anchor semangat \'Jas Putih\' diperkuat untuk mengingat tujuan mulia menyembuhkan orang.','dokter,koas,jaga,stres',8,1,'2025-12-25 17:56:44','2025-12-25 17:56:44'),
(300,'islamic_adv','Konsep Ridho','Gimana caranya Ridho sama ketentuan Allah yang pahit?','Ridho itu level di atas Sabar. Sabar = Menahan sakit. Ridho = Menerima dengan lapang dada. Kami gunakan metafora: \'Seperti minum obat pahit dari Dokter yang sangat sayang pada kita (Allah)\'. Pahitnya terasa, tapi kita tahu ini menyembuhkan. Terapi membuka dada untuk menerima takdir.','ridho,takdir,ikhlas,allah',9,1,'2025-12-25 17:56:44','2025-12-25 17:56:44'),
(301,'islamic_adv','Konsep Tawakkal Praktis','Saya tawakkal tapi kok masih cemas besok makan apa?','Tawakkal itu perbuatan Hati, Ikhtiar perbuatan Badan. Kalau masih cemas, berarti hatinya belum \'Bersandar\'. Kami latih visualisasi: Anda sudah melakukan 100% usaha, lalu hasil akhirnya Anda letakkan di dalam kotak emas, lalu kotak itu Anda serahkan ke tangan Allah. Rasakan beban di pundak hilang saat kotak itu berpindah tangan.','tawakkal,cemas,rezeki,pasrah',9,1,'2025-12-25 17:56:45','2025-12-25 17:56:45'),
(302,'islamic_adv','Gangguan Ain (Mata Jahat)','Takut kena Ain kalau posting foto anak.','Ain itu benar (Haq). Tapi takut berlebihan itu was-was. Solusinya: (1) Bentengi dengan doa, (2) Luruskan niat posting (bukan pamer), (3) Posting sekadarnya. Kami hilangkan paranoia. Keyakinan bahwa \'Pelindung (Allah) lebih kuat dari Pengganggu (Ain)\' ditanamkan kuat.','ain,pamer,sakit,takut',8,1,'2025-12-25 17:56:45','2025-12-25 17:56:45'),
(303,'islamic_adv','Memaafkan Orang Tua (Birrul Walidain)','Ortu saya toxic, dosa gak kalau saya jaga jarak?','Birrul Walidain (berbakti) tidak berarti harus membiarkan diri disakiti fisik/mental. Kami bantu Anda memaafkan jiwa mereka (yang mungkin juga terluka), sambil tetap menjaga batasan fisik (boundaries) yang sehat demi kewarasan. Berbakti bisa lewat doa jarak jauh dan kiriman materi, tanpa harus serumah jika membahayakan mental.','ortu,durhaka,benci,maaf',9,1,'2025-12-25 17:56:45','2025-12-25 17:56:45'),
(304,'islamic_adv','Khusyu\' Zakat/Sedekah','Masih berat keluarin sedekah, takut uang habis.','Scarcity Mindset. Kami ubah jadi Abundance. Sedekah itu \'Memancing Rezeki\', bukan membuang uang. Visualisasi: Seperti petani menebar benih. Benih hilang dari tangan, tapi akan tumbuh jadi pohon lebat. Rasa bahagia saat memberi (Giving Glow) diaktifkan.','sedekah,pelit,uang,zakat',8,1,'2025-12-25 17:56:45','2025-12-25 17:56:45'),
(305,'islamic_adv','Persiapan Haji/Umrah','Takut meninggal di Tanah Suci karena banyak dosa.','Ketakutan ini tanda hati yang hidup (takut azab). Kami ubah jadi energi tobat. Tanah Suci adalah tanah Rahmat. Tamu Allah pasti dimuliakan, bukan disiksa. Kami persiapkan mental \'Tamu Agung\' yang rindu bertemu Tuan Rumahnya, bukan terpidana yang mau dihukum.','haji,umrah,mekkah,mati',8,1,'2025-12-25 17:56:46','2025-12-25 17:56:46'),
(306,'hypno_tech','Gelombang Otak (Brainwave)','Apa itu Alpha dan Theta? Kok sering disebut.','Otak punya gigi persneling. Beta = Sadar/Sibuk (Gigi 1-2). Alpha = Rileks/Melamun (Gigi 3-4). Theta = Sangat Dalam/Mimpi (Gigi 5). Hipnoterapi memindahkan gigi otak Anda ke Alpha/Theta. Di frekuensi ini, \'Filter Kritis\' terbuka, jadi kita bisa edit file (kebiasaan/emosi) dengan mudah.','otak,gelombang,alpha,theta',7,1,'2025-12-25 17:56:46','2025-12-25 17:56:46'),
(307,'hypno_tech','Critical Factor','Apa itu Critical Factor yang ditembus hipnotis?','Critical Factor itu \'Satpam\' di otak yang memfilter informasi. Dia yang bilang \'Ah masa sih?\', \'Gak mungkin\'. Saat hipnosis, Satpam ini kita suruh \'ngopi dulu\' (istirahat). Jadi sugesti positif \'Kamu Percaya Diri\' bisa langsung masuk ke ruang bos (Bawah Sadar) tanpa dicegah Satpam.','kritis,pikiran,filter,masuk',7,1,'2025-12-25 17:56:46','2025-12-25 17:56:46'),
(308,'hypno_tech','Submodality','Gimana caranya mengubah perasaan lewat pikiran?','Otak menyimpan memori dalam kode gambar/suara (Submodality). Memori sedih biasanya gambarnya besar, gelap, dekat. Kami ubah kodenya: Gambar sedih itu kita \'Edit\' jadi kecil, hitam-putih, dan dijauhkan ke ujung horizon. Otomatis, perasaan sedihnya ikut hilang. Seperti edit foto di Photoshop mental.','edit,memori,gambar,rasa',8,1,'2025-12-25 17:56:46','2025-12-25 17:56:46'),
(309,'hypno_tech','Anchor (Jangkar Emosi)','Apa itu Anchor? Katanya bisa bikin tenang instan.','Anchor itu tombol pemicu. Contoh: Dengar lagu lama langsung ingat mantan (itu anchor alami). Di terapi, kita BUAT anchor baru. Misal: Saat Anda merasa sangat rileks, kami minta Anda tekan jempol. Otak merekam: \'Tekan Jempol = Rileks\'. Nanti di rumah, saat stres, tekan jempol saja, otomatis rileks muncul.','anchor,tombol,pemicu,tenang',8,1,'2025-12-25 17:56:46','2025-12-25 17:56:46'),
(310,'hypno_tech','Ideomotor Response','Bisa gak ngobrol sama bawah sadar tanpa ngomong?','Bisa, lewat Ideomotor. Kita minta Bawah Sadar gerakkan jari. \'Kalau Ya, gerakkan telunjuk kanan. Kalau Tidak, telunjuk kiri\'. Ini teknik canggih untuk tanya jawab jujur dengan batin saat mulut susah berkata-kata. Jari akan bergerak sendiri di luar kendali sadar Anda.','jari,gerak,tanya,jawab',7,1,'2025-12-25 17:56:47','2025-12-25 17:56:47'),
(311,'parenting_adv','Single Parent (Ayah/Ibu)','Capek jadi Single Mom, harus jadi ayah sekaligus ibu.','Peran ganda itu berat tapi mulia. Kami kuatkan pundak Anda. Anda tidak perlu jadi Superwoman. Kami bantu Anda delegasi, meminta tolong, dan \'memaafkan diri\' jika rumah berantakan sedikit. Fokus pada kualitas hubungan dengan anak, bukan kesempurnaan rumah tangga.','single,janda,duda,anak',8,1,'2025-12-25 17:56:47','2025-12-25 17:56:47'),
(312,'parenting_adv','Co-Parenting (Cerai)','Susah kompak sama mantan suami buat urus anak.','Ego mantan pasangan sering menghalangi. Kami bantu Anda \'Menetralisir Emosi\' pada mantan. Lihat dia hanya sebagai \'Ayah/Ibu dari anakku\', bukan sebagai \'Mantan yang menyebalkan\'. Fokus komunikasi transaksional hanya soal anak. Emosi Anda stabil, anak pun aman.','cerai,anak,mantan,asuh',8,1,'2025-12-25 17:56:47','2025-12-25 17:56:47'),
(313,'parenting_adv','Anak Tantrum di Mall','Malu banget anak guling-guling di mall minta mainan.','Tantrum adalah badai emosi anak, jangan ikut badai. Kami latih Ibu punya \'Tombol Mute\' mental terhadap tatapan orang lain. Fokus hanya menenangkan anak (dipeluk/didiamkan aman). Saat Ibu tenang (Alpha state), frekuensi tenang itu menular ke anak (Resonansi Limbik), anak lebih cepat diam.','tantrum,nangis,mall,malu',8,1,'2025-12-25 17:56:47','2025-12-25 17:56:47'),
(314,'parenting_adv','Anak Introvert vs Ortu Ekstrovert','Saya gemes anak saya pendiam banget, gak gaul.','Beda kepribadian bukan kekurangan. Jangan paksa anak jadi Anda. Kami bantu Anda memahami kekuatan Introvert (fokus, dalam, pendengar baik). Stop label \'Pemalu\', ganti dengan \'Pengamat\'. Terima anak apa adanya, dia akan mekar dengan caranya sendiri.','diam,gaul,malu,anak',7,1,'2025-12-25 17:56:47','2025-12-25 17:56:47'),
(315,'parenting_adv','Seks Edukasi Anak','Bingung jelasin seks/pubertas ke anak, tabu.','Hambatan budaya/mental. Kami hilangkan rasa risih/tabu. Seks edukasi adalah benteng agar anak tidak cari tahu di bokep. Kami berikan skrip mental cara bicara santai tapi tegas sesuai usia/syariat. Orang tua harus jadi sumber informasi pertama dan terpercaya.','seks,anak,tabu,edukasi',8,1,'2025-12-25 17:56:48','2025-12-25 17:56:48'),
(316,'parenting_adv','Anak Gak Mau Ibadah','Anak remaja susah disuruh sholat, harus dibentak.','Bentakan membuat sholat diasosiasikan dengan \'Marah\'. Kami ubah strateginya. Hypnoparenting saat anak tidur (Sleep Hypnosis): Bisikkan doa dan sugesti cinta pada Allah di telinganya. Siang hari, jadilah teladan yang menikmati sholat, bukan sholat beban. Dakwah lisan < Dakwah perbuatan.','sholat,malas,anak,nakal',8,1,'2025-12-25 17:56:48','2025-12-25 17:56:48'),
(317,'lifestyle','Diet Mindful','Saya makan sehat seminggu, terus balas dendam junkfood.','Siklus Yo-Yo Diet. Karena merasa \'Dikekang\'. Mindful Eating tidak melarang, tapi sadar. \'Apakah tubuhku butuh gorengan ini?\'. Kami latih Anda menghargai tubuh seperti bait Allah. Anda akan menolak junkfood bukan karena aturan diet, tapi karena rasa sayang pada organ tubuh sendiri.','diet,gemuk,makan,sehat',8,1,'2025-12-25 17:56:48','2025-12-25 17:56:48'),
(318,'lifestyle','Digital Minimalism','Merasa otak penuh sampah informasi, susah fokus (Brain Fog).','Information Overload. Kami pandu \'Digital Detox\'. Memprogram rasa \'Jijik/Muak\' pada konten sampah/gosip. Mengembalikan kenikmatan membaca buku fisik atau melihat alam. Otak yang bersih dari sampah digital akan tajam kembali.','hp,fokus,lemot,detox',8,1,'2025-12-25 17:56:48','2025-12-25 17:56:48'),
(319,'lifestyle','Decluttering Mental','Rumah penuh barang gak kepakai, susah buang (Hoarding).','Hoarding adalah ketakutan melepaskan masa lalu atau takut kekurangan di masa depan. Kami atasi \'Attachment\' pada benda. \'Kenangan ada di hati, bukan di barang rongsokan\'. Belajar melepas barang adalah latihan melepas beban emosi. Rumah lapang, hati lapang.','barang,sampah,buang,timbun',7,1,'2025-12-25 17:56:48','2025-12-25 17:56:48'),
(320,'lifestyle','Bangun Habit Olahraga','Daftar gym setahun, datang cuma 2x.','Motivasi saja tidak cukup. Kami bangun \'Identitas Baru\'. Bukan \'Saya mau olahraga\', tapi \'Saya adalah Atlet\'. Atlet otomatis olahraga. Kami kaitkan olahraga dengan \'Rasa Senang\' (Endorfin), bukan \'Rasa Capek\'.','gym,olahraga,malas,kurus',8,1,'2025-12-25 17:56:49','2025-12-25 17:56:49'),
(321,'lifestyle','Slow Living','Hidup di kota besar serba buru-buru, napas aja susah.','Hurry Sickness. Kami install \'Mode Desa\' di tengah kota. Mengajarkan teknik \'Micro-Break\'. Berhenti 1 menit tiap jam untuk napas sadar. Menikmati teh dengan pelan. Menurunkan tempo internal meski dunia eksternal cepat. Stres turun drastis.','cepat,buru,santai,kota',7,1,'2025-12-25 17:56:49','2025-12-25 17:56:49'),
(322,'lifestyle','Self-Love (Fisik)','Benci lihat cermin, merasa jelek/gemuk.','Body Image Issue. Kami rekonsiliasi Anda dengan cermin. Latihan \'Mirror Work\': Menatap mata sendiri dan berkata \'Aku sayang kamu\'. Mencari 1 bagian tubuh yang disyukuri (misal: mata sehat). Menerima tubuh sebagai kendaraan jiwa yang setia, bukan objek pameran.','cermin,jelek,gemuk,benci',8,1,'2025-12-25 17:56:49','2025-12-25 17:56:49'),
(323,'conditions','Hipnoterapi Kanker (Psycho-Oncology)','Saya divonis kanker, drop banget mentalnya.','Diagnosis kanker adalah trauma besar. Kami bantu (1) Menerima diagnosis dengan ikhlas (bukan menyerah), (2) Visualisasi sel imun (seperti tentara) memakan sel kanker, (3) Mengelola efek samping kemoterapi (mual/nyeri). Semangat hidup yang tinggi terbukti meningkatkan efektivitas pengobatan medis.','kanker,tumor,sakit,vonis',9,1,'2025-12-25 17:56:49','2025-12-25 17:56:49'),
(324,'conditions','Stroke Recovery','Pasca stroke tangan susah gerak, mau nyerah.','Neuroplasticity (plastisitas otak) itu nyata. Lewat hipnosis, kita latih otak \'membayangkan\' tangan bergerak. Imajinasi yang kuat menstimulasi jalur saraf baru untuk menggantikan saraf yang rusak. Mental semangat latihan fisik dibangkitkan lagi.','stroke,lumpuh,gerak,sembuh',8,1,'2025-12-25 17:56:49','2025-12-25 17:56:49'),
(325,'conditions','Autoimun (Lupus/Gerd)','Penyakit autoimun kambuh kalau stres.','Autoimun adalah tubuh menyerang diri sendiri (simbol konflik batin/menyalahkan diri). Kami lakukan \'Peace Treaty\' (perjanjian damai) dengan tubuh. Meredakan perang batin. Mengurangi inflamasi lewat relaksasi deep trance.','autoimun,lupus,sakit,kambuh',8,1,'2025-12-25 17:56:50','2025-12-25 17:56:50'),
(326,'conditions','Gagap Bicara (Stuttering)','Gagap kalau ngomong sama atasan doang.','Contextual Stuttering. Artinya alat bicara Anda normal, mentalnya yang \'macet\'. Kami cari akar ketakutan pada otoritas (atasan/ayah?). Kami latih bicara lancar dalam imajinasi sampai saraf bicara terbiasa rileks di depan siapapun.','gagap,bicara,bata,bos',7,1,'2025-12-25 17:56:50','2025-12-25 17:56:50'),
(327,'conditions','Kebas Emosi (Dissociation)','Sering merasa kayak robot, badan di sini pikiran melayang.','Disosiasi adalah mekanisme kabur dari realita yang menyakitkan. Kami ajak Anda \'Grounding\'. Kembali masuk ke tubuh dengan aman. Merasakan napas, merasakan kaki injak lantai. Meyakinkan bawah sadar bahwa \'Sekarang sudah aman\', tidak perlu kabur lagi.','robot,kosong,layang,linglung',8,1,'2025-12-25 17:56:50','2025-12-25 17:56:50'),
(328,'faq_general','Hipnoterapi via Chat/Text','Bisa terapi lewat chat WA aja? Saya malu telepon.','Hipnoterapi butuh *Real Time Guidance* lewat suara (nada/intonasi terapis itu memandu gelombang otak). Lewat chat teks TIDAK EFEKTIF untuk terapi (hanya bisa konseling/curhat). Minimal Voice Call/Telepon. Kalau malu video, matikan saja kameranya, yang penting suara lancar.','chat,wa,teks,malu',8,1,'2025-12-25 17:56:50','2025-12-25 17:56:50'),
(329,'faq_general','Rekaman MP3 Saja','Jual rekaman audionya aja gak? Gak sempat sesi.','Kami punya produk \'Albashiro Audio Therapy\' untuk masalah umum (Insomnia, Relaksasi, Fokus). TAPI untuk masalah spesifik/berat (Trauma, Depresi), audio umum tidak cukup. Perlu sesi personal untuk bedah akarnya. Audio hanya suplemen, Sesi adalah obat utamanya.','mp3,audio,rekaman,beli',7,1,'2025-12-25 17:56:50','2025-12-25 17:56:50'),
(330,'faq_general','Bisa Gagal?','Apa penyebab hipnoterapi gagal?','Biasanya karena: (1) Klien tidak jujur/tertutup, (2) Klien datang karena dipaksa orang lain (tidak niat sendiri), (3) Klien pasif (berharap di-\'magic\' sembuh tanpa usaha mental), (4) Tidak mengerjakan PR (latihan di rumah). Kerjasama 50:50 adalah kunci.','gagal,rugi,bisa,efektif',8,1,'2025-12-25 17:56:51','2025-12-25 17:56:51'),
(331,'faq_general','Dosis Terapi','Boleh terapi tiap hari biar cepat sembuh?','Otak butuh waktu \'Inkubasi\' untuk memproses perubahan. Ibarat minum obat, overdosis gak bikin cepat sembuh. Jarak ideal 1 minggu sekali. Kecuali kasus krisis (panic attack parah), bisa 2x seminggu atas saran terapis.','tiap hari,sering,dosis,cepat',7,1,'2025-12-25 17:56:51','2025-12-25 17:56:51'),
(332,'faq_general','Efek Samping Pusing','Habis terapi kok kepala agak pening ya?','Itu wajar, namanya \'Trance Hangover\'. Mirip bangun tidur terlalu nyenyak. Itu tanda otak habis bekerja keras menata ulang saraf (rewiring). Minum air putih hangat yang banyak dan istirahat sejenak, pening akan hilang berganti rasa segar.','pusing,sakit,efek,habis',7,1,'2025-12-25 17:56:51','2025-12-25 17:56:51'),
(333,'faq_general','Definisi Hipnoterapi','Apa itu hipnoterapi?','Hipnoterapi adalah metode terapi yang menggunakan kondisi hipnosis (trance) untuk membantu mengatasi berbagai masalah psikologis dan perilaku. Dalam kondisi trance, pikiran bawah sadar lebih terbuka untuk menerima sugesti positif dan perubahan.','hipnoterapi,definisi,pengertian',10,1,'2025-12-25 17:56:51','2025-12-25 17:56:51'),
(334,'faq_general','Hipnoterapi Islami','Apa itu hipnoterapi Islami?','Hipnoterapi Islami menggabungkan teknik hipnoterapi modern dengan nilai-nilai spiritual Islam. Menggunakan dzikir, doa, dan ayat Al-Quran dalam proses terapi untuk kesembuhan holistik jasmani dan rohani.','hipnoterapi islami,spiritual,dzikir',10,1,'2025-12-25 17:56:52','2025-12-25 17:56:52'),
(335,'faq_general','Kondisi Trance','Apa itu kondisi trance?','Trance adalah kondisi kesadaran yang berubah dimana pikiran sangat fokus dan rileks. Seperti saat Anda sangat fokus membaca hingga tidak sadar waktu berlalu. Dalam hipnoterapi, kondisi ini digunakan untuk terapi.','trance,kondisi,hipnosis',8,1,'2025-12-25 17:56:52','2025-12-25 17:56:52'),
(336,'faq_general','Sejarah Hipnoterapi','Sejak kapan hipnoterapi ada?','Hipnoterapi modern dimulai abad ke-18 dengan Franz Mesmer, dikembangkan oleh James Braid dan Milton Erickson. Kini diakui secara medis dan digunakan di banyak negara.','sejarah,history,perkembangan',6,1,'2025-12-25 17:56:52','2025-12-25 17:56:52'),
(337,'faq_general','Keamanan','Apakah hipnoterapi aman?','Ya, sangat aman bila dilakukan terapis profesional. Klien tetap sadar penuh dan memiliki kontrol diri. Tidak ada efek samping berbahaya.','aman,keamanan,safety',10,1,'2025-12-25 17:56:52','2025-12-25 17:56:52'),
(338,'faq_general','Kontrol Diri','Apakah saya kehilangan kontrol?','Tidak. Anda tetap memiliki kontrol penuh. Terapis hanya memandu. Anda tidak akan melakukan hal yang bertentangan dengan nilai Anda.','kontrol,kendali',9,1,'2025-12-25 17:56:52','2025-12-25 17:56:52'),
(339,'faq_general','Rahasia','Apakah saya akan membocorkan rahasia?','Tidak. Anda tetap memiliki filter moral dan tidak akan mengungkapkan hal yang tidak ingin Anda bagikan.','rahasia,privasi',8,1,'2025-12-25 17:56:53','2025-12-25 17:56:53'),
(340,'faq_general','Kesadaran','Apakah saya akan sadar?','Ya, tetap sadar penuh. Dapat mendengar, berpikir, dan merespons. Hipnosis bukan tidur, melainkan fokus yang sangat dalam.','sadar,kesadaran',9,1,'2025-12-25 17:56:53','2025-12-25 17:56:53'),
(341,'faq_general','Efek Samping','Ada efek samping?','Tidak ada efek samping berbahaya. Beberapa mungkin merasa sedikit lelah setelah sesi (normal, hilang dalam 1-2 jam).','efek samping,side effect',8,1,'2025-12-25 17:56:53','2025-12-25 17:56:53'),
(342,'faq_general','Durasi Sesi pendek','Berapa lama sesi pendek?','Sesi pendek berlangsung 60 menit. Mencakup konsultasi awal, proses hipnosis, terapi, dan evaluasi. Sesi pertama biasanya lebih lama karena ada anamnesis.','durasi,lama,pendek,waktu',7,1,'2025-12-25 17:56:53','2025-12-25 17:56:53'),
(343,'faq_general','Durasi Sesi standar','Berapa lama sesi standar?','Sesi standar berlangsung 90 menit. Mencakup konsultasi awal, proses hipnosis, terapi, dan evaluasi. Sesi pertama biasanya lebih lama karena ada anamnesis.','durasi,lama,standar,waktu',7,1,'2025-12-25 17:56:53','2025-12-25 17:56:53'),
(344,'faq_general','Durasi Sesi panjang','Berapa lama sesi panjang?','Sesi panjang berlangsung 120 menit. Mencakup konsultasi awal, proses hipnosis, terapi, dan evaluasi. Sesi pertama biasanya lebih lama karena ada anamnesis.','durasi,lama,panjang,waktu',7,1,'2025-12-25 17:56:54','2025-12-25 17:56:54'),
(345,'faq_general','Jumlah Sesi Ringan','Berapa sesi untuk masalah ringan?','Masalah ringan biasanya 1-3 sesi. Beberapa klien merasakan perubahan setelah sesi pertama.','jumlah sesi,ringan',7,1,'2025-12-25 17:56:54','2025-12-25 17:56:54'),
(346,'faq_general','Jumlah Sesi Sedang','Berapa sesi untuk masalah sedang?','Masalah sedang biasanya 3-5 sesi untuk hasil optimal.','jumlah sesi,sedang',7,1,'2025-12-25 17:56:54','2025-12-25 17:56:54'),
(347,'faq_general','Jumlah Sesi Kompleks','Berapa sesi untuk masalah kompleks?','Masalah kompleks biasanya 5-10 sesi. Terapis akan memberikan rekomendasi setelah sesi pertama.','jumlah sesi,kompleks',7,1,'2025-12-25 17:56:54','2025-12-25 17:56:54'),
(348,'faq_general','Interval Sesi Ideal','Berapa jarak antar sesi?','Ideal 1-2 minggu antar sesi untuk memberi waktu pikiran bawah sadar memproses perubahan.','interval,jarak waktu',6,1,'2025-12-25 17:56:54','2025-12-25 17:56:54'),
(349,'faq_general','Biaya anak','Berapa biaya untuk anak?','Untuk klien anak (5-12 tahun), biaya Rp 500.000 per sesi. Pendekatan disesuaikan dengan karakteristik usia, mencakup child-friendly.','biaya,harga,anak,cost',8,1,'2025-12-25 17:56:55','2025-12-25 17:56:55'),
(350,'faq_general','Pendekatan anak','Bagaimana pendekatan untuk anak?','Untuk anak (5-12 tahun), kami menggunakan pendekatan child-friendly yang disesuaikan dengan kebutuhan dan karakteristik usia tersebut.','pendekatan,anak,metode',6,1,'2025-12-25 17:56:55','2025-12-25 17:56:55'),
(351,'faq_general','Biaya remaja','Berapa biaya untuk remaja?','Untuk klien remaja (13-18 tahun), biaya Rp 500.000 per sesi. Pendekatan disesuaikan dengan karakteristik usia, mencakup teen issues.','biaya,harga,remaja,cost',8,1,'2025-12-25 17:56:55','2025-12-25 17:56:55'),
(352,'faq_general','Pendekatan remaja','Bagaimana pendekatan untuk remaja?','Untuk remaja (13-18 tahun), kami menggunakan pendekatan teen issues yang disesuaikan dengan kebutuhan dan karakteristik usia tersebut.','pendekatan,remaja,metode',6,1,'2025-12-25 17:56:55','2025-12-25 17:56:55'),
(353,'faq_general','Biaya dewasa','Berapa biaya untuk dewasa?','Untuk klien dewasa (18-60 tahun), biaya Rp 500.000-600.000 per sesi. Pendekatan disesuaikan dengan karakteristik usia, mencakup adult problems.','biaya,harga,dewasa,cost',8,1,'2025-12-25 17:56:56','2025-12-25 17:56:56'),
(354,'faq_general','Pendekatan dewasa','Bagaimana pendekatan untuk dewasa?','Untuk dewasa (18-60 tahun), kami menggunakan pendekatan adult problems yang disesuaikan dengan kebutuhan dan karakteristik usia tersebut.','pendekatan,dewasa,metode',6,1,'2025-12-25 17:56:56','2025-12-25 17:56:56'),
(355,'faq_general','Biaya lansia','Berapa biaya untuk lansia?','Untuk klien lansia (60+ tahun), biaya Rp 500.000 per sesi. Pendekatan disesuaikan dengan karakteristik usia, mencakup elderly care.','biaya,harga,lansia,cost',8,1,'2025-12-25 17:56:56','2025-12-25 17:56:56'),
(356,'faq_general','Pendekatan lansia','Bagaimana pendekatan untuk lansia?','Untuk lansia (60+ tahun), kami menggunakan pendekatan elderly care yang disesuaikan dengan kebutuhan dan karakteristik usia tersebut.','pendekatan,lansia,metode',6,1,'2025-12-25 17:56:56','2025-12-25 17:56:56'),
(357,'faq_general','Transfer Bank','Bisa transfer bank?','Ya, kami terima transfer Bank (BCA, Mandiri, BNI, BRI). Detail rekening diberikan saat konfirmasi booking.','transfer,bank,pembayaran',7,1,'2025-12-25 17:56:56','2025-12-25 17:56:56'),
(358,'faq_general','E-Wallet','Bisa pakai e-wallet?','Ya, kami terima E-wallet (OVO, GoPay, Dana, ShopeePay, LinkAja).','e-wallet,digital payment',7,1,'2025-12-25 17:56:57','2025-12-25 17:56:57'),
(359,'faq_general','Cash','Bisa bayar cash?','Ya, pembayaran cash di tempat untuk sesi offline di klinik.','cash,tunai,pembayaran',7,1,'2025-12-25 17:56:57','2025-12-25 17:56:57'),
(360,'conditions','Arachnophobia','Takut laba-laba parah banget, bisa sembuh?','Arachnophobia (spider phobia) adalah salah satu phobia paling umum, affecting 3-5% populasi. SYMPTOMS: Panic, screaming, freezing, avoidance saat lihat laba-laba bahkan di foto. IMPACT: Tidak bisa masuk basement, garage, atau outdoor activities. TREATMENT: (1) Cognitive reframing - laba-laba lebih takut ke kita, (2) Gradual exposure dalam trance: foto → video → toy spider → real spider dalam jar → real spider free, (3) Anchoring calm state, (4) Reprocessing traumatic spider encounter jika ada. SUCCESS RATE: 80-85% dalam 4-6 sesi. TIMELINE: Bertahap, tidak rush. Many clients akhirnya bisa tangani spider sendiri di rumah tanpa panic. Homework: spider documentaries untuk desensitization.','arachnophobia,takut laba-laba,spider phobia,takut spider',9,1,'2025-12-25 17:56:57','2025-12-25 17:56:57'),
(361,'conditions','Ophidiophobia','Fobia ular mengganggu aktivitas, bisa diterapi?','Ophidiophobia (snake phobia) mempengaruhi 1/3 populasi dalam berbagai tingkat. TRIGGERS: Lihat ular di TV, kebun, hiking trails, zoo. SYMPTOMS: Intense fear, avoidance outdoor activities, nightmares tentang ular. EVOLUTIONARY: Fear of snakes adalah biological predisposition untuk survival, tapi bisa excessive. TREATMENT: (1) Education tentang snake behavior untuk cognitive reframe, (2) Systematic desensitization dalam hypnotic trance, (3) Visualization safe interaction dengan non-venomous snake, (4) Eventually exposure ke real snake dengan handler professional. SUCCESS: 75-80% dapat hiking dan outdoor activities comfortably dalam 5-8 sesi. BENEFIT: Expand lifestyle possibilities - hiking, camping, traveling ke tropical areas.','ophidiophobia,takut ular,snake phobia,fobia ular',8,1,'2025-12-25 17:56:57','2025-12-25 17:56:57'),
(362,'conditions','Hemophobia','Takut darah sampai pingsan, bisa diatasi?','Hemophobia (blood phobia) unique karena 75% sufferers experience vasovagal syncope (pingsan) saat lihat darah. IMPACT: Menghindari medical procedures, tidak bisa donor darah, career limitation (medis, forensic). PHYSIOLOGY: Blood phobia trigger paradoxical response - blood pressure drop drastically. TREATMENT: (1) Applied tension technique - tense muscles untuk prevent fainting, (2) Gradual exposure: cartoon blood → fake blood → blood donation video → real blood test, (3) Hypnotic suggestion untuk vascular control, (4) Reframe blood as life-giving not dangerous. SUCCESS: 70-80% dapat medical procedures tanpa syncope dalam 6-10 sesi. UNIQUE: Need teach applied tension skill sebagai safety net. Most clients eventually bisa donor darah!','hemophobia,takut darah,blood phobia,pingsan',9,1,'2025-12-25 17:56:57','2025-12-25 17:56:57'),
(363,'conditions','Aquaphobia','Takut air dalam, tidak bisa berenang karena fobia','Aquaphobia (fear of water) ranging dari mild (deep water) hingga severe (tidak bisa mandi/shower). CAUSES: Near-drowning experience, parental fear transmission, no water exposure as child. IMPACT: No swimming, beach anxiety, career limitation (military, rescue). SEVERITY LEVELS: (1) Mild: deep water, (2) Moderate: cannot swim, (3) Severe: shower anxiety. TREATMENT: (1) Water safety education, (2) Breathing control hypnosis, (3) Gradual exposure imaginal: ankle-deep → waist → swimming pool → ocean, (4) Installing trust dan buoyancy suggestions, (5) Real exposure dengan lifeguard present. SUCCESS: 75% dapat learn swimming dalam 8-12 sesi combined dengan swim lessons. Timeline longer untuk severe cases. Many clients eventually love water activities!','aquaphobia,takut air,water phobia,tidak bisa renang',8,1,'2025-12-25 17:56:58','2025-12-25 17:56:58'),
(364,'conditions','Dentophobia','Takut dokter gigi parah, gigi rusak semua','Dentophobia (dental phobia) affecting 10-15% adults, leading to severe dental problems. CAUSES: Painful childhood dental experience, fear of needles, loss of control, embarrassment tentang dental condition. IMPACT: Tooth decay, gum disease, tooth loss, chronic pain, social embarrassment. TREATMENT: (1) Desensitization to dental stimuli: sound, smell, sight of instruments, (2) Pain control hypnosis - analgesia suggestions, (3) Dissociation techniques selama dental work, (4) Reprocessing traumatic dental memories, (5) Building trust dengan dentist. SUCCESS: 80-85% dapat dental cleaning dalam 4-6 sesi, major work dalam 8-10 sesi. COLLABORATION: Work closely dengan dentist yang experienced dengan anxious patients. Self-hypnosis audio for dental appointments. Life-changing results!','dentophobia,takut dokter gigi,dental phobia,dental anxiety',9,1,'2025-12-25 17:56:58','2025-12-25 17:56:58'),
(365,'conditions','Mysophobia','Obsesi takut kuman mengganggu hidup, bisa normal?','Mysophobia (germophobia/contamination OCD) adalah ketakutan excessive terhadap germs dan contamination. SYMPTOMS: Excessive handwashing (50-100x/day), avoidance public places, gloves di rumah, tidak bisa sentuh doorknobs. SEVERITY: Mild (frequent handwashing) hingga Severe (housebound, skin damage dari washing). OVERLAP: Often overlaps dengan OCD - butuh comprehensive assessment. TREATMENT: (1) Cognitive reframing tentang immune system, (2) Anxiety tolerance building, (3) Gradual exposure ke \'contaminated\' objects dalam controlled setting, (4) Response prevention hypnotic suggestions, (5) Distress tolerance. SUCCESS: 60-70% significant reduction dalam 12-20 sesi. REALISTIC: Chronic condition - manage symptoms not complete cure. Maintenance sessions needed. Quality of life improves dramatically.','mysophobia,takut kuman,germophobia,OCD kontaminasi',8,1,'2025-12-25 17:56:58','2025-12-25 17:56:58'),
(366,'conditions','Nyctophobia','Anak takut gelap tidak bisa tidur sendiri','Nyctophobia (fear of dark) sangat umum pada children, 10-30% mengalaminya. AGE: Usually 2-12 years, most outgrow by adolescence, tapi some persist ke adulthood. CAUSES: Imagination overactive, scary stories/movies, separation anxiety, fear of unknown. IMPACT: Cannot sleep alone, nightlight dependency, fear-induced insomnia. TREATMENT CHILDREN: (1) Storytelling dengan brave characters facing darkness, (2) Imagination play - \'darkness as friend\', (3) Gradual dark exposure with parent present, (4) Empowerment suggestions, (5) Night routine dengan safety objects. SUCCESS: 85-90% overcome dalam 4-8 sesi karena children very responsive. APPROACH: Playful, non-threatening, involve teddy bears atau comfort objects. Parents must not reinforce fear. Most children sleep independently after treatment!','nyctophobia,takut gelap,fear of dark,anak takut gelap',9,1,'2025-12-25 17:56:58','2025-12-25 17:56:58'),
(367,'conditions','Astraphobia','Takut petir dan guntur dari kecil, traumatis','Astraphobia (fear of thunder/lightning) affecting 2-5% population, more common di tropical regions. SYMPTOMS: Panic during storms, hiding, crying, hypervigilance tentang weather forecast. CAUSES: Traumatic storm experience, parental modeling, natural survival instinct gone excessive. TREATMENT: (1) Education tentang thunder/lightning science untuk reduce unknown, (2) Desensitization: soft thunder sounds → loud → real storm dengan support, (3) Reframing storm as nature\'s powerful beauty not dangerous, (4) Safe place visualization during storms, (5) Anchoring calm. SUCCESS: 70-80% dapat stay calm during storms dalam 5-8 sesi. PRACTICAL: Storm sounds exposure as homework. Many clients eventually enjoy watching storms dari jendela! Seasonal consideration: tratment before rainy season optimal.','astraphobia,takut petir,thunder phobia,lightning fear',8,1,'2025-12-25 17:56:58','2025-12-25 17:56:58'),
(368,'conditions','Thanatophobia','Takut mati berlebihan mengganggu hidup','Thanatophobia (death anxiety) adalah fear of death or dying yang excessive dan persistent. NORMAL VS PATHOLOGICAL: Normal untuk think about death occasionally, pathological ketika daily preoccupation dan avoidance behaviors. SYMPTOMS: Panic attacks ketika think about death, avoidance funeral/hospital, health anxiety, existential dread. CAUSES: Trauma, loss of loved one, midlife crisis, religious doubts. TREATMENT: (1) Existential therapy dalam hypnosis - explore meaning of life, (2) Acceptance of mortality sebagai natural, (3) Living fully di present moment, (4) Spiritual exploration (for Muslims: iman kepada akhirat), (5) Legacy work - what you want to leave behind. SUCCESS: 60-70% significant reduction dalam 10-15 sesi. DEEP WORK: This is existential issue, butuh patience dan philosophical exploration. For Muslims: strengthen iman tentang akhirat very helpful.','thanatophobia,takut mati,death anxiety,fear of death',8,1,'2025-12-25 17:56:59','2025-12-25 17:56:59'),
(369,'conditions','Emetophobia Detail','Takut muntah bikin gak bisa makan normal','Emetophobia detail impact: (1) EATING: Restrictive diet, avoid \'risky\' foods, eating disorders, malnutrition, (2) SOCIAL: Cannot eat di restaurant, avoid bars/parties, (3) PREGNANCY: Avoid pregnancy karena morning sickness fear, (4) TRAVEL: Cannot travel karena motion sickness fear, (5) MEDICAL: Refuse chemotherapy atau anesthesia. SEVERITY: One of most debilitating phobias with lowest treatment-seeking. TREATMENT STAGES: (1) Stabilize eating patterns, (2) Interoceptive exposure ke nausea sensations, (3) Imaginal exposure ke vomit scenarios, (4) Cognitive reframe, (5) Eventually in vivo exposure. TIMELINE: 15-25 sesi karena very resistant phobia. SUCCESS: 60-70% dapat eat normally dan less avoidance. SUPPORT: Dietitian collaboration untuk nutritional rehabilitation.','emetophobia,takut muntah,eating restriction,food phobia',9,1,'2025-12-25 17:56:59','2025-12-25 17:56:59'),
(370,'conditions','Trypophobia','Takut lubang-lubang kecil, geli dan panik','Trypophobia (fear of clustered holes/bumps) adalah relatively newly recognized phobia. TRIGGERS: Lotus seed pod, honeycomb, coral, sponge, soap bubbles, certain skin conditions. SYMPTOMS: Disgust, goosebumps, nausea, panic, skin crawling sensation. THEORY: Evolutionary response untuk avoid diseased skin atau poisonous animals. PREVALENCE: 15-25% population dalam berbagai tingkat. TREATMENT: (1) Gradual exposure ke trypophobic images dengan increasing intensity, (2) Disgust reframing, (3) Relaxation training saat view images, (4) Cognitive restructuring tentang harm assessment. SUCCESS: 70-80% can tolerate images without distress dalam 4-6 sesi. UNIQUE: More disgust than fear response - treatment adjust accordingly. Most clients manage symptoms well dengan minimal sessions. Low impact on daily life usually, tapi bothersome.','trypophobia,takut lubang,holes phobia,clustered holes',7,1,'2025-12-25 17:56:59','2025-12-25 17:56:59'),
(371,'conditions','Glossophobia Detail','Presentasi di depan bos besok, bisa urgent session?','Glossophobia urgent treatment: Ya! Kami provide PRE-PRESENTATION INTENSIVE SESSION. PROTOCOL: (1) Emergency booking same-day atau night before, (2) 90-minute intensive session: rapid relaxation → confidence building → hypnotic rehearsal entire presentation → anchoring confident state → post-hypnotic suggestions, (3) Audio recording untuk dengar pagi hari presentasi, (4) WhatsApp support sampai presentasi selesai. SUCCESS: 85-90% report significantly better performance dan reduced anxiety. TECHNIQUE: Imaginal rehearsal proven increase actual performance by 20-30%. COST: Emergency surcharge apply (+50%). TESTIMONIAL: Klien yang \'almost cancel\' presentation because of anxiety, successfully present dan dapat promotion! Best results: session 1-2 hari sebelum event, bukan 2 jam sebelum (butuh time untuk consolidate).','glossophobia,urgent,emergency,presentation,public speaking',10,1,'2025-12-25 17:56:59','2025-12-25 17:56:59'),
(372,'conditions','Tokophobia','Takut hamil dan melahirkan menunda punya anak','Tokophobia adalah intense fear of pregnancy/childbirth yang affect family planning decisions. TYPES: (1) Primary: nulliparous women, never pregnant, (2) Secondary: after traumatic birth experience. PREVALENCE: 6-10% women of childbearing age. IMPACT: Delay pregnancy, request cesarean, relationship strain. SYMPTOMS: Panic attacks tentang pregnancy, nightmares, avoidance sexual intercourse. TREATMENT: (1) Education tentang modern obstetrics dan pain management, (2) Reprocessing traumatic birth stories heard, (3) Hypnobirthing preparation - visualize positive birth, (4) Pain control techniques, (5) Empowerment suggestions. SUCCESS: 70-75% proceed dengan pregnancy confidently dalam 8-12 sesi. COLLABORATION: Work dengan OB-GYN dan doula. Hypnobirthing component: visualize ideal birth, pain as \'pressure\', baby descent visualization. Many have positive birth experiences after treatment!','tokophobia,takut hamil,pregnancy fear,childbirth anxiety',8,1,'2025-12-25 17:56:59','2025-12-25 17:56:59'),
(373,'conditions','Nomophobia','Gak bisa lepas dari HP, anxiety parah kalau ketinggalan','Nomophobia (no-mobile-phone phobia) adalah modern phobia - fear of being without smartphone. SYMPTOMS: Anxiety ketika battery low, panic jika lupa HP, check phone 150-300x/day, phantom vibration syndrome. IMPACT: Sleep disruption, relationship issues, attention problems, neck pain. PREVALENCE: 50-65% smartphone users mengalami dalam berbagai tingkat. TREATMENT: (1) Digital detox gradual - mulai 30 min tanpa phone, kemudian 1 jam, dst, (2) Anxiety tolerance building, (3) Reframe phone as tool not lifeline, (4) FOMO (fear of missing out) management, (5) Installing alternative coping mechanisms. SUCCESS: 60-70% reduce phone dependency significantly dalam 8-12 sesi. HOMEWORK: Phone-free activities, airplane mode practice, designated phone-free times. Young adults paling affected. Quality of life dan relationships improve dramatically!','nomophobia,addiction hp,phone addiction,smartphone anxiety',8,1,'2025-12-25 17:57:00','2025-12-25 17:57:00'),
(374,'conditions','Ergophobia','Takut kerja setelah burnout, gak bisa masuk kantor','Ergophobia (fear of work) develops setelah severe burnout, workplace trauma, atau prolonged unemployment. SYMPTOMS: Panic attacks sebelum kerja, Sunday night anxiety, avoidance behaviors, psychosomatic illness (headache, nausea). CAUSES: Toxic workplace, harassment, excessive workload, perfectionism, fear of failure. IMPACT: Job loss, financial stress, self-esteem issues, depression. TREATMENT: (1) Identify specific work triggers (boss, deadline, meetings), (2) Desensitization gradual - imaginal work situations, (3) Ego strengthening dan competence building, (4) Work-life balance suggestions, (5) Assertiveness training hypnosis. SUCCESS: 65-75% dapat return to work dalam 10-15 sesi. REALISTIS: Kadang memang need job change jika workplace truly toxic. Career counseling integration helpful. Many clients report finding more fulfilling careers after treatment!','ergophobia,takut kerja,work anxiety,burnout,workplace phobia',8,1,'2025-12-25 17:57:00','2025-12-25 17:57:00'),
(375,'conditions','Atychiphobia','Takut gagal bikin gak berani mulai apapun','Atychiphobia (fear of failure) adalah perfectionism extreme yang paralyze action. SYMPTOMS: Procrastination, cannot start projects, self-sabotage, avoidance challenges. ROOTS: Critical parenting, past humiliation, impossibly high standards. IMPACT: Underachievement, missed opportunities, regret, depression. COGNITIVE DISTORTION: \'If I\'m not perfect, I\'m failure\' - black and white thinking. TREATMENT: (1) Reframe failure as learning opportunity, (2) Lower perfectionism standards dengan graduated success experiences, (3) Self-compassion building, (4) Visualization successful attempts with mistakes included, (5) Exposure to \'failing\' dalam safe environment. SUCCESS: 70-80% dapat take risks dan start projects dalam 8-12 sesi. BREAKTHROUGH: When clients realize \'B grade is okay\' atau \'imperfect action beats perfect inaction\'. Life becomes more adventurous dan fulfilling!','atychiphobia,takut gagal,fear of failure,perfectionism',8,1,'2025-12-25 17:57:00','2025-12-25 17:57:00'),
(376,'conditions','Philophobia','Takut jatuh cinta karena trauma masa lalu','Philophobia (fear of love/relationships) develops after betrayal, abuse, atau attachment trauma. SYMPTOMS: Sabotage relationships ketika getting close, emotional unavailability, cannot commit, push people away. CAUSES: Infidelity trauma, abusive past relationship, parental divorce, abandonment issues. IMPACT: Loneliness, serial dating tanpa depth, cannot form lasting relationships. PROTECTIVE: Fear is protective mechanism - \'can\'t hurt me if I don\'t let you in\'. TREATMENT: (1) Reprocess past relationship trauma, (2) Trust rebuilding suggestions, (3) Challenge cognitive distortions tentang love, (4) Gradual vulnerability exercises, (5) Attachment style work. SUCCESS: 60-70% dapat form healthy relationship dalam 15-25 sesi. DEEP WORK: Need explore attachment patterns from childhood. Couples therapy integration jika currently in relationship. Beautiful outcomes: clients finding lasting love after years of avoidance!','philophobia,takut cinta,fear of love,relationship anxiety',8,1,'2025-12-25 17:57:00','2025-12-25 17:57:00'),
(377,'conditions','Somniphobia','Takut tidur karena mimpi buruk berulang','Somniphobia (sleep anxiety/fear of sleeping) develops after recurrent nightmares atau sleep paralysis. SYMPTOMS: Resist bedtime, insomnia, exhaustion, fear of losing control during sleep. CAUSES: PTSD nightmares, sleep paralysis episodes, sleepwalking incidents, fear of death during sleep. IMPACT: Chronic sleep deprivation → cognitive impairment, mood issues, health problems. TREATMENT: (1) Nightmare reprocessing - change nightmare endings dalam hypnosis, (2) Sleep as safe space suggestions, (3) Lucid dreaming training untuk control nightmares, (4) Pre-sleep relaxation routine hypnosis, (5) Address underlying trauma causing nightmares. SUCCESS: 75-80% dapat sleep normally dalam 8-12 sesi. TECHNIQUE: Image rehearsal therapy very effective. Most clients report fewer nightmares within 4 sessions. Sleep quality transforms life quality dramatically!','somniphobia,takut tidur,sleep anxiety,nightmare disorder',9,1,'2025-12-25 17:57:01','2025-12-25 17:57:01'),
(378,'conditions','Carcinophobia','Obsesi takut kanker mengganggu hidup normal','Carcinophobia (cancer phobia) adalah subset dari health anxiety focused on cancer fear. SYMPTOMS: Frequent cancer worry, excessive body checking, multiple doctor visits, googling symptoms, avoid cancer-related media. TRIGGERS: Family history of cancer, celebrity cancer news, medical checkup approaching. IMPACT: Constant anxiety, excessive medical tests (financial burden), quality of life reduced drastically. TREATMENT: (1) Reality testing - statistical probability actual cancer, (2) Intolerance of uncertainty work, (3) Reduce checking behaviors gradually, (4) Mindfulness untuk present moment vs future worry, (5) Cognitive restructuring tentang bodily sensations. SUCCESS: 65-75% significant reduction dalam obsessive worry dalam 10-15 sesi. CHALLENGE: Health anxiety resistant karena \'better safe than sorry\' mindset. Homework: Limit googling symptoms. Collaboration dengan primary care physician helpful untuk appropriate screening schedule.','carcinophobia,takut kanker,cancer phobia,health anxiety',8,1,'2025-12-25 17:57:01','2025-12-25 17:57:01'),
(379,'conditions','Coulrophobia','Takut badut parah dari kecil, trauma','Coulrophobia (clown phobia) surprisingly common, affecting 5-10% population. CAUSES: (1) Uncanny valley effect - familiar tapi distorted features, (2) Childhood traumatic clown encounter, (3) Horror movie clowns (IT), (4) Cannot read emotions karena makeup. SYMPTOMS: Panic at parties dengan clowns, avoidance circus, nightmares. IMPACT: Usually low daily impact kecuali kerja dengan children events. TREATMENT: (1) Education - clowns adalah people in costume, (2) Gradual exposure: cartoon clowns → friendly clown images → clown videos → real clown dari jauh → close interaction, (3) Reprocessing traumatic clown memory, (4) Desensitization via humor. SUCCESS: 80-85% tolerate clowns comfortably dalam 4-6 sesi. TIMELINE: Relatively quick resolution karena limited real-world exposure. Many clients eventually find clowns funny after treatment!','coulrophobia,takut badut,clown phobia,badut',7,1,'2025-12-25 17:57:01','2025-12-25 17:57:01'),
(380,'pricing','Paket 10 Sesi','Paket hemat untuk terapi jangka panjang ada?','Paket 10 Sesi Albashiro: Rp 6.000.000 (original Rp 7.500.000) - HEMAT 20%! BEST VALUE untuk complex issues. INCLUDES: (1) 10x sesi individual 60-90 menit, (2) Comprehensive psychological assessment, (3) Detailed treatment plan dengan milestones, (4) Multiple audio self-hypnosis recordings customized, (5) Progress evaluation setiap 3 sesi, (6) Priority scheduling, (7) Unlimited WhatsApp support, (8) Resource materials (worksheets, journals, reading), (9) Email check-ins antar sesi. VALIDITY: 6 bulan. COCOK UNTUK: Complex trauma, chronic anxiety, OCD, deep-rooted issues, personality work. PAYMENT: Bisa installment 2-3x tanpa bunga. Average client dengan paket ini achieve 70-80% improvement. Investment terbaik untuk transformasi mendalam!','paket 10,package,diskon,hemat,long-term',10,1,'2025-12-25 17:57:01','2025-12-25 17:57:01'),
(381,'pricing','First Session Extended','Berapa biaya konsultasi pertama?','First Session Extended: Rp 900.000 (90-120 menit). INCLUDES: (1) Comprehensive intake interview - 30 menit: history, symptoms, goals, (2) Psychological assessment - 15 menit: severity, suggestibility test, (3) Psychoeducation - 15 menit: explain condition, treatment plan, realistic expectations, (4) Initial hypnotherapy - 30 menit: experience hipnosis pertama kali, (5) Homework assignment - 10 menit: self-hypnosis audio, journaling tasks. PURPOSE: Build rapport, establish diagnosis, experience therapy, assess response. LONGER karena perlu thorough understanding. FOLLOW-UP sessions: Rp 600.000-750.000 (60-90 menit). VALUE: Comprehensive assessment saves time long-term. Most clients feel 30-40% better bahkan after first session! Book via website atau WhatsApp.','first session,consultation,initial,pertama kali,assessment',10,1,'2025-12-25 17:57:01','2025-12-25 17:57:01'),
(382,'pricing','Online Session Rate','Berapa tarif sesi online?','Online Session Rate: Rp 400.000-600.000 per sesi (60-90 menit), lebih affordable 30-40% dari in-person! PLATFORM: Zoom, Google Meet, atau WhatsApp Video. SAME QUALITY: Research shows online hypnotherapy 70-85% efficacy, only 5-10% lower dari face-to-face. REQUIREMENTS: (1) Stable internet minimum 5 Mbps, (2) Quiet private room, (3) Headphones/earbuds dengan mic bagus, (4) Laptop/tablet (lebih baik dari phone untuk eye contact), (5) Comfortable seating atau bisa berbaring. PROCESS: Same structure sebagai in-person - consultation, hypnosis, post-talk. BENEFITS: (1) No travel time & cost, (2) Comfort di rumah = easier relaxation, (3) Access best therapists di Indonesia dari mana saja, (4) Flexible scheduling. COCOK: Anxiety, phobias, habits, stress. KURANG COCOK: Severe trauma butuh grounding, atau klien mudah distracted.','online,virtual,zoom,rate,tarif online',10,1,'2025-12-25 17:57:02','2025-12-25 17:57:02'),
(383,'pricing','Couple Therapy Rate','Berapa biaya terapi untuk pasangan?','Couple Hypnotherapy Session: Rp 1.200.000 per sesi (90-120 menit untuk 2 orang). ISSUES TREATED: (1) Communication problems, (2) Trust issues post-infidelity, (3) Sexual issues (low libido, performance anxiety), (4) Premarital preparation, (5) Conflict resolution, (6) Emotional intimacy, (7) Co-parenting stress. APPROACH: Both partners dalam satu sesi - individual hypnosis untuk each partner untuk unlock subconscious blocks, kemudian joint suggestions untuk relationship harmony. SUCCESS: 70-75% couples report significant improvement dalam 6-10 sesi. REALISTIC: Not miracle cure - both must committed. Homework: Practice communication skills, intimacy exercises. PAKET: 5 couple sessions Rp 5.500.000 (save 8%). TESTIMONIAL: Couples on brink of divorce saved, reignited passion after years of disconnect. Premarital couples build strong foundation. Investment terbaik untuk relationship!','couple,pasangan,couple therapy,relationship,marriage',9,1,'2025-12-25 17:57:02','2025-12-25 17:57:02'),
(384,'pricing','Home Visit Pricing','Berapa biaya kalau terapis datang ke rumah?','Home Visit Service Pricing: (1) JAKARTA PUSAT/SELATAN/BARAT: Rp 1.500.000, (2) JAKARTA UTARA/TIMUR: Rp 1.750.000, (3) BOGOR/DEPOK/TANGERANG/BEKASI: Rp 2.000.000, (4) LUAR JABODETABEK: Negotiate (fuel + time). DURATION: Minimum 90 menit, bisa extend to 120 menit +Rp 300.000. INCLUDES: Professional therapy sama kualitas, equipment portable, assessment tools, follow-up materials. REQUIREMENTS: (1) Private quiet room, (2) Comfortable seating/bed, (3) Minimal distractions, (4) Parking/access untuk terapis. PAYMENT: 50% deposit saat booking, 50% setelah sesi. COCOK UNTUK: (1) Mobility limitations (elderly, post-surgery), (2) Agoraphobia (takut keluar rumah), (3) High-profile clients butuh discretion, (4) Busy executives. PAKET 5 HOME VISITS: Rp 7.000.000 (save 15%). Convenience premium tapi worth it untuk comfort maksimal!','home visit,visit rumah,terapis datang,mobile service,harga home visit',9,1,'2025-12-25 17:57:02','2025-12-25 17:57:02'),
(385,'pricing','Group Workshop Rate','Berapa biaya workshop group untuk kantor?','Group Workshop Pricing: (1) STRESS MANAGEMENT (20-30 pax, 3 jam): Rp 12.000.000, (2) ANXIETY & RELAXATION (20-30 pax, 2 jam): Rp 8.000.000, (3) SMOKING CESSATION GROUP (10-15 pax, 4 jam): Rp 10.000.000, (4) PRODUCTIVITY & FOCUS (20-30 pax, 3 jam): Rp 12.000.000, (5) LEADERSHIP CONFIDENCE (15-20 leaders, 4 jam): Rp 15.000.000. STRUCTURE: Psychoeducation 30% + Group hypnosis 50% + Q&A 20%. INCLUDES: Materials handouts, audio recordings untuk participants, follow-up resources. LOCATION: Client\'s office atau kami provide space (+Rp 2 juta). CUSTOMIZABLE: Content adjust sesuai company needs dan industry. ROI: Studies show setiap Rp 1 invested dalam mental health return Rp 3-4 dalam productivity. BOOKING: Minimum 2 minggu notice. Popular untuk corporate wellness programs!','group,workshop,corporate,kantor,seminar',8,1,'2025-12-25 17:57:02','2025-12-25 17:57:02'),
(386,'pricing','Emergency Surcharge','Kalau urgent butuh besok bisa? Berapa biayanya?','Emergency/Urgent Session: Available dengan surcharge +50% dari regular rate. REGULAR Rp 750.000 → EMERGENCY Rp 1.125.000. CRITERIA EMERGENCY: (1) Severe panic attack, (2) Acute trauma response (accident, assault baru terjadi), (3) Pre-important event (presentation besok, exam lusa), (4) Crisis intervention (suicidal ideation as adjunct ke psychiatric care), (5) Relapse prevention urgent. AVAILABILITY: Same-day atau next-day IF ada slot. NOT GUARANTEED - tergantung therapist schedule. BOOKING: WhatsApp admin dengan explain urgency. ALTERNATIVE: Jika tidak ada slot, kami provide crisis support via phone consultation 15-20 menit gratis untuk stabilize, kemudian schedule ASAP. NOTE: Emergency session bukan replacement untuk psychiatric emergency - jika actively suicidal atau psychotic, segera ke UGD atau call 119!','emergency,urgent,darurat,crisis,surcharge',9,1,'2025-12-25 17:57:02','2025-12-25 17:57:02'),
(387,'pricing','Student Discount','Ada diskon untuk mahasiswa?','Student Discount: 15% off regular session rate! Regular Rp 750.000 → Student Rate Rp 637.500. REQUIREMENTS: (1) Valid student ID/KTM, (2) Mahasiswa aktif S1/S2/S3, (3) Age 17-30, (4) Indonesia university atau international student di Indonesia. APPLICABLE TO: Individual sessions only (not packages, though packages already discounted). WHY: Kami believe mental health harus accessible untuk young people. Students menghadapi unique stressors: exam anxiety, social pressure, identity issues, career uncertainty. COMMON ISSUES: Exam anxiety, procrastination, social anxiety, depression, family conflicts, quarter-life crisis. BOOKING: Mention student status saat booking, tunjukkan KTM at session. ADDITIONAL: Student package option: 5 sessions Rp 3.000.000 (double discount!). Investment dalam mental health sekarang = foundation untuk successful future!','student,mahasiswa,diskon,discount,pelajar',8,1,'2025-12-25 17:57:03','2025-12-25 17:57:03'),
(388,'pricing','Senior Citizen Rate','Apakah ada tarif khusus untuk lansia?','Senior Citizen Rate (60+ tahun): 15% discount. Regular Rp 750.000 → Senior Rate Rp 637.500. RESPECT: Kami honor kehidupan dan pengalaman elders, mental health sama pentingnya di semua usia. COMMON ELDERLY ISSUES: (1) Adjustment to retirement, (2) Grief & loss (spouse, friends), (3) Health anxiety, (4) Insomnia, (5) Pain management (arthritis, chronic pain), (6) Memory concerns anxiety, (7) Feeling useless/purposeless, (8) Loneliness. APPROACH: Slower pace, louder volume jika hearing issues, simpler language, respect dan dignity utama. SUCCESS: Elderly very responsive karena wisdom dan life experience. LOGISTICS: Home visit recommended jika mobility issues (dengan harga khusus senior). DURATION: Sometimes shorter sessions (45-60 min) karena fatigue easier. Beautiful work - helping elders find peace dan meaning di golden years!','senior,lansia,elderly,old age,diskon',8,1,'2025-12-25 17:57:03','2025-12-25 17:57:03'),
(389,'pricing','Referral Bonus Detail','Sistem referral gimana? Bisa dapat gratis?','Referral Program Detail: (1) REFERRER BENEFIT: 20% discount untuk next session setiap 1 referral yang successfully book & attend, (2) REFEREE BENEFIT: 10% discount untuk first session, (3) ACCUMULATION: Diskon bisa distack hingga maksimum 50% off untuk satu sesi (tapi tidak bisa free session), (4) BONUS MILESTONE: Setiap 5 successful referrals = 1 FREE session worth Rp 750.000! (5) UNLIMITED: No cap berapa banyak bisa refer. CARA KERJA: (1) Minta referral code dari terapis/admin setelah sesi pertama Anda, (2) Share code ke friends/family/social media, (3) Mereka mention code saat booking, (4) Setelah mereka attend first session, Anda dapat discount code via email. TRACKING: Dashboard untuk track referrals. WIN-WIN: You help friends dengan mental health, you save money, we grow community!','referral,refer friend,bonus,gratis,free session',9,1,'2025-12-25 17:57:03','2025-12-25 17:57:03'),
(390,'pricing','Package Comparison','Mending ambil paket atau per sesi?','COMPARISON Per Sesi vs Packages: PER SESI (Rp 750.000): PROS - Flexibility, no commitment, test terapis dulu, cocok untuk simple issues (1-3 sesi cukup). CONS - Lebih mahal long-term, no priority booking. PAKET 5 (Rp 3.375k, save 10%): PROS - Save Rp 375k, suitable untuk moderate issues, 3-month validity cukup. PAKET 10 (Rp 6.000k, save 20%): PROS - Save Rp 1.500k!, best value, priority scheduling, extensive support, suitable complex issues, 6-month validity. CONS packages - commitment needed, uang dimuka. RECOMMENDATION: (1) Simple issues (smoking, simple phobia): Per sesi atau paket 3-5, (2) Moderate issues (anxiety, mild depression): Paket 5, (3) Complex issues (trauma, OCD, severe anxiety): Paket 10. FLEXIBILITY: Unused package sessions bisa direfund 50% jika cancel dalam validity period. Calculate: 10 sesi per-sesi = Rp 7.5 juta, paket = Rp 6 juta. SAVE RP 1.5 JUTA!','package,comparison,mending,per sesi,compare',9,1,'2025-12-25 17:57:03','2025-12-25 17:57:03'),
(391,'pricing','Payment Methods','Metode pembayaran apa saja yang diterima?','Payment Methods Accepted: (1) BANK TRANSFER: BCA, Mandiri, BNI, BRI - preferred method, (2) E-WALLET: GoPay, OVO, Dana, ShopeePay, (3) CREDIT CARD: Visa, Mastercard via payment gateway (+ 3% admin fee), (4) DEBIT CARD: Semua bank, (5) CASH: Acceptable untuk in-person sessions (exact amount). WHEN TO PAY: (1) Per session: Bayar sebelum atau immediately after session, (2) Packages: 50% deposit untuk secure booking, 50% sebelum first session ATAU full payment dimuka (get additional 2% discount!), (3) Home visit: 50% deposit, 50% after session. INVOICE: Resmi dengan kwitansi untuk corporate clients atau reimbursement. NO HIDDEN FEES. REFUND POLICY: Cancel >48 jam before session = full refund, 24-48 jam = 50% refund, <24 jam = no refund (kecuali emergency dengan proof).','payment,pembayaran,transfer,metode bayar,how to pay',9,1,'2025-12-25 17:57:03','2025-12-25 17:57:03'),
(392,'pricing','Insurance Coverage','Apakah bisa pakai asuransi?','Insurance Coverage: CURRENTLY sebagian besar asuransi Indonesia BELUM cover hipnoterapi specifically. STATUS: (1) Asuransi swasta (Prudential, AIA, Manulife, Allianz): Kadang cover sebagai \'alternative medicine\' atau \'mental health counseling\' - CHECK dengan provider Anda, (2) BPJS: TIDAK cover hipnoterapi, (3) Corporate insurance: Beberapa companies include alternative therapy dalam employee wellness benefit. PROCESS JIKA COVERED: (1) Kami provide detailed invoice/kuitansi, (2) Anda submit ke insurance untuk reimbursement, (3) Approval tergantung policy Anda. REKOMENDASI: Call insurance provider sebelum booking untuk confirm coverage. ALTERNATIVE: Gunakan FSA/HSA (Flexible Spending Account) jika perusahaan provide. TREND: Coverage improving - semakin banyak insurance recognize hipnoterapi sebagai legitimate mental health treatment. Fight untuk coverage dengan show research dan referral dari doctor!','insurance,asuransi,coverage,claim,reimbursement',8,1,'2025-12-25 17:57:04','2025-12-25 17:57:04'),
(393,'pricing','Installment Plans','Bisa cicil gak untuk paket?','Installment Plans: Ya! PAKET 5 & 10 bisa dicicil tanpa bunga. TERMS: (1) PAKET 5 (Rp 3.375k): Cicil 2x (Rp 1.688k + Rp 1.688k) atau 3x (Rp 1.125k per month), (2) PAKET 10 (Rp 6 juta): Cicil 2x (Rp 3 juta + Rp 3 juta) atau 3x (Rp 2 juta per month). SCHEDULE: (1) Pembayaran 1: Saat booking (down payment), (2) Pembayaran 2: 30 hari kemudian, (3) Pembayaran 3: 60 hari kemudian (jika 3x). AUTOMATIC: Set up auto-debit atau manual transfer dengan reminder. NO INTEREST: 0% bunga untuk make mental health accessible. REQUIREMENTS: Valid ID, contact info, signed installment agreement. DEFAULT: Jika missed payment, remaining sessions suspended until paid. GOAL: Don\'t let cost be barrier untuk treatment! Banyak klien utilize ini untuk afford comprehensive treatment. Investasi dalam mental health adalah investasi terbaik!','installment,cicil,payment plan,cicilan,kredit',9,1,'2025-12-25 17:57:04','2025-12-25 17:57:04'),
(394,'pricing','Corporate Package Detail','Paket untuk 50 karyawan ada?','Corporate Package (50+ employees): CUSTOM PRICING starting Rp 150 juta per year. STRUCTURE: (1) TIER 1 (50 employees): Rp 150 juta - 3 sesi per employee per year = 150 total sessions, (2) TIER 2 (100 employees): Rp 250 juta - 3 sesi per employee = 300 sessions + 4 wellness workshops, (3) TIER 3 (200+ employees): Rp 450 juta - 4 sesi per employee + 8 workshops + dedicated corporate therapist 1 day/week on-site. BENEFITS: (1) Reduced absenteeism 20-40%, (2) Increased productivity 15-30%, (3) Better employee retention, (4) Improved workplace morale, (5) Compliance dengan mental health regulations. SERVICES INCLUDED: Individual counseling, group workshops, stress management, burnout prevention, conflict resolution, leadership coaching. BOOKING: Annual contract dengan quarterly review. ROI: $3-4 return per $1 invested proven by studies. Contact untuk custom proposal!','corporate package,karyawan,bulk,company,enterprise',8,1,'2025-12-25 17:57:04','2025-12-25 17:57:04'),
(395,'pricing','Cancellation Fee','Kalau cancel mendadak kena charge?','Cancellation Policy: (1) CANCEL >48 JAM sebelum session: FREE cancellation, full refund atau reschedule tanpa charge, (2) CANCEL 24-48 JAM: 50% cancellation fee (or lose 50% of package session), (3) CANCEL <24 JAM: 100% cancellation fee (or lose full package session), (4) NO-SHOW: 100% charge + possible suspension dari booking. EXCEPTIONS: (1) Medical emergency dengan doctor\'s note: Free reschedule, (2) Family emergency (death, hospitalization): Free reschedule dengan proof, (3) Force majeure (natural disaster, govt restriction): Free reschedule. RESCHEDULE: Unlimited reschedules asalkan >48 jam notice. WHY POLICY: Terapis reserve time exclusively untuk Anda, last-minute cancel means slot wasted & terapis kehilangan income. RESPECT: We understand emergencies happen - communicate ASAP. BOOKING: Ambil appointment yang Anda confident bisa attend!','cancellation,cancel,refund,reschedule,batal',9,1,'2025-12-25 17:57:04','2025-12-25 17:57:04'),
(396,'pricing','Family Package','Ada paket untuk sekeluarga?','Family Package: Ya! Diskon khusus untuk family members book bersama. STRUCTURE: (1) 2 FAMILY MEMBERS: 15% discount untuk both (save Rp 225k per person per paket 5), (2) 3 FAMILY MEMBERS: 20% discount untuk all (save Rp 300k per person per paket 5), (3) 4+ FAMILY MEMBERS: 25% discount (save Rp 375k per person). DEFINITION FAMILY: Spouse, children, parents, siblings living dalam satu rumah atau immediate family. EXAMPLE: Family of 4 (ayah, ibu, 2 anak remaja) each ambil paket 5 = normally Rp 13.5 juta, dengan family discount = Rp 10.125 juta, SAVE RP 3.375 JUTA! BENEFITS: (1) Whole family healing together, (2) Better family dynamics, (3) Shared understanding, (4) Cost-effective. ISSUES: Family trauma, parenting challenges, sibling conflicts, family communication. Each person separate session - privacy maintained. Beautiful outcomes: whole families transform together!','family,keluarga,family package,paket keluarga,discount',8,1,'2025-12-25 17:57:04','2025-12-25 17:57:04'),
(397,'pricing','Lifetime Maintenance','Setelah sembuh perlu maintenance? Berapa biayanya?','Maintenance Sessions: Recommended untuk prevent relapse, especially untuk chronic conditions. SCHEDULE: (1) Post-treatment awal: Monthly maintenance for 3 months, (2) Kemudian: Quarterly (every 3 months) for 1 year, (3) Long-term: Bi-annually (6 months) or as-needed. DURATION: Shorter 45-60 menit (vs regular 90 menit). RATE: Maintenance discount 30% off regular rate - Rp 525.000 (vs regular Rp 750k). PURPOSE: (1) Reinforce suggestions, (2) Address any emerging issues early, (3) Update techniques untuk new life circumstances, (4) Booster confidence dan coping skills, (5) Celebrate progress. NEEDED FOR: OCD, addiction recovery, complex anxiety, trauma - conditions dengan relapse risk. NOT NEEDED FOR: Simple phobias once resolved, single incident trauma setelah successful processing. FLEXIBLE: Schedule berdasarkan need, not rigid. Many clients come back 1-2x per year untuk \'tune-up\' dan feeling great!','maintenance,booster,relapse,prevention,follow-up',8,1,'2025-12-25 17:57:05','2025-12-25 17:57:05'),
(398,'pricing','Trial Session Discount','Ada trial session dulu sebelum commit?','Trial/Taster Session: Ya! Kami understand need untuk \'test\' before commit. OFFERING: First session BISA jadi trial - Anda bayar full price Rp 900k untuk extended first session, kemudian JIKA Anda decide continue dalam 48 jam after first session, that Rp 900k COUNT TOWARDS paket price! EXAMPLE: First session Rp 900k (trial) → Anda suka, ambil paket 5 (Rp 3.375k) → Bayar hanya Rp 2.475k (karena first session counted). NO PRESSURE: Jika after first session Anda feel not for you, no obligation to continue. BENEFIT: (1) Experience hipnoterapi firsthand, (2) Meet terapis & build rapport, (3) Assess effectiveness untuk Anda specifically, (4) No wasted money if continue. CONFIDENCE: 85% clients who attend first session continue dengan paket karena experience positive results immediately!','trial,taster,coba,test,percobaan',9,1,'2025-12-25 17:57:05','2025-12-25 17:57:05'),
(399,'pricing','Sliding Scale','Situasi keuangan sulit, ada opsi affordable?','Sliding Scale / Financial Hardship: Ya, kami provide LIMITED sliding scale spots untuk financial hardship cases. CRITERIA: (1) Demonstrated financial need (unemployed, student dengan no family support, low-income, medical bankruptcy), (2) Condition requires urgent treatment (severe anxiety, trauma, suicidal ideation), (3) No insurance or other resources available, (4) Commitment untuk attend sessions regularly. APPLICATION: (1) Fill form menjelaskan situation & financial status, (2) Provide proof jika possible (income statement, student status), (3) Brief interview dengan admin. DISCOUNT: 30-50% off regular rates based on assessment. SLOTS: Limited 5-10 slots per month - first come first served. ALTERNATIVE: (1) Group workshops lebih affordable, (2) Online sessions cheaper, (3) Community mental health clinics (kami provide referrals), (4) Payment plans. MISSION: Mental health adalah right, not privilege. We try to help!','sliding scale,affordable,murah,financial hardship,poor',8,1,'2025-12-25 17:57:05','2025-12-25 17:57:05'),
(400,'category','topic','question','answer','keywords',0,1,'2025-12-25 17:57:05','2025-12-25 17:57:05'),
(401,'faq_general','Definisi Hipnoterapi','Apa itu hipnoterapi?','Hipnoterapi adalah metode terapi yang menggunakan kondisi hipnosis (trance) untuk mengakses pikiran bawah sadar dan melakukan perubahan positif. Dalam kondisi trance, klien tetap sadar penuh tapi sangat rileks dan fokus, sehingga lebih mudah menerima sugesti terapeutik. Hipnoterapi efektif untuk mengatasi berbagai masalah psikologis, kebiasaan buruk, fobia, trauma, dan gangguan psikosomatis. Success rate mencapai 75-90% untuk berbagai kondisi. Sesi berlangsung 60-90 menit dengan pendekatan yang disesuaikan kebutuhan individu.','hipnoterapi,definisi,terapi hipnosis,hipnotis',10,1,'2025-12-25 17:57:06','2025-12-25 17:57:06'),
(402,'faq_general','Keamanan','Apakah hipnoterapi aman?','Ya, hipnoterapi sangat aman bila dilakukan oleh terapis terlatih dan bersertifikat. Anda tidak akan kehilangan kontrol atau melakukan hal yang bertentangan dengan nilai Anda. Kondisi hipnosis adalah state natural yang dialami setiap orang setiap hari (seperti saat melamun atau fokus menonton film). Tidak ada risiko \'terjebak\' dalam hipnosis - Anda bisa keluar kapan saja. Selama 200+ tahun penggunaan klinis, tidak ada kasus efek samping permanen yang terdokumentasi. WHO dan American Psychological Association mengakui hipnoterapi sebagai modalitas terapi yang aman dan efektif.','keamanan,aman,risiko,bahaya,safety',10,1,'2025-12-25 17:57:06','2025-12-25 17:57:06'),
(403,'faq_general','Kehilangan Kontrol','Apakah saya akan kehilangan kontrol saat dihipnosis?','Tidak, ini adalah mitos terbesar tentang hipnosis. Anda TIDAK akan kehilangan kontrol sama sekali. Hipnosis justru adalah kondisi fokus tinggi dimana Anda tetap sadar dan bisa mendengar semua yang dikatakan terapis. Anda bisa menolak sugesti yang tidak sesuai dengan nilai Anda, dan bisa keluar dari kondisi hipnosis kapan saja. Bahkan dalam kondisi trance paling dalam sekalipun, bagian conscious mind Anda tetap berfungsi sebagai \'pengawas\'. Anda tidak akan melakukan atau mengatakan hal yang bertentangan dengan moral atau keyakinan Anda.','kontrol,kehilangan kontrol,terkendali,sadar',10,1,'2025-12-25 17:57:06','2025-12-25 17:57:06'),
(404,'faq_general','Durasi Sesi','Berapa lama satu sesi hipnoterapi?','Satu sesi hipnoterapi berlangsung 60-90 menit, tergantung kompleksitas masalah. Breakdown waktu: (1) Konsultasi & anamnesis: 15-20 menit, (2) Pre-talk & persiapan: 10 menit, (3) Induksi & deepening: 10-15 menit, (4) Terapi inti: 20-30 menit, (5) Awakening & post-talk: 10 menit. Sesi pertama biasanya lebih lama (90-120 menit) karena termasuk assessment lengkap dan building rapport. Untuk kondisi tertentu seperti smoking cessation, bisa menggunakan sesi extended 2-3 jam.','durasi,lama sesi,waktu terapi,berapa lama',9,1,'2025-12-25 17:57:06','2025-12-25 17:57:06'),
(405,'faq_general','Jumlah Sesi','Berapa kali sesi yang dibutuhkan?','Jumlah sesi sangat bervariasi tergantung kondisi: (1) Smoking cessation & simple habits: 1-3 sesi, (2) Fobia spesifik: 2-5 sesi, (3) Anxiety ringan-sedang: 4-6 sesi, (4) Depression, trauma, PTSD: 8-15 sesi, (5) Complex trauma atau personality issues: 15-30 sesi. Rata-rata klien membutuhkan 5-8 sesi untuk perubahan signifikan. Setiap orang merespons berbeda tergantung tingkat suggestibility, motivasi, dan kompleksitas masalah. Kami selalu evaluasi progress setiap 3 sesi dan adjust treatment plan.','jumlah sesi,berapa kali,treatment duration',9,1,'2025-12-25 17:57:06','2025-12-25 17:57:06'),
(406,'faq_general','Biaya Per Sesi','Berapa biaya per sesi hipnoterapi?','Biaya per sesi di Albashiro: (1) Individual session: Rp 500.000-800.000, (2) First consultation (extended): Rp 900.000, (3) Couple therapy: Rp 1.200.000, (4) Online session: Rp 400.000-600.000, (5) Home visit: Rp 1.500.000-2.000.000 (tergantung lokasi). Harga bervariasi berdasarkan pengalaman terapis, durasi sesi, dan kompleksitas kasus. Kami menyediakan paket diskon untuk multiple sessions: Paket 5 sesi (diskon 10%), Paket 10 sesi (diskon 20%). Tersedia payment plan dengan installment 2-3x tanpa bunga.','biaya,harga,cost,tarif,pricing',10,1,'2025-12-25 17:57:07','2025-12-25 17:57:07'),
(407,'faq_general','Persiapan Sebelum Sesi','Apa yang perlu saya persiapkan sebelum sesi?','Persiapan optimal sebelum sesi: (1) Tidur cukup minimal 7 jam malam sebelumnya, (2) Makan ringan 1-2 jam sebelum sesi (jangan perut kosong atau terlalu kenyang), (3) Hindari kafein 3 jam sebelum sesi, (4) Pakai baju nyaman yang tidak ketat, (5) Kosongkan kandung kemih sebelum sesi, (6) Bawa catatan gejala/keluhan jika ada, (7) Bawa obat rutin jika ada (untuk informasi terapis), (8) Set niat dan motivasi yang jelas, (9) Hindari alkohol 24 jam sebelumnya, (10) Datang 10 menit lebih awal untuk adaptasi ruangan dan paperwork.','persiapan,sebelum sesi,preparation,pre-session',8,1,'2025-12-25 17:57:07','2025-12-25 17:57:07'),
(408,'faq_general','Setelah Sesi','Apa yang harus dilakukan setelah sesi?','Aftercare pasca sesi hipnoterapi: (1) Rest 10-15 menit sebelum berkendara, (2) Minum air putih 2-3 gelas untuk rehidrasi, (3) Journaling emosi atau insights yang muncul, (4) Praktik self-hypnosis atau audio rekaman yang diberikan terapis, (5) Hindari keputusan besar dalam 24 jam pertama, (6) Amati perubahan perilaku/perasaan untuk didiskusikan sesi berikutnya, (7) Continue dzikir atau spiritual practice yang diintegrasikan, (8) Hindari alkohol 24 jam pasca sesi, (9) Tidur cukup untuk consolidasi memori terapeutik, (10) Contact terapis jika ada reaksi tidak biasa (sangat jarang terjadi).','aftercare,setelah sesi,post session,perawatan',8,1,'2025-12-25 17:57:07','2025-12-25 17:57:07'),
(409,'faq_general','Success Rate Anxiety','Berapa success rate untuk anxiety?','Success rate hipnoterapi untuk anxiety disorders sangat tinggi: (1) Generalized Anxiety Disorder (GAD): 75-80% improvement setelah 8-10 sesi, (2) Panic Disorder: 80-85% reduction dalam panic attacks setelah 6-8 sesi, (3) Social Anxiety: 70-75% improvement dalam 8-12 sesi, (4) Specific Anxiety: 85-90% dalam 4-6 sesi. Meta-analysis dari 15 studies menunjukkan hipnoterapi 3x lebih efektif dibanding CBT untuk anxiety reduction. Hasil optimal dicapai ketika dikombinasi dengan homework (self-hypnosis, breathing exercises) dan lifestyle changes.','success rate,anxiety,tingkat keberhasilan,efektivitas',9,1,'2025-12-25 17:57:07','2025-12-25 17:57:07'),
(410,'faq_general','Mitos Mind Control','Benarkah hipnoterapis bisa mengontrol pikiran saya?','MITOS! Ini adalah misconception terbesar dari film-film Hollywood. Fakta: (1) Hipnoterapis TIDAK bisa mengontrol pikiran atau tindakan Anda, (2) Anda tetap aware dan bisa menolak sugesti apapun, (3) Anda TIDAK akan mengungkap rahasia yang tidak ingin dibagi, (4) Anda TIDAK akan melakukan hal yang bertentangan dengan nilai moral Anda, (5) Hipnosis adalah kerjasama sukarela - jika Anda tidak mau, tidak akan terjadi. Hipnoterapi adalah guided meditation yang kolaboratif, bukan mind control. Clinical hypnosis sangat berbeda dengan stage hypnosis yang tujuannya entertainment.','mitos,mind control,kontrol pikiran,misconception',10,1,'2025-12-25 17:57:07','2025-12-25 17:57:07'),
(411,'faq_general','Bandingkan Psikolog','Apa beda hipnoterapi dengan psikolog?','Perbedaan utama: (1) PENDEKATAN: Psikolog fokus pada talk therapy & conscious mind, hipnoterapi bekerja dengan subconscious mind, (2) DURASI: Psikolog umumnya butuh 20-40 sesi, hipnoterapi 5-15 sesi untuk hasil serupa, (3) METODE: Psikolog menggunakan CBT, psychoanalysis, dst; hipnoterapi menggunakan trance state untuk akselerasi perubahan, (4) LISENSI: Keduanya butuh sertifikasi profesional (psikolog S1/S2 Psikologi, hipnoterapis certified training), (5) KOLABORASI: Keduanya bisa dikombinasi - banyak psikolog mengintegrasikan hipnosis dalam praktik. Pilihan tergantung preferensi personal dan jenis masalah.','psikolog,perbedaan,banding,comparison',9,1,'2025-12-25 17:57:08','2025-12-25 17:57:08'),
(412,'faq_general','Bandingkan Psikiater','Hipnoterapi vs psikiater, lebih baik mana?','Perbandingan: (1) FOKUS: Psikiater adalah medical doctor yang fokus pada aspek biological & medication, hipnoterapi fokus pada psychological & behavioral change tanpa obat, (2) TREATMENT: Psikiater prescribe obat antidepressant/anxiolytic, hipnoterapi menggunakan sugesti & subconscious reprogramming, (3) KONDISI: Psikiater untuk severe mental illness (schizophrenia, bipolar), hipnoterapi untuk anxiety, phobia, habits, trauma, (4) KOLABORASI: Bisa dikombinasi - hipnoterapi complement medication untuk hasil lebih cepat, (5) BIAYA: Psikiater Rp 300-800rb + obat bulanan, hipnoterapi Rp 500-800rb per sesi tanpa obat. Konsultasi psikiater dulu jika ada riwayat psychosis atau severe depression.','psikiater,medication,obat,comparison',9,1,'2025-12-25 17:57:08','2025-12-25 17:57:08'),
(413,'faq_general','Online vs Offline','Bisa hipnoterapi online? Efektif gak?','Ya, hipnoterapi online sangat efektif! Research menunjukkan online hypnotherapy memiliki efficacy rate 70-85%, hanya 5-10% lebih rendah dari face-to-face. KEUNGGULAN ONLINE: (1) Kenyamanan di rumah = lebih rileks, (2) No travel time, (3) Lebih affordable (Rp 400-600rb vs Rp 500-800rb), (4) Akses ke terapis terbaik di Indonesia. SYARAT: (1) Koneksi internet stabil, (2) Ruangan private dan quiet, (3) Headphones berkualitas baik, (4) Duduk/berbaring nyaman, (5) Device dengan camera untuk eye contact. Tidak cocok untuk: severe trauma yang butuh physical grounding, atau klien yang mudah distracted di rumah.','online,virtual,zoom,teletherapy,effectiveness',9,1,'2025-12-25 17:57:08','2025-12-25 17:57:08'),
(414,'faq_general','Hipnosis Panggung','Apa beda hipnosis panggung dengan hipnoterapi?','Perbedaan fundamental: (1) TUJUAN: Stage hypnosis untuk entertainment, hipnoterapi untuk healing & personal development, (2) METODE: Stage hypnotist pilih volunteer yang highly suggestible & extroverted, hipnoterapi work dengan semua tipe personality, (3) SUGESTI: Stage hypnosis pakai sugesti lucu/embarrassing untuk show, hipnoterapi pakai sugesti terapeutik yang empowering, (4) ETHICS: Stage hypnosis sering abaikan dignity subjek, hipnoterapi bound by strict ethical code, (5) SKILL: Stage hypnotist fokus pada showmanship, clinical hypnotherapist butuh training psikologi mendalam 300-500 jam. Clinical hypnotherapy adalah evidence-based healthcare, bukan entertainment.','stage hypnosis,hipnosis panggung,beda,entertainment',8,1,'2025-12-25 17:57:08','2025-12-25 17:57:08'),
(415,'faq_general','Meditasi vs Hipnoterapi','Apa bedanya meditasi dengan hipnoterapi?','Perbedaan kunci: (1) STRUKTUR: Meditasi self-directed & non-goal oriented, hipnoterapi guided & goal-oriented dengan target spesifik, (2) FOKUS: Meditasi untuk mindfulness & present moment awareness, hipnoterapi untuk problem-solving & behavioral change, (3) BRAIN STATE: Keduanya induce alpha-theta waves, tapi hipnoterapi lebih targeted pada subconscious reprogramming, (4) DURATION: Meditasi butuh praktik harian bertahun-tahun untuk transformasi, hipnoterapi bisa hasil cepat 5-10 sesi, (5) GUIDANCE: Meditasi bisa sendiri, hipnoterapi butuh trained therapist. KOMPLEMENTER: Keduanya bisa dikombinasi - meditasi as daily practice + hipnoterapi for specific issues.','meditasi,meditation,mindfulness,perbedaan',8,1,'2025-12-25 17:57:08','2025-12-25 17:57:08'),
(416,'faq_general','Pregnancy Safety','Apakah hipnoterapi aman untuk ibu hamil?','Ya, hipnoterapi sangat aman dan bahkan recommended untuk ibu hamil! MANFAAT: (1) Mengurangi morning sickness, (2) Manage pregnancy anxiety, (3) Persiapan hypnobirthing untuk persalinan lebih mudah, (4) Kontrol nyeri tanpa medication, (5) Reduce risk of postpartum depression. EVIDENCE: Studies menunjukkan ibu hamil yang menggunakan hipnosis memiliki 50% less need for pain medication saat melahirkan, shorter labor duration, dan lower c-section rate. SAFE BECAUSE: Tidak ada obat, tidak ada physical manipulation, hanya relaksasi dan positive suggestions. Trimester 2-3 paling ideal. Kontraindikasi: history of severe mental illness atau high-risk pregnancy (konsultasi dokter dulu).','pregnancy,hamil,kehamilan,ibu hamil,safety',9,1,'2025-12-25 17:57:09','2025-12-25 17:57:09'),
(417,'faq_general','Children Hypnotherapy','Apakah anak-anak bisa dihipnoterapi?','Ya! Anak-anak sebenarnya SANGAT responsive terhadap hipnoterapi karena imagination mereka masih sangat aktif. AGE RANGE: (1) 5-8 tahun: menggunakan play therapy & storytelling, (2) 9-12 tahun: kombinasi play & direct suggestion, (3) 13-17 tahun: pendekatan seperti dewasa tapi lebih conversational. KONDISI YANG TREATABLE: Bedwetting, nail biting, exam anxiety, sleep problems, behavioral issues, fear/phobias, ADHD symptoms. SUCCESS RATE: 80-90% untuk habit issues. SYARAT: (1) Parental consent wajib, (2) Parent bisa hadir dalam sesi (untuk anak <12), (3) Anak willing & cooperative, (4) Masalah bukan organic/medical. Durasi sesi lebih singkat: 30-45 menit.','children,anak,kids,pediatric,child hypnotherapy',9,1,'2025-12-25 17:57:09','2025-12-25 17:57:09'),
(418,'faq_general','Smoking Cessation Rate','Berapa success rate untuk berhenti merokok?','Hipnoterapi memiliki success rate tertinggi untuk smoking cessation: (1) Single session: 30-40% quit permanently, (2) 2-3 sessions: 60-70% quit rate, (3) 5 sessions dengan follow-up: 80-85% still smoke-free after 1 year. COMPARISON: Willpower alone: 5%, Nicotine patches: 15-20%, Prescription drugs: 25-30%, Behavioral therapy: 30-40%, Hypnotherapy: 60-85%. META-ANALYSIS dari University of Iowa (2007) pada 600,000 smokers menunjukkan hipnosis 3x lebih efektif dari nicotine replacement. METODE: Subconscious reprogramming untuk asosiasi negatif terhadap rokok + strengthening inner motivation + relapse prevention suggestions.','smoking,merokok,berhenti merokok,quit smoking',10,1,'2025-12-25 17:57:09','2025-12-25 17:57:09'),
(419,'faq_general','Insomnia Treatment','Bisa ngatasi insomnia dengan hipnoterapi?','Ya, hipnoterapi sangat efektif untuk insomnia! SUCCESS RATE: 70-80% klien mengalami significant improvement dalam 4-6 sesi. CARA KERJA: (1) Identifikasi root cause (stress, anxiety, trauma, bad sleep hygiene), (2) Subconscious reprogramming untuk asosiasi positif dengan sleep, (3) Teaching self-hypnosis for sleep onset, (4) Anchoring relaxation response, (5) Sleep hygiene education. RESEARCH: Stanford study menunjukkan 80% chronic insomnia patients tidur lebih cepat dan nyenyak setelah 6 sesi hipnoterapi. BONUS: Audio self-hypnosis diberikan untuk didengar setiap malam. Hasil bertahan long-term karena mengajarkan skill, bukan dependency pada obat.','insomnia,susah tidur,sleep disorder,gangguan tidur',9,1,'2025-12-25 17:57:09','2025-12-25 17:57:09'),
(420,'faq_general','Weight Loss','Apakah hipnoterapi efektif untuk diet dan turun berat badan?','Ya, hipnoterapi adalah adjunct therapy yang powerful untuk weight loss! SUCCESS RATE: 60-75% klien lose 5-15kg dalam 3-6 bulan dengan hypnotherapy + diet + exercise. CARA KERJA: (1) Address emotional eating & stress eating, (2) Reprogram relationship dengan food, (3) Increase motivation untuk exercise, (4) Install healthy eating habits di subconscious, (5) Manage cravings & portion control, (6) Boost self-esteem & body image. TIDAK BISA: Hipnoterapi TIDAK bisa menurunkan berat badan tanpa perubahan diet & aktivitas fisik - ini bukan magic! BEST RESULTS: Kombinasi dengan nutritionist + exercise program. Average weight loss: 1-2kg per minggu secara sustainable.','weight loss,diet,turun berat badan,obesitas,kurus',8,1,'2025-12-25 17:57:10','2025-12-25 17:57:10'),
(421,'faq_general','Pain Management','Bisa hipnosis untuk mengurangi nyeri kronis?','Ya! Hipnoterapi adalah salah satu metode pain management paling efektif tanpa obat. EVIDENCE: (1) Clinical trials menunjukkan 50-80% reduction dalam chronic pain, (2) Efektif untuk: migraine, fibromyalgia, arthritis, back pain, cancer pain, (3) AMA (American Medical Association) officially approved hypnosis untuk pain management sejak 1958. CARA KERJA: (1) Gate control theory - hipnosis \'close the gate\' untuk pain signals, (2) Endorphin release, (3) Dissociation dari pain, (4) Reframing pain sensation. TIDAK REPLACE: Medical treatment untuk underlying condition, tapi reduce need for pain medication hingga 50%. Session 6-10 kali untuk chronic pain, maintenance monthly.','pain,nyeri,chronic pain,pain management',9,1,'2025-12-25 17:57:10','2025-12-25 17:57:10'),
(422,'faq_general','Trauma Healing','Berapa lama proses penyembuhan trauma dengan hipnoterapi?','Timeline trauma healing bervariasi tergantung severity: (1) Single incident trauma (accident, assault): 6-10 sesi, 2-3 bulan, (2) Complex trauma (childhood abuse, long-term): 15-30 sesi, 6-12 bulan, (3) PTSD dengan flashbacks: 12-20 sesi, 4-6 bulan, (4) Developmental trauma: 20-40 sesi, 9-18 bulan. METODE: Regression therapy, reprocessing traumatic memories, parts therapy, ego strengthening, resource building. PROGRESS: Biasanya symptom reduction 30-40% setelah 5 sesi, 60-70% setelah 10 sesi. PENTING: Trauma healing is not linear - ada ups and downs. Butuh patience dan commitment. Dikombinasi dengan EMDR atau somatic therapy untuk hasil optimal.','trauma,PTSD,healing,traumatic,penyembuhan',9,1,'2025-12-25 17:57:10','2025-12-25 17:57:10'),
(423,'faq_general','Referral Discount','Apakah ada program referral?','Ya! Program referral Albashiro: (1) REFERRER: Dapatkan diskon 20% untuk sesi berikutnya setiap kali refer teman yang book sesi, (2) REFEREE: Teman yang direferral dapat diskon 10% untuk first session, (3) UNLIMITED: Tidak ada limit berapa banyak orang yang bisa Anda refer, (4) STACK: Diskon bisa diakumulasi hingga 50% off untuk satu sesi, (5) SHARING: Bonus sesi gratis setiap 5 referral yang successfully book. CARA: Minta referral code dari terapis atau admin, share ke teman, mereka mention code saat booking. Win-win solution untuk spread mental health awareness!','referral,diskon,discount,program,promo',8,1,'2025-12-25 17:57:10','2025-12-25 17:57:10'),
(424,'faq_general','Emergency Session','Apakah tersedia sesi darurat untuk kasus urgent?','Ya, kami provide emergency session untuk urgent cases: (1) CRITERIA: Severe panic attack, acute trauma response, suicidal ideation (as adjunct to psychiatric care), severe anxiety crisis, (2) AVAILABILITY: Same-day atau next-day appointment jika ada slot, (3) BIAYA: Emergency surcharge 50% dari regular rate, (4) DURASI: 60-90 menit, (5) AKSES: WhatsApp/phone ke admin untuk emergency scheduling. PENTING: Jika psychiatric emergency (active suicidal, psychotic episode), segera ke UGD atau call 119 dulu. Hipnoterapi adalah supportive care, not replacement untuk emergency psychiatric intervention. Kami work closely dengan psychiatrist untuk co-manage emergency cases.','emergency,darurat,urgent,crisis,panic',9,1,'2025-12-25 17:57:10','2025-12-25 17:57:10'),
(425,'faq_general','Home Visit Service','Apakah ada layanan home visit?','Ya! Home visit service tersedia dengan conditions: (1) AREA: Jakarta, Bogor, Depok, Tangerang, Bekasi (Jabodetabek), (2) BIAYA: Rp 1.500.000-2.500.000 tergantung distance + transportation, (3) SYARAT: Minimum 90-minute session, private quiet room, stable internet for paperwork, (4) COCOK UNTUK: Mobility issues, agoraphobia, post-surgery patients, elderly, high-profile clients yang butuh privacy, (5) BOOKING: Minimum 3 hari advance notice, subject to therapist availability. BENEFIT: Maximum comfort dan privacy, no travel stress, bisa sesi di environment familiar. Paket 5 home visits dapat diskon 15%.','home visit,visit,rumah,datang ke rumah,mobile',8,1,'2025-12-25 17:57:11','2025-12-25 17:57:11'),
(426,'faq_general','Group Therapy','Apakah ada sesi terapi kelompok?','Ya, group hypnotherapy available untuk kondisi tertentu: (1) JENIS: Stress management workshop, smoking cessation group, weight loss support group, anxiety management, (2) SIZE: 5-12 orang per group untuk effectiveness, (3) BIAYA: Rp 250.000-400.000 per person per session (lebih affordable), (4) DURASI: 90-120 menit, typically 4-6 sessions program, (5) STRUKTUR: Psychoeducation + group trance + sharing session. BENEFIT: Cost-effective, peer support, learn from others, normalize experiences. TIDAK COCOK untuk: Severe trauma, deep personal issues, privacy concerns. Schedule: Biasanya monthly workshop, check website untuk upcoming sessions.','group,kelompok,group therapy,workshop',7,1,'2025-12-25 17:57:11','2025-12-25 17:57:11'),
(427,'faq_general','Corporate Package','Apakah ada paket untuk karyawan perusahaan?','Ya! Corporate wellness package Albashiro: (1) STRESS MANAGEMENT WORKSHOP: 2-3 jam untuk 20-30 karyawan, Rp 10-15 juta, (2) BURNOUT PREVENTION PROGRAM: 6 sessions, Rp 30 juta untuk 30 karyawan, (3) LEADERSHIP HYPNOSIS: Confidence & public speaking untuk leaders, custom package, (4) PRODUCTIVITY BOOTCAMP: Focus & procrastination program, (5) INDIVIDUAL COUNSELING: Paket 50-100 sesi untuk employee assistance program. BENEFIT: Reduce absenteeism, increase productivity 15-30%, improve workplace morale, retention. CUSTOMIZABLE: Bisa adjust content sesuai industry & company needs. ROI studies show $3-4 return per $1 invested in mental health programs.','corporate,perusahaan,karyawan,workplace,employee',8,1,'2025-12-25 17:57:11','2025-12-25 17:57:11'),
(428,'conditions','Generalized Anxiety Disorder','Apa itu GAD dan bisa disembuhin?','Generalized Anxiety Disorder (GAD) adalah kondisi kecemasan berlebihan dan persisten tentang berbagai hal tanpa alasan jelas, berlangsung minimal 6 bulan. SYMPTOMS: Restlessness, mudah lelah, sulit konsentrasi, irritability, muscle tension, sleep disturbance, excessive worry. PREVALENCE: 5-7% populasi, lebih umum pada wanita. TREATMENT: Hipnoterapi menggunakan anxiety reduction techniques: (1) Deep relaxation training, (2) Cognitive restructuring sugesti, (3) Worry management, (4) Mindfulness integration, (5) Self-hypnosis untuk daily practice. SUCCESS RATE: 70-80% significant reduction dalam 8-12 sesi. KOMBINASI: Optimal jika combined dengan CBT techniques dan lifestyle changes. Long-term remission achievable dengan maintenance sessions.','GAD,anxiety,kecemasan,generalized anxiety',9,1,'2025-12-25 17:57:11','2025-12-25 17:57:11'),
(429,'conditions','Panic Disorder','Gimana cara ngatasi panic attack dengan hipnoterapi?','Panic Disorder adalah kondisi panic attack recurrent yang unexpected, dengan intense fear dan physical symptoms. SYMPTOMS: Palpitations, sweating, trembling, shortness of breath, chest pain, nausea, dizziness, fear of dying. TREATMENT: (1) Desensitization - exposure dalam kondisi aman, (2) Anchoring calm state untuk interrupt panic, (3) Breathing retraining dengan hypnotic suggestion, (4) Cognitive reframe tentang bodily sensations, (5) Ego strengthening untuk confidence. SUCCESS: 80-85% experience 70%+ reduction dalam panic frequency setelah 6-8 sesi. BONUS: Teaching self-hypnosis technique to abort panic attack onset. Maintenance: Monthly booster sessions jika needed.','panic,panic attack,panik,panic disorder,serangan panik',10,1,'2025-12-25 17:57:11','2025-12-25 17:57:11'),
(430,'conditions','Social Anxiety','Fobia sosial parah bisa sembuh total gak?','Social Anxiety Disorder (SAD) adalah ketakutan intense akan judgment sosial dan embarrassment. SEVERITY: Mild (presentasi), Moderate (conversations), Severe (tidak bisa keluar rumah). TREATABLE: Ya! Bahkan severe cases. SUCCESS RATE: 70-80% improvement dengan 10-15 sesi. APPROACH: (1) Graduated exposure dalam trance, (2) Confidence building suggestions, (3) Reframing negative self-perceptions, (4) Social skills visualization, (5) Past success amplification. TIMELINE: Mild: 4-6 sesi, Moderate: 8-12 sesi, Severe: 15-20 sesi. TESTIMONIAL: Klien yang tidak bisa meeting kini jadi public speaker. Dikombinasi dengan behavioral experiments di real life untuk generalization.','social anxiety,fobia sosial,takut orang,social phobia',9,1,'2025-12-25 17:57:12','2025-12-25 17:57:12'),
(431,'conditions','OCD Treatment','Hipnoterapi bisa untuk OCD gak?','Ya, hipnoterapi efektif sebagai adjunct treatment untuk OCD (Obsessive-Compulsive Disorder). OCD ADALAH: Intrusive thoughts (obsessions) + repetitive behaviors (compulsions). Common types: Contamination, checking, symmetry, intrusive thoughts. TREATMENT: (1) Subconscious reprocessing obsessive thoughts, (2) Anxiety reduction sehingga compulsions tidak needed, (3) Installing alternative coping mechanisms, (4) Ego strengthening, (5) Visualization of control over compulsions. EFFICACY: 50-60% symptom reduction sebagai standalone, 70-80% jika combined dengan ERP (Exposure Response Prevention) dan SSRI medication. DURASI: 15-25 sesi. REALISTIC: OCD adalah chronic condition - hipnoterapi manage symptoms significantly tapi biasanya not complete cure.','OCD,obsessive compulsive,kompulsif,obsesi',8,1,'2025-12-25 17:57:12','2025-12-25 17:57:12'),
(432,'conditions','Health Anxiety','Saya selalu takut sakit parah, bisa dibantu?','Health Anxiety (Hypochondriasis/Illness Anxiety Disorder) adalah ketakutan excessive bahwa Anda memiliki serious illness meskipun medical tests normal. SYMPTOMS: Frequent body checking, excessive medical appointments, googling symptoms, reassurance-seeking. CAUSES: Past trauma, loss of loved one, personality traits. TREATMENT: (1) Reality testing suggestions, (2) Anxiety tolerance building, (3) Distraction & refocusing techniques, (4) Reframe bodily sensations, (5) Trust in body\'s health. SUCCESS: 65-75% significant improvement dalam 8-12 sesi. APPROACH: Gradual reduction dalam checking behaviors + acceptance suggestions. IMPORTANT: Medical checkup pertama untuk rule out actual medical issues, baru terapi.','health anxiety,takut sakit,hipokondria,hypochondria',8,1,'2025-12-25 17:57:12','2025-12-25 17:57:12'),
(433,'conditions','Acrophobia','Takut ketinggian parah bisa hilang total?','Acrophobia (takut ketinggian) adalah salah satu fobia yang PALING treatable dengan hipnoterapi! SUCCESS RATE: 85-90% dalam 3-6 sesi. TREATMENT: (1) Systematic desensitization - visualisasi bertahap dari ketinggian rendah ke tinggi dalam kondisi rileks, (2) Reprocessing past traumatic fall experience jika ada, (3) Installing confidence dan balance, (4) Anchoring calm state, (5) Real-world graduated exposure. TIMELINE: Session 1-2: Visualisasi, Session 3-4: Virtual reality exposure, Session 5-6: Real-world practice dengan therapist. TESTIMONIAL: Klien yang tidak bisa naik tangga kini bisa naik pesawat dan mendaki gunung. Hasil biasanya permanent dengan occasional refresher.','acrophobia,takut ketinggian,height,phobia ketinggian',9,1,'2025-12-25 17:57:12','2025-12-25 17:57:12'),
(434,'conditions','Agoraphobia','Takut keluar rumah bisa sembuh dengan hipnosis?','Agoraphobia adalah ketakutan akan tempat/situasi dimana escape sulit atau help tidak available. MANIFESTASI: Takut public transport, open spaces, enclosed spaces, crowds, atau bahkan keluar rumah sendiri. Often co-occurs dengan panic disorder. SEVERITY: 40% agoraphobics menjadi housebound. TREATMENT: (1) Safety building suggestions, (2) Graduated exposure imaginal dulu, lalu in vivo, (3) Reprocessing traumatic panic attacks, (4) Anchoring calm untuk trigger situations, (5) Confidence building. SUCCESS: 70-80% dapat resume normal activities dalam 12-20 sesi. GRADUAL: Mulai dari depan rumah → 10m dari rumah → keliling kompleks → mall → public transport. Butuh patience dan commitment.','agoraphobia,takut keluar,takut tempat ramai,housebound',9,1,'2025-12-25 17:57:12','2025-12-25 17:57:12'),
(435,'conditions','Claustrophobia','Takut ruang sempit gimana ngatasinnya?','Claustrophobia (takut ruang tertutup/sempit) sangat umum dan highly treatable. TRIGGERS: Lift, MRI machine, pesawat, kamar kecil, kerumunan. SYMPTOMS: Panic, palpitations, sweating, fear of suffocation saat di confined space. TREATMENT: (1) Desensitization bertahap - visualisasi ruang sempit dalam kondisi deeply relaxed, (2) Reframe \'sempit\' as \'cozy\' dan \'safe\', (3) Breathing control suggestions, (4) Installing eject button mental untuk sense of control. SUCCESS RATE: 80-90% dalam 4-6 sesi. PRACTICE: Homework includes graduated exposure - mulai dari lemari kecil, kemudian lift dengan pintu terbuka, dst. Most clients dapat masuk lift dan pesawat tanpa anxiety setelah 6 sesi.','claustrophobia,takut sempit,takut lift,ruang sempit,elevator',9,1,'2025-12-25 17:57:13','2025-12-25 17:57:13'),
(436,'conditions','Trypanophobia','Takut jarum suntik sampai gak bisa vaksin, bisa dibantu?','Trypanophobia (needle phobia) adalah salah satu phobia paling umum, affecting 10% populasi. IMPACT: Menghindari medical care, tidak vaksin, risk kesehatan. TREATMENT: (1) Desensitization - visualisasi jarum dari jauh kemudian dekat, (2) Dissociation technique - mental pergi ke \'happy place\' saat disuntik, (3) Pain threshold elevation dengan analgesia suggestions, (4) Reprocessing traumatic injection di masa lalu, (5) Anchoring calm state. SUCCESS: 75-85% dapat injection tanpa significant anxiety dalam 3-5 sesi. QUICK RESULT: Often single session hypnosis sebelum vaksinasi sudah dramatically reduce anxiety. Technique bisa digunakan untuk dental procedures juga.','trypanophobia,takut jarum,needle phobia,suntikan,injection',9,1,'2025-12-25 17:57:13','2025-12-25 17:57:13'),
(437,'conditions','Aviophobia','Takut naik pesawat bisa disembuhin?','Aviophobia (fear of flying) mempengaruhi 25% populasi dalam berbagai tingkat. TYPES: Takut crash, takut ketinggian, claustrophobia, loss of control, turbulence. IMPACT: Career limitation, tidak bisa liburan, relationship strain. TREATMENT: (1) Education tentang aviation safety - kognitif reframing, (2) Systematic desensitization - visualisasi tiap tahap flight, (3) Anchoring calm saat turbulence, (4) Hypnotic rehearsal entire flight, (5) In vivo exposure dengan support. SUCCESS: 70-80% dapat terbang comfortably dalam 6-10 sesi. BOOSTER: Session khusus 1-2 hari sebelum flight untuk maximum confidence. Banyak client kemudian enjoy traveling dan naik pesawat jadi routine.','aviophobia,takut terbang,fear of flying,takut pesawat',9,1,'2025-12-25 17:57:13','2025-12-25 17:57:13'),
(438,'conditions','Emetophobia','Takut muntah mengganggu hidup saya, bisa dibantu?','Emetophobia (fear of vomiting) adalah salah satu phobia paling debilitating namun underreported. IMPACT: Menghindari makanan, obsessive checking, panic saat nausea, pregnancy avoidance, social withdrawal. PREVALENCE: 0.1-8% population, underdiagnosed karena malu. TREATMENT: (1) Desensitization terhadap nausea sensations dan vomit-related stimuli, (2) Reframing vomiting as natural protective mechanism not catastrophic, (3) Anxiety reduction, (4) Reprocessing traumatic vomiting incident, (5) Exposure imaginal dan eventually graduated in vivo. SUCCESS: 60-70% significant improvement dalam 10-15 sesi. CHALLENGING: Often co-occurs dengan eating disorder dan health anxiety, butuh comprehensive approach.','emetophobia,takut muntah,phobia muntah,vomit fear',8,1,'2025-12-25 17:57:13','2025-12-25 17:57:13'),
(439,'conditions','Glossophobia','Public speaking anxiety parah, bisa hipnoterapi?','Glossophobia (public speaking fear) adalah salah satu phobia paling umum - 75% populasi! MANIFESTATIONS: Trembling, sweating, mental blank, panic sebelum/saat presentasi. IMPACT: Career limitation, academic struggles. TREATMENT: (1) Confidence building dan ego strengthening, (2) Visualization successful presentations berulang kali, (3) Anchoring confident state, (4) Reframe audience as supportive not judgemental, (5) Performance anxiety reduction, (6) Hypnotic rehearsal. SUCCESS RATE: 80-90% dalam 5-8 sesi. PRACTICAL: Practice dengan recorded video review + real presentations dengan incremental difficulty. Testimonial: Klien dari tidak bisa presentasi kini jadi trainer dan public speaker.','glossophobia,public speaking,takut bicara,presentation anxiety',9,1,'2025-12-25 17:57:13','2025-12-25 17:57:13'),
(440,'conditions','Cynophobia','Anak saya takut anjing parah, bisa terapi?','Cynophobia (dog phobia) sangat umum terutama pada children setelah dog attack atau traumatic encounter. SYMPTOMS: Panic saat lihat/dengar anjing, avoidance, nightmare tentang anjing. TREATMENT CHILDREN: (1) Play therapy dengan stuffed dogs, (2) Storytelling dengan friendly dog characters, (3) Imagination desensitization bertahap, (4) Installing bravery suggestions, (5) Eventually exposure dengan real calm dog. SUCCESS: 80-90% children overcome dog fear dalam 4-8 sesi karena children sangat responsive terhadap imagery. DURATION: 30-45 menit per session untuk anak. Parental involvement penting - jangan reinforce fear dengan overprotection.','cynophobia,takut anjing,dog phobia,anak takut anjing',8,1,'2025-12-25 17:57:14','2025-12-25 17:57:14'),
(441,'conditions','Major Depression','Depresi berat bisa diterapi dengan hipnosis?','Major Depressive Disorder (MDD) dapat dibantu dengan hipnoterapi sebagai adjunct treatment. SYMPTOMS: Persistent sadness, anhedonia, fatigue, appetite/sleep changes, worthlessness, suicidal ideation. APPROACH: (1) Ego strengthening untuk rebuild self-esteem, (2) Pleasant imagery dan future pacing untuk hope, (3) Subconscious exploration untuk unresolved issues, (4) Energy & motivation suggestions, (5) Reframe negative cognitions. EFFICACY: 40-60% improvement sebagai standalone, 70-80% jika combined dengan antidepressants dan CBT. LIMITATIONS: Severe depression dengan suicidal risk harus managed by psychiatrist first. TIMELINE: 12-20 sesi, dengan weekly frequency awalnya. Maintenance monthly untuk prevent relapse.','depression,depresi,major depression,depressive disorder',8,1,'2025-12-25 17:57:14','2025-12-25 17:57:14'),
(442,'conditions','PTSD Complex','PTSD kompleks dari trauma masa kecil, bisa sembuh?','Complex PTSD (C-PTSD) dari prolonged trauma (abuse, neglect) adalah salah satu kondisi paling challenging tapi treatable. SYMPTOMS: PTSD symptoms + emotional dysregulation, negative self-concept, relationship difficulties. TREATMENT: (1) Phase 1 (Stabilization): Safety, grounding, affect regulation - 5-10 sesi, (2) Phase 2 (Trauma Processing): Regression therapy, abreaction, reprocessing - 10-20 sesi, (3) Phase 3 (Integration): Meaning-making, identity rebuilding - 5-10 sesi. TIMELINE: 20-40 sesi over 9-18 bulan. SUCCESS: 60-70% achieve significant symptom reduction. CAUTION: Not rush - premature trauma processing dapat re-traumatize. Need skilled trauma therapist.','PTSD,complex PTSD,trauma,childhood trauma,abuse',9,1,'2025-12-25 17:57:14','2025-12-25 17:57:14'),
(443,'islamic','Hukum Hipnoterapi','Apakah hipnoterapi halal menurut Islam?','Hipnoterapi HALAL dengan syarat tertentu menurut majority ulama kontemporer. DALIL HALAL: (1) Asal terapi adalah mubah selama tidak melanggar syariat, (2) Menjaga kesehatan jiwa adalah wajib - hipnoterapi adalah cara, (3) Tidak ada magic/syirik involved - murni psychological technique. SYARAT HALAL: (1) Niat untuk kesembuhan lillahi ta\'ala, (2) Terapis Muslim atau minimal respect Islamic values, (3) Tidak melanggar aurat - perempuan dengan terapis perempuan atau mahram present, (4) Tidak ada unsur syirik/memanggil jin, (5) Sugesti tidak bertentangan dengan akidah. FATWA: MUI beberapa daerah menyatakan halal dengan syarat. PENDAPAT ULAMA: Dr. Aidh al-Qarni mendukung, Sheikh Assim al-Hakeem dengan syarat ketat.','halal,haram,hukum,islamic,syariah',10,1,'2025-12-25 17:57:14','2025-12-25 17:57:14'),
(444,'islamic','Dzikir Subhanallah','Bagaimana mengintegrasikan Subhanallah dalam terapi?','Subhanallah (Maha Suci Allah) digunakan pada tahap deepening dan terapi inti untuk ketenangan maksimal. METHOD: (1) Klien dipandu mengucap Subhanallah 33x dengan ritme pernapasan - exhale \'Subhanallah\', (2) Fokus pada makna: mensucikan Allah dari segala kekurangan, (3) Merasakan kedamaian karena pasrah pada kesempurnaan Allah, (4) Visualisasi cahaya/kedamaian setiap dzikir. SCIENTIFIC: Studies menunjukkan dzikir menurunkan cortisol 30-40%, meningkatkan alpha waves (relaksasi), aktivasi prefrontal cortex (emotional regulation). SPIRITUAL: Mendekatkan diri kepada Allah, meningkatkan tawakkal. Powerful untuk anxiety dan overthinking karena shift focus dari masalah ke kebesaran Allah.','subhanallah,dzikir,tasbih,islamic therapy',9,1,'2025-12-25 17:57:15','2025-12-25 17:57:15'),
(445,'islamic','Dzikir Alhamdulillah','Kapan menggunakan Alhamdulillah dalam sesi?','Alhamdulillah (Segala puji bagi Allah) diintegrasikan untuk gratitude cultivation dan positive reframing. USAGE: (1) Awal sesi: Alhamdulillah untuk nikmat kesempatan terapi, (2) Saat reframing negative situations: Cari hikmah dan ucap Alhamdulillah, (3) Post-therapy: Alhamdulillah untuk progress dan strength, (4) 33x repetition untuk kondisi rileks mendalam. BENEFITS: Neuroplasticity research shows gratitude practice rewires brain untuk positivity, meningkatkan serotonin dan dopamine. SPIRITUAL: Meningkatkan syukur, qanaah, dan ridha terhadap takdir Allah. Effective untuk depression dan negative thinking patterns. Klien yang rutin praktik Alhamdulillah report 50% lebih bahagia dalam 4 minggu.','alhamdulillah,dzikir,gratitude,syukur,praise',9,1,'2025-12-25 17:57:15','2025-12-25 17:57:15'),
(446,'islamic','Dzikir La Ilaha Illallah','Bagaimana La Ilaha Illallah digunakan dalam terapi?','La Ilaha Illallah (Tiada Tuhan selain Allah) adalah kalimat tauhid terkuat untuk spiritual grounding dan ego dissolution. USAGE: (1) Trauma release: Melepaskan attachment kepada selain Allah, (2) Addiction: Shift dependency dari substance ke Allah, (3) Fear: Menguatkan keimanan bahwa hanya Allah yang control segalanya, (4) Identity issues: Core identity adalah abdullah (hamba Allah). METHOD: 100x repetition dengan focus pada makna - negating semua selain Allah, affirming only Allah. NEUROSCIENCE: Repetitive phrase induces deep trance state (theta waves), reduce DMN (default mode network) activity = ego dissolution. SPIRITUAL: Taqarrub kepada Allah, peningkatan iman. Powerful untuk semua kondisi karena address spiritual root.','la ilaha illallah,tauhid,kalimat tauhid,syahadat',10,1,'2025-12-25 17:57:15','2025-12-25 17:57:15'),
(447,'islamic','Ayat Kursi','Bagaimana Ayat Kursi digunakan dalam hipnoterapi?','Ayat Kursi (Al-Baqarah 255) digunakan untuk protection, strength, dan peace. USAGE: (1) Awal sesi: Baca untuk barakah dan perlindungan Allah, (2) Saat exposure untuk phobia: Klien visualize Ayat Kursi sebagai shield, (3) Trauma processing: Protection dari emotional overwhelm, (4) Post-session: Sugesti untuk baca sebelum tidur untuk nightmares. BENEFITS: Spiritual - perlindungan dari gangguan setan, psychological - sense of safety dan empowerment. RESEARCH: Quranic recitation aktivasi relaxation response dan positive emotions. Klien Muslim report feeling \'dilindungi\' dan lebih berani face fears. Combines psychological technique dengan spiritual practice untuk holistic healing.','ayat kursi,quran,protection,perlindungan',9,1,'2025-12-25 17:57:15','2025-12-25 17:57:15'),
(448,'islamic','Ruqyah vs Hipnoterapi','Apa bedanya ruqyah dengan hipnoterapi?','RUQYAH adalah Islamic spiritual healing dengan Quran & doa untuk mengusir jin/sihir. HIPNOTERAPI adalah psychological therapy untuk mental/emotional issues. DIFFERENCES: (1) CAUSE: Ruqyah untuk gangguan spiritual (possession, black magic), Hipnoterapi untuk psychological issues, (2) METHOD: Ruqyah pakai Quran recitation & doa, Hipnoterapi pakai suggestion & subconscious work, (3) PRACTITIONER: Ruqyah by ustadz/healer, Hipnoterapi by certified therapist. COMBINATION: Keduanya bisa complementary - jika symptoms spiritual (hearing voices, unusual behavior), ruqyah dulu. Jika psychological (anxiety, phobia, trauma), hipnoterapi. Banyak kasus mix - butuh both. Albashiro collaborate dengan raqee (ruqyah practitioner) untuk holistic Islamic healing approach.','ruqyah,versus,comparison,spiritual healing',9,1,'2025-12-25 17:57:15','2025-12-25 17:57:15'),
(449,'islamic','Perempuan Terapis Laki-laki','Bolehkah perempuan diterapi oleh terapis laki-laki?','HUKUM ISLAM: Perempuan sebaiknya diterapi oleh terapis perempuan untuk menjaga aurat dan khalwat. JIKA TERPAKSA terapis laki-laki: (1) Harus ada mahram atau perempuan lain present dalam ruangan (no khalwat), (2) Jaga aurat - tidak boleh buka jilbab atau touch, (3) Pintu tidak dikunci, (4) Professional boundaries ketat. SOLUSI ALBASHIRO: (1) Kami punya terapis perempuan untuk klien perempuan, (2) Jika terapis laki-laki, bisa request mahram hadir atau staff perempuan present, (3) Online session lebih aman untuk avoid khalwat. PENDAPAT ULAMA: Majority allow dengan syarat darurat dan ada mahram. Prevention of mental illness adalah necessity yang allows rukhsah.','perempuan,mahram,khalwat,aurat,islamic ruling',9,1,'2025-12-25 17:57:16','2025-12-25 17:57:16'),
(450,'islamic','Dzikir Allahu Akbar','Kapan menggunakan takbir dalam terapi?','Allahu Akbar (Allah Maha Besar) digunakan untuk empowerment, courage building, dan overcoming fears. USAGE: (1) Phobia treatment: Sebelum exposure, klien ucap Allahu Akbar untuk courage boost, (2) Confidence building: Takbir mengingatkan tidak ada yang lebih besar dari Allah, masalah kita kecil, (3) Anger management: Shift dari ego ke Allah\'s greatness, (4) Performance anxiety: Allah Maha Besar, Dia yang berikan kemampuan. METHOD: 7x atau 33x repetition dengan full conviction, visualization Allah\'s power. NEUROSCIENCE: Empowering self-talk aktivasi motor cortex dan reward system, increase dopamine. SPIRITUAL: Meningkatkan tawakkal dan keberanian karena yakin Allah melindungi. Effective untuk social anxiety dan confidence issues.','allahu akbar,takbir,courage,power,confidence',8,1,'2025-12-25 17:57:16','2025-12-25 17:57:16'),
(451,'conditions','GAD','Bisa mengatasi Kecemasan Umum?','Ya, hipnoterapi sangat efektif untuk Kecemasan Umum (kecemasan berlebihan tanpa sebab jelas). Terapi membantu mengidentifikasi akar masalah, mengubah pola pikir negatif, mengajarkan teknik relaksasi, dan memprogram ulang respons. Success rate 75-85%.','GAD,anxiety disorder',9,1,'2025-12-25 17:57:16','2025-12-25 17:57:16'),
(452,'conditions','Panic Disorder','Bisa mengatasi Panic Attack?','Ya, hipnoterapi sangat efektif untuk Panic Attack (serangan panik mendadak dengan jantung berdebar). Terapi membantu mengidentifikasi akar masalah, mengubah pola pikir negatif, mengajarkan teknik relaksasi, dan memprogram ulang respons. Success rate 75-85%.','panic,serangan panik',8,1,'2025-12-25 17:57:16','2025-12-25 17:57:16'),
(453,'conditions','Social Anxiety','Bisa mengatasi Fobia Sosial?','Ya, hipnoterapi sangat efektif untuk Fobia Sosial (ketakutan berinteraksi sosial). Terapi membantu mengidentifikasi akar masalah, mengubah pola pikir negatif, mengajarkan teknik relaksasi, dan memprogram ulang respons. Success rate 75-85%.','social anxiety,fobia sosial',8,1,'2025-12-25 17:57:16','2025-12-25 17:57:16'),
(454,'conditions','Health Anxiety','Bisa mengatasi Kecemasan Kesehatan?','Ya, hipnoterapi sangat efektif untuk Kecemasan Kesehatan (kecemasan berlebihan tentang kesehatan). Terapi membantu mengidentifikasi akar masalah, mengubah pola pikir negatif, mengajarkan teknik relaksasi, dan memprogram ulang respons. Success rate 75-85%.','health anxiety,hypochondria',7,1,'2025-12-25 17:57:17','2025-12-25 17:57:17'),
(455,'conditions','Acrophobia','Bisa mengatasi fobia ketinggian?','Ya, Acrophobia (fobia ketinggian) sangat responsif terhadap hipnoterapi. Terapi menggunakan desensitisasi sistem atis, reframing, dan visualisasi. Success rate 85-90%. Biasanya 3-5 sesi sudah menunjukkan perbaikan signifikan.','Acrophobia,fobia ketinggian,heights',7,1,'2025-12-25 17:57:17','2025-12-25 17:57:17'),
(456,'conditions','Agoraphobia','Bisa mengatasi fobia ruang terbuka?','Ya, Agoraphobia (fobia ruang terbuka) sangat responsif terhadap hipnoterapi. Terapi menggunakan desensitisasi sistem atis, reframing, dan visualisasi. Success rate 85-90%. Biasanya 3-5 sesi sudah menunjukkan perbaikan signifikan.','Agoraphobia,fobia ruang terbuka,open spaces',7,1,'2025-12-25 17:57:17','2025-12-25 17:57:17'),
(457,'conditions','Claustrophobia','Bisa mengatasi fobia ruang sempit?','Ya, Claustrophobia (fobia ruang sempit) sangat responsif terhadap hipnoterapi. Terapi menggunakan desensitisasi sistem atis, reframing, dan visualisasi. Success rate 85-90%. Biasanya 3-5 sesi sudah menunjukkan perbaikan signifikan.','Claustrophobia,fobia ruang sempit,enclosed spaces',7,1,'2025-12-25 17:57:17','2025-12-25 17:57:17'),
(458,'conditions','Arachnophobia','Bisa mengatasi fobia laba-laba?','Ya, Arachnophobia (fobia laba-laba) sangat responsif terhadap hipnoterapi. Terapi menggunakan desensitisasi sistem atis, reframing, dan visualisasi. Success rate 85-90%. Biasanya 3-5 sesi sudah menunjukkan perbaikan signifikan.','Arachnophobia,fobia laba-laba,spiders',7,1,'2025-12-25 17:57:17','2025-12-25 17:57:17'),
(459,'conditions','Ophidiophobia','Bisa mengatasi fobia ular?','Ya, Ophidiophobia (fobia ular) sangat responsif terhadap hipnoterapi. Terapi menggunakan desensitisasi sistem atis, reframing, dan visualisasi. Success rate 85-90%. Biasanya 3-5 sesi sudah menunjukkan perbaikan signifikan.','Ophidiophobia,fobia ular,snakes',7,1,'2025-12-25 17:57:18','2025-12-25 17:57:18'),
(460,'conditions','Aviophobia','Bisa mengatasi fobia terbang?','Ya, Aviophobia (fobia terbang) sangat responsif terhadap hipnoterapi. Terapi menggunakan desensitisasi sistem atis, reframing, dan visualisasi. Success rate 85-90%. Biasanya 3-5 sesi sudah menunjukkan perbaikan signifikan.','Aviophobia,fobia terbang,flying',7,1,'2025-12-25 17:57:18','2025-12-25 17:57:18'),
(461,'conditions','Trypanophobia','Bisa mengatasi fobia jarum suntik?','Ya, Trypanophobia (fobia jarum suntik) sangat responsif terhadap hipnoterapi. Terapi menggunakan desensitisasi sistem atis, reframing, dan visualisasi. Success rate 85-90%. Biasanya 3-5 sesi sudah menunjukkan perbaikan signifikan.','Trypanophobia,fobia jarum suntik,needles',7,1,'2025-12-25 17:57:18','2025-12-25 17:57:18'),
(462,'conditions','Mysophobia','Bisa mengatasi fobia kuman?','Ya, Mysophobia (fobia kuman) sangat responsif terhadap hipnoterapi. Terapi menggunakan desensitisasi sistem atis, reframing, dan visualisasi. Success rate 85-90%. Biasanya 3-5 sesi sudah menunjukkan perbaikan signifikan.','Mysophobia,fobia kuman,germs',7,1,'2025-12-25 17:57:18','2025-12-25 17:57:18'),
(463,'conditions','Cynophobia','Bisa mengatasi fobia anjing?','Ya, Cynophobia (fobia anjing) sangat responsif terhadap hipnoterapi. Terapi menggunakan desensitisasi sistem atis, reframing, dan visualisasi. Success rate 85-90%. Biasanya 3-5 sesi sudah menunjukkan perbaikan signifikan.','Cynophobia,fobia anjing,dogs',7,1,'2025-12-25 17:57:18','2025-12-25 17:57:18'),
(464,'conditions','Aquaphobia','Bisa mengatasi fobia air?','Ya, Aquaphobia (fobia air) sangat responsif terhadap hipnoterapi. Terapi menggunakan desensitisasi sistem atis, reframing, dan visualisasi. Success rate 85-90%. Biasanya 3-5 sesi sudah menunjukkan perbaikan signifikan.','Aquaphobia,fobia air,water',7,1,'2025-12-25 17:57:19','2025-12-25 17:57:19'),
(465,'conditions','Insomnia Kronik','Bisa mengatasi Insomnia Kronik?','Ya, hipnoterapi efektif untuk Insomnia Kronik (susah tidur berkepanjangan lebih dari 3 bulan). Terapi membantu mengidentifikasi penyebab, mengajarkan sleep hygiene, memprogram ulang pola tidur, dan self-hypnosis untuk relaksasi. Banyak klien merasakan perbaikan setelah 2-4 sesi.','insomnia,kronik,tidur,sleep',7,1,'2025-12-25 17:57:19','2025-12-25 17:57:19'),
(466,'conditions','Sleep Onset Insomnia','Bisa mengatasi Sleep Onset Insomnia?','Ya, hipnoterapi efektif untuk Sleep Onset Insomnia (sulit memulai tidur malam). Terapi membantu mengidentifikasi penyebab, mengajarkan sleep hygiene, memprogram ulang pola tidur, dan self-hypnosis untuk relaksasi. Banyak klien merasakan perbaikan setelah 2-4 sesi.','sleep,onset,insomnia,tidur,sleep',7,1,'2025-12-25 17:57:19','2025-12-25 17:57:19'),
(467,'conditions','Sleep Maintenance Insomnia','Bisa mengatasi Sleep Maintenance Insomnia?','Ya, hipnoterapi efektif untuk Sleep Maintenance Insomnia (sering terbangun di malam hari). Terapi membantu mengidentifikasi penyebab, mengajarkan sleep hygiene, memprogram ulang pola tidur, dan self-hypnosis untuk relaksasi. Banyak klien merasakan perbaikan setelah 2-4 sesi.','sleep,maintenance,insomnia,tidur,sleep',7,1,'2025-12-25 17:57:19','2025-12-25 17:57:19'),
(468,'conditions','Early Morning Awakening','Bisa mengatasi Early Morning Awakening?','Ya, hipnoterapi efektif untuk Early Morning Awakening (bangun terlalu pagi dan tidak bisa tidur lagi). Terapi membantu mengidentifikasi penyebab, mengajarkan sleep hygiene, memprogram ulang pola tidur, dan self-hypnosis untuk relaksasi. Banyak klien merasakan perbaikan setelah 2-4 sesi.','early,morning,awakening,tidur,sleep',7,1,'2025-12-25 17:57:20','2025-12-25 17:57:20'),
(469,'conditions','Nightmare Disorder','Bisa mengatasi Nightmare Disorder?','Ya, hipnoterapi efektif untuk Nightmare Disorder (mimpi buruk berulang). Terapi membantu mengidentifikasi penyebab, mengajarkan sleep hygiene, memprogram ulang pola tidur, dan self-hypnosis untuk relaksasi. Banyak klien merasakan perbaikan setelah 2-4 sesi.','nightmare,disorder,tidur,sleep',7,1,'2025-12-25 17:57:20','2025-12-25 17:57:20'),
(470,'islamic','Hukum Hipnoterapi','Apakah hipnoterapi halal?','Hipnoterapi untuk tujuan penyembuhan adalah halal. Ulama sepakat bahwa berobat dengan metode yang tidak bertentangan dengan syariat diperbolehkan. Yang haram adalah hipnosis untuk hiburan atau merugikan orang lain.','halal,haram,hukum',10,1,'2025-12-25 17:57:20','2025-12-25 17:57:20'),
(471,'islamic','Dalil Berobat','Apa dalil tentang berobat?','Rasulullah SAW bersabda: Setiap penyakit ada obatnya. Jika obat yang tepat diberikan dengan izin Allah, penyakit akan sembuh (HR. Muslim). Ini menunjukkan anjuran untuk berobat.','dalil,hadits,berobat',9,1,'2025-12-25 17:57:20','2025-12-25 17:57:20'),
(472,'islamic','Asmaul Husna dalam Terapi','Bagaimana Asmaul Husna digunakan?','Asmaul Husna diintegrasikan dalam terapi untuk menguatkan spiritualitas dan ketenangan jiwa. Klien dipandu berdzikir dalam kondisi relaksasi mendalam, memaksimalkan manfaat spiritual dan psikologis. Semua dilakukan sadar penuh.','asmaul husna,dzikir,spiritual',8,1,'2025-12-25 17:57:20','2025-12-25 17:57:20'),
(473,'islamic','Tasbih dalam Terapi','Bagaimana Tasbih digunakan?','Tasbih diintegrasikan dalam terapi untuk menenangkan pikiran dan hati. Klien dipandu berdzikir dalam kondisi relaksasi mendalam, memaksimalkan manfaat spiritual dan psikologis. Semua dilakukan sadar penuh.','tasbih,dzikir,spiritual',8,1,'2025-12-25 17:57:21','2025-12-25 17:57:21'),
(474,'islamic','Istigfar dalam Terapi','Bagaimana Istigfar digunakan?','Istigfar diintegrasikan dalam terapi untuk membersihkan jiwa dari beban dosa. Klien dipandu berdzikir dalam kondisi relaksasi mendalam, memaksimalkan manfaat spiritual dan psikologis. Semua dilakukan sadar penuh.','istigfar,dzikir,spiritual',8,1,'2025-12-25 17:57:21','2025-12-25 17:57:21'),
(475,'islamic','Sholawat dalam Terapi','Bagaimana Sholawat digunakan?','Sholawat diintegrasikan dalam terapi untuk mendatangkan keberkahan. Klien dipandu berdzikir dalam kondisi relaksasi mendalam, memaksimalkan manfaat spiritual dan psikologis. Semua dilakukan sadar penuh.','sholawat,dzikir,spiritual',8,1,'2025-12-25 17:57:21','2025-12-25 17:57:21'),
(476,'islamic','Tahlil dalam Terapi','Bagaimana Tahlil digunakan?','Tahlil diintegrasikan dalam terapi untuk menguatkan iman dan ketenangan. Klien dipandu berdzikir dalam kondisi relaksasi mendalam, memaksimalkan manfaat spiritual dan psikologis. Semua dilakukan sadar penuh.','tahlil,dzikir,spiritual',8,1,'2025-12-25 17:57:21','2025-12-25 17:57:21'),
(477,'pricing','Harga Hipnoterapi Anak','Berapa harga Hipnoterapi Anak?','Hipnoterapi Anak: Rp 500.000 per sesi (60-90 menit). Cocok untuk anak 5-12 tahun. Termasuk konsultasi, terapi, dan follow-up guidance.','hipnoterapi,anak,harga,biaya',8,1,'2025-12-25 17:57:21','2025-12-25 17:57:21'),
(478,'pricing','Durasi Hipnoterapi Anak','Berapa lama Hipnoterapi Anak?','Durasi Hipnoterapi Anak adalah 60-90 menit per sesi. Mencakup konsultasi awal, proses terapi, dan evaluasi hasil.','hipnoterapi,anak,durasi,lama',6,1,'2025-12-25 17:57:22','2025-12-25 17:57:22'),
(479,'pricing','Harga Hipnoterapi Remaja','Berapa harga Hipnoterapi Remaja?','Hipnoterapi Remaja: Rp 500.000 per sesi (90-120 menit). Cocok untuk remaja 13-18 tahun. Termasuk konsultasi, terapi, dan follow-up guidance.','hipnoterapi,remaja,harga,biaya',8,1,'2025-12-25 17:57:22','2025-12-25 17:57:22'),
(480,'pricing','Durasi Hipnoterapi Remaja','Berapa lama Hipnoterapi Remaja?','Durasi Hipnoterapi Remaja adalah 90-120 menit per sesi. Mencakup konsultasi awal, proses terapi, dan evaluasi hasil.','hipnoterapi,remaja,durasi,lama',6,1,'2025-12-25 17:57:22','2025-12-25 17:57:22'),
(481,'pricing','Harga Manajemen Stress','Berapa harga Manajemen Stress?','Manajemen Stress: Rp 500.000 per sesi (90-120 menit). Cocok untuk stress dan kecemasan. Termasuk konsultasi, terapi, dan follow-up guidance.','manajemen,stress,harga,biaya',8,1,'2025-12-25 17:57:22','2025-12-25 17:57:22'),
