(483,'pricing','Harga Trauma Healing','Berapa harga Trauma Healing?','Trauma Healing: Rp 600.000 per sesi (120-150 menit). Cocok untuk trauma dan PTSD. Termasuk konsultasi, terapi, dan follow-up guidance.','trauma,healing,harga,biaya',8,1,'2025-12-25 17:57:23','2025-12-25 17:57:23'),
(484,'pricing','Durasi Trauma Healing','Berapa lama Trauma Healing?','Durasi Trauma Healing adalah 120-150 menit per sesi. Mencakup konsultasi awal, proses terapi, dan evaluasi hasil.','trauma,healing,durasi,lama',6,1,'2025-12-25 17:57:23','2025-12-25 17:57:23'),
(485,'pricing','Harga Konseling Pasangan','Berapa harga Konseling Pasangan?','Konseling Pasangan: Rp 700.000 per sesi (90-120 menit). Cocok untuk masalah hubungan. Termasuk konsultasi, terapi, dan follow-up guidance.','konseling,pasangan,harga,biaya',8,1,'2025-12-25 17:57:23','2025-12-25 17:57:23'),
